/* AUTO-GENERATED — Delaware Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["DE"] = {"code":"DE","name":"Delaware","agency":"Delaware DMV","agencyShort":"DMV","handbook":"https://dmv.de.gov/forms/driver_serv_forms/pdfs/cdl_manual.pdf","links":{},"en":[{"q":"What is the maximum legal vehicle height, including any load, on Delaware highways?","options":["13 feet 6 inches","14 feet","13 feet","12 feet 6 inches"],"answer":0,"explanation":"Delaware law sets the maximum height of a vehicle and its load at 13 feet 6 inches, both on general roads and the Interstate system. Source: Delaware Code Title 21, Ch. 45, sections 4502(b) and 4503(b).","handbook":"","hbref":""},{"q":"Excluding safety equipment, what is the maximum total outside width permitted for most commercial vehicles in Delaware?","options":["102 inches","96 inches","108 inches","120 inches"],"answer":0,"explanation":"Delaware limits total outside vehicle width to 102 inches (8 feet 6 inches), exclusive of safety equipment. Source: Delaware Code Title 21, sections 4502 and 4503; DelDOT OSOW legal limits.","handbook":"","hbref":""},{"q":"What is the maximum allowable length of a semitrailer (exclusive of the truck tractor) operating in Delaware?","options":["53 feet","48 feet","57 feet","45 feet"],"answer":0,"explanation":"A semitrailer, including any load, may not exceed 53 feet in length, exclusive of the truck tractor. Source: Delaware Code Title 21, Ch. 45, section 4503(b).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight for a typical five-or-more-axle combination in Delaware?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"answer":0,"explanation":"Delaware caps the gross weight of a vehicle combination of five or more axles at 80,000 pounds, consistent with the federal limit. Source: Delaware Code Title 21, Ch. 45, sections 4502(c) and 4503(c).","handbook":"","hbref":""},{"q":"On the Interstate system in Delaware, what is the maximum weight allowed on a single axle?","options":["20,000 pounds","22,400 pounds","18,000 pounds","24,000 pounds"],"answer":0,"explanation":"On Interstate highways Delaware follows the federal single-axle limit of 20,000 pounds. Source: Delaware Code Title 21, Ch. 45, section 4503(c).","handbook":"","hbref":""},{"q":"On the Interstate system in Delaware, what is the maximum weight allowed on a tandem axle?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"answer":0,"explanation":"On Interstate highways the tandem-axle limit is 34,000 pounds, matching the federal standard. Source: Delaware Code Title 21, Ch. 45, section 4503(c).","handbook":"","hbref":""},{"q":"When is a Delaware DOT oversize/overweight hauling permit required?","options":["When a vehicle or load exceeds the size or weight limits set in Chapter 45, Title 21 of the Delaware Code","Only when the gross weight exceeds 80,000 pounds, regardless of axle weights","Only for loads wider than 12 feet","Only when traveling on Interstate 95"],"answer":0,"explanation":"A permit is required whenever a vehicle, combination, or self-propelled equipment exceeds the dimensional and/or weight limits set in Chapter 45, Title 21 of the Delaware Code, including when an individual axle is overweight even if the gross weight is legal. Source: DelDOT OSOW permit FAQ; Delaware Code Title 21, section 4504.","handbook":"","hbref":""},{"q":"How are Delaware oversize/overweight hauling permits obtained?","options":["Through the DelDOT online Oversize/Overweight (OSOW) permit system administered by the Hauling Permit Office","By mailing a paper form to the Delaware DMV CDL division","By purchasing them at any DMV vehicle services counter","Automatically issued with the vehicle registration"],"answer":0,"explanation":"Oversize/overweight permits are issued by DelDOT through its online OSOW permit system, managed by the Hauling Permit Office, not by the DMV. Source: DelDOT OSOW permit system (deldot.gov/osow).","handbook":"","hbref":""},{"q":"What is the minimum fee for a standard single-trip Delaware oversize/overweight permit?","options":["$30.00","$15.00","$50.00","$10.00"],"answer":0,"explanation":"The minimum fee for a single-trip hauling permit is $30.00 ($60.00 for a Superload). Source: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405 permit policy manual.","handbook":"","hbref":""},{"q":"For an overweight Delaware permit, how is the additional weight fee calculated?","options":["$10.00 for every 8,000 pounds (or portion thereof) over the legal weight limit","$25.00 for every 5,000 pounds over the legal weight limit","$5.00 for every 1,000 pounds over the legal weight limit","A flat $100.00 regardless of the overweight amount"],"answer":0,"explanation":"Delaware adds a weight fee of $10.00 for every 8,000 pounds, or portion thereof, over the legal weight limit. Source: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405.","handbook":"","hbref":""},{"q":"How long is a standard Delaware single-trip oversize/overweight hauling permit valid?","options":["5 days (effective date to expiration date)","24 hours","30 days","10 days"],"answer":0,"explanation":"A standard hauling permit is valid for five days, from the effective date to the expiration date. Source: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405.","handbook":"","hbref":""},{"q":"During what hours may a permitted oversize load generally travel on Delaware highways, unless the permit states otherwise?","options":["Sunrise to sunset, Monday through Sunday","Only Monday through Friday during business hours","Only between 9 p.m. and 5 a.m.","Any time, 24 hours a day, without restriction"],"answer":0,"explanation":"Permitted loads are authorized to move from sunrise to sunset, Monday through Sunday, unless the permit's special provisions state otherwise. Source: DelDOT OSOW permit FAQ.","handbook":"","hbref":""},{"q":"Which formula does Delaware apply to determine the maximum gross weight on a group of consecutive axles?","options":["The federal Bridge Formula, W = 500[(LN / (N-1)) + 12N + 36]","A flat 1,000 pounds per inch of tire width","The manufacturer's GVWR multiplied by 1.5","A simple 20,000 pounds per axle with no spacing factor"],"answer":0,"explanation":"Delaware adopts the federal Bridge Formula, W = 500[(LN / (N-1)) + 12N + 36], where W is allowable weight, L is the distance between the extreme axles of the group, and N is the number of axles. Source: Delaware Code Title 21, Ch. 45, section 4503(c).","handbook":"","hbref":""},{"q":"Under Delaware's bridge-weight rule, two consecutive sets of tandem axles may each carry 34,000 pounds provided the distance between the first and last axle of the sets is at least:","options":["36 feet","30 feet","40 feet","24 feet"],"answer":0,"explanation":"An exception to the bridge formula allows two consecutive sets of tandem axles to carry 34,000 pounds each when the overall distance between the first and last axle of those sets is 36 feet or more. Source: Delaware Code Title 21, Ch. 45, section 4503(c).","handbook":"","hbref":""},{"q":"On Delaware roads that are NOT part of the Interstate or federal-aid primary system, what is the maximum single-axle weight?","options":["22,400 pounds","20,000 pounds","18,000 pounds","25,000 pounds"],"answer":0,"explanation":"On non-Interstate state roads Delaware permits a higher single-axle weight of 22,400 pounds, compared with 20,000 pounds on the Interstate. Source: Delaware Code Title 21, Ch. 45, section 4502(c).","handbook":"","hbref":""},{"q":"Delaware grants a weight variance for trucks hauling certain in-state farm produce or grain. Up to what gross weight may such vehicles operate?","options":["90,000 pounds","80,000 pounds","100,000 pounds","85,000 pounds"],"answer":0,"explanation":"Delaware allows trucks hauling in-state fruits, vegetables, or commodity grains to reach up to 90,000 pounds (or the manufacturer's gross combined weight rating, whichever is less). Source: Delaware Code Title 21, Ch. 45, section 4502(c).","handbook":"","hbref":""},{"q":"Delaware's live-poultry hauling weight provision includes a tolerance to account for precipitation and variations in bird size. What is that percentage variance?","options":["3%","5%","10%","1%"],"answer":0,"explanation":"Trucks hauling live poultry within Delaware may operate up to 90,000 pounds with a 3% variance for weight differences caused by precipitation and bird size. Source: Delaware Code Title 21, Ch. 45, section 4502(c).","handbook":"","hbref":""},{"q":"On Delaware roads other than the Interstate and federal-aid primary system, what is the maximum length of a single vehicle (not a combination)?","options":["40 feet","45 feet","53 feet","35 feet"],"answer":0,"explanation":"On non-Interstate roads a single vehicle may not exceed 40 feet, and a combination of vehicles may not exceed 60 feet. Source: Delaware Code Title 21, Ch. 45, section 4502(b).","handbook":"","hbref":""},{"q":"In a truck tractor-semitrailer-trailer (twin) combination in Delaware, what is the maximum length of each trailer or semitrailer?","options":["29 feet","28 feet","33 feet","31 feet"],"answer":0,"explanation":"Each trailer or semitrailer in a tractor-semitrailer-trailer combination is limited to 29 feet, exclusive of the tractor. Source: Delaware Code Title 21, Ch. 45, section 4503(b).","handbook":"","hbref":""},{"q":"At what point does a Delaware oversize/overweight move qualify as a 'Superload,' which carries a higher minimum permit fee?","options":["Length at 120 feet, width at 15 feet, height at 15 feet, or gross weight over 120,000 pounds","Any load over 90,000 pounds gross weight","Any load wider than 10 feet","Length over 75 feet or weight over 100,000 pounds"],"answer":0,"explanation":"A move is classified as a Superload when length reaches 120 feet, width reaches 15 feet, height reaches 15 feet, or gross weight exceeds 120,000 pounds; the minimum Superload permit fee is $60.00. Source: DelDOT OSOW permit FAQ.","handbook":"","hbref":""},{"q":"In Delaware, which class of CDL is required to operate a combination of vehicles with a Gross Vehicle Weight Rating (GVWR) of 26,001 pounds or more, provided the GVWR of the towed unit is in excess of 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Delaware Commercial Driver's Manual (Version 4.0, \"Types of CDL\") states a Class A CDL is required for any combination of vehicles with a GVWR of 26,001 pounds or more provided the GVWR of the towed unit(s) is in excess of 10,000 pounds.","handbook":"","hbref":""},{"q":"Under Delaware rules, a single vehicle with a GVWR of 26,001 pounds or more that is not towing a unit over 10,000 pounds requires which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"The Delaware Commercial Driver's Manual defines Class B as any single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a vehicle not in excess of 10,000 pounds GVWR.","handbook":"","hbref":""},{"q":"In Delaware, a vehicle with a GVWR under 26,001 pounds that is designed to transport 16 or more passengers (including the driver) or carries placarded hazardous materials requires which CDL class?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"Per the Delaware Commercial Driver's Manual, a Class C CDL is required for a vehicle with a GVWR less than 26,001 pounds that is designed to transport 16 or more persons including the driver, or that is used to transport hazardous materials requiring placarding.","handbook":"","hbref":""},{"q":"On a Delaware CDL, which endorsement code authorizes operation of a tank vehicle?","options":["Code N","Code T","Code H","Code P"],"answer":0,"explanation":"The Delaware Commercial Driver's Manual lists the Tanker endorsement as code N. The T endorsement is for Doubles/Triples, H is Hazardous Materials, and P is Passenger.","handbook":"","hbref":""},{"q":"Which Delaware CDL endorsement is required to pull double or triple trailers?","options":["Endorsement T","Endorsement N","Endorsement X","Endorsement P"],"answer":0,"explanation":"The Delaware Commercial Driver's Manual lists the Doubles/Triples endorsement as code T and requires passing a special knowledge examination on the problems associated with pulling multiple trailers.","handbook":"","hbref":""},{"q":"According to the Delaware Commercial Driver's Manual, a Tank Vehicle (N) endorsement is required when the vehicle is designed to transport liquid or gas in a tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of at least how many gallons?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"answer":2,"explanation":"The Delaware Commercial Driver's Manual states the Tank Vehicle (N) endorsement applies to tanks having an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more.","handbook":"","hbref":""},{"q":"In Delaware, what is the minimum age to obtain a CDL for driving intrastate (within Delaware only)?","options":["16 years","17 years","18 years","21 years"],"answer":2,"explanation":"The Delaware Commercial Driver's Manual's Basic CDL Requirements state an applicant must be 18 years of age with 1 year of driving experience to drive intrastate.","handbook":"","hbref":""},{"q":"Under Delaware's basic CDL requirements, what minimum age is needed to drive in interstate commerce or to transport hazardous materials?","options":["18 years","19 years","20 years","21 years"],"answer":3,"explanation":"The Delaware Commercial Driver's Manual requires an applicant to be 21 years of age with at least 1 year of driving experience to drive in interstate commerce or to transport hazardous materials.","handbook":"","hbref":""},{"q":"After passing the knowledge exams, how long must a Delaware Commercial Learner's Permit (CLP) holder hold the CLP before being allowed to take the CDL skills test?","options":["A minimum of 14 full days","A minimum of 10 full days","A minimum of 7 full days","A minimum of 30 full days"],"answer":0,"explanation":"The Delaware Commercial Driver's Manual states you must hold your CLP for a minimum of 14 full days before you are able to perform the CDL skills test, matching the federal 49 CFR 383 requirement.","handbook":"","hbref":""},{"q":"When driving on a Delaware Commercial Learner's Permit (CLP), the holder must be accompanied by whom?","options":["Any licensed driver age 18 or older","A licensed CDL driver qualified in the same type of CMV","A certified DMV examiner only","No one; the CLP allows solo driving"],"answer":1,"explanation":"The Delaware Commercial Driver's Manual states a CLP allows you to drive a CMV accompanied by another licensed CDL driver, and you may only drive the type of vehicle for which you tested with a CDL driver qualified in the same type of CMV.","handbook":"","hbref":""},{"q":"Before being issued a Delaware CDL with a hazardous materials (H) endorsement, what must an applicant first complete?","options":["A defensive driving course at the DMV","A 30-day waiting period after the skills test","A TSA security threat assessment including fingerprinting","A separate road test in a placarded vehicle"],"answer":2,"explanation":"The Delaware Commercial Driver's Manual states no CDL with a hazmat endorsement may be issued unless the applicant has first undergone the TSA security threat assessment (including fingerprinting and verification of citizenship/legal presence) and obtained TSA clearance.","handbook":"","hbref":""},{"q":"Under the federal Entry-Level Driver Training (ELDT) rule applied in Delaware, training must be provided by a school listed on which registry?","options":["The Delaware DMV Approved Schools list","The AAMVA Instructor Directory","The FMCSA Training Provider Registry (TPR)","The TSA Certified Trainer Registry"],"answer":2,"explanation":"Delaware DMV's ELDT page states entry-level driver training must be completed through an FMCSA-registered provider listed on the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) before the applicant can take the CDL skills exam.","handbook":"","hbref":""},{"q":"Which of the following does Delaware require ELDT (Entry-Level Driver Training) for before the skills/knowledge exam can be taken?","options":["Adding a Tanker (N) endorsement","Adding a Doubles/Triples (T) endorsement","Renewing an existing CDL","Obtaining a first-time Class A or Class B CDL"],"answer":3,"explanation":"Per Delaware DMV's ELDT page (effective Feb 7, 2022), ELDT is required for first-time Class A or B applicants, upgrades to a higher class, and the S, P, and H endorsements. It is not required for the N or T endorsements or for renewals.","handbook":"","hbref":""},{"q":"Delaware requires CDL holders to self-certify their type of driving. How many self-certification categories are there?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"The Delaware Commercial Driver's Manual states CDL holders must self-certify a driving status of non-excepted interstate, non-excepted intrastate, excepted interstate, or excepted intrastate — four categories.","handbook":"","hbref":""},{"q":"A Delaware CDL applicant who drives a CMV in interstate commerce and is subject to the federal physical qualification rules certifies as which medical self-certification category?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"answer":0,"explanation":"The Delaware Commercial Driver's Manual explains that CDL holders who drive CMVs in interstate commerce and must meet the federal medical certificate requirement are non-excepted interstate commerce drivers.","handbook":"","hbref":""},{"q":"When a Delaware CLP is issued with a Passenger (P) endorsement, what restriction must it also carry?","options":["A 'K' Intrastate Only restriction","An 'L' No air brake restriction","A 'P' No passengers in a CMV bus restriction","An 'E' No manual transmission restriction"],"answer":2,"explanation":"The Delaware Commercial Driver's Manual notes that if a CLP is issued with a Passenger (P) or School Bus (S) endorsement, it must also contain a 'P' – No passengers in a CMV bus restriction (allowing only specified personnel aboard).","handbook":"","hbref":""},{"q":"If a Delaware CLP is issued with a Tanker (N) endorsement, what additional restriction is placed on it?","options":["'X' – No cargo in a CMV tank vehicle","'Z' – No full air brake equipped CMV","'V' – Medical variance","'O' – No tractor-trailer CMV"],"answer":0,"explanation":"The Delaware Commercial Driver's Manual states that a CLP issued with a Tanker (N) endorsement must also contain an 'X' – No cargo in a CMV tank vehicle restriction, meaning the holder may operate only an empty, purged tank vehicle.","handbook":"","hbref":""},{"q":"What documentation does the Delaware DMV require an applicant to present regarding Delaware residency when applying for a license?","options":["One proof of Delaware residency","Three proofs of Delaware residency","A notarized residency affidavit only","Two proofs of Delaware residency"],"answer":3,"explanation":"The Delaware DMV requires applicants to provide proof of identity (one primary and one secondary document), a Social Security number if eligible, and two proofs of Delaware residency; non-U.S. citizens must also show proof of legal presence (Delaware DMV Driver License/ID document requirements).","handbook":"","hbref":""},{"q":"Under Delaware rules, what is required of a person who wishes to drive a school bus?","options":["Only a Class C CDL with no endorsements","A CDL with both a Passenger (P) and a School Bus (S) endorsement, plus Department of Education requirements","A standard Class D license with a school bus sticker","A Tanker (N) endorsement and a TSA background check"],"answer":1,"explanation":"The Delaware Commercial Driver's Manual states all Delaware school bus drivers must have a CDL and meet additional Delaware Department of Education training and medical requirements; the DMV then issues a CDL with P and S endorsements (with an M or N restriction depending on vehicle class).","handbook":"","hbref":""},{"q":"Delaware offers a special non-CDL credential under the federal CDL waiver provisions for which group of drivers operating a CMV?","options":["Long-haul interstate truckers","Hazmat tanker operators","Charter bus drivers","Farmers and firefighters"],"answer":3,"explanation":"The Delaware Commercial Driver's Manual states Delaware has a special Non-CDL to identify farmers and firefighters who operate CMVs under the CDL waiver provisions; this Non-CDL may not be used in interstate commerce or for-hire situations.","handbook":"","hbref":""},{"q":"In Delaware, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"answer":1,"explanation":"Delaware makes it illegal to operate a CMV with a BAC of 0.04 percent or more, half the 0.08 limit for private vehicles. Source: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614.","handbook":"","hbref":""},{"q":"Under Delaware's implied-consent law, when a person operates a commercial motor vehicle in the state, they are deemed to have given consent to what?","options":["A search of the vehicle's cargo","Testing for alcohol concentration","A medical fitness examination","Release of their employment records"],"answer":1,"explanation":"By operating a CMV in Delaware, a driver is deemed to have consented to alcohol (chemical) testing. Source: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614 (implied consent for CMV drivers).","handbook":"","hbref":""},{"q":"How long is a Delaware CDL holder disqualified for a FIRST major offense, such as driving a CMV with a BAC of 0.04 or higher, when not hauling hazardous materials?","options":["60 days","120 days","1 year","3 years"],"answer":2,"explanation":"A first major violation results in a 1-year CDL disqualification in Delaware. Source: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612 (federal standard 49 CFR 383.51 applied by the state).","handbook":"","hbref":""},{"q":"In Delaware, the disqualification for a first major offense increases to three years when the offense occurs while the driver is operating a CMV that is doing what?","options":["Placarded for hazardous materials","Carrying passengers for hire","Towing a double trailer","Crossing state lines"],"answer":0,"explanation":"A first major offense committed while operating a CMV placarded for hazardous materials raises the disqualification from 1 year to 3 years. Source: Delaware CDL Manual Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the Delaware CDL disqualification period for a SECOND major offense (for example, a second conviction for driving under the influence)?","options":["3 years","10 years","Lifetime","5 years"],"answer":2,"explanation":"A second major violation in any vehicle results in a lifetime CDL disqualification in Delaware. Source: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Delaware CDL rules, refusing to submit to a required alcohol/chemical test while operating a CMV is treated as which kind of violation?","options":["A serious traffic violation","A major offense","An out-of-service violation","A non-reportable infraction"],"answer":1,"explanation":"Refusal to undergo blood-alcohol testing is listed among the major offenses, carrying at least a 1-year disqualification for a first offense. Source: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614.","handbook":"","hbref":""},{"q":"Under Delaware's implied-consent warning for CMV drivers, refusing the alcohol test results in being immediately placed out of service for how long, plus disqualification?","options":["8 hours","12 hours","24 hours","48 hours"],"answer":2,"explanation":"Delaware law requires that the officer warn the driver a refusal results in being immediately placed out of service for 24 hours and disqualified for at least 1 year. Source: 21 Del. C. Section 2614.","handbook":"","hbref":""},{"q":"A Delaware CMV driver is found with a BAC of 0.02 (a measurable amount of alcohol below 0.04). What is the required consequence?","options":["A 60-day CDL disqualification","Being placed out of service for 24 hours","A 1-year CDL disqualification","Lifetime CDL disqualification"],"answer":1,"explanation":"Any detectable amount of alcohol under 0.04 (a measurable amount of 0.02 to under 0.04) requires the driver be placed out of service for 24 hours. Source: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation under Delaware CDL rules?","options":["Driving a CMV with a BAC of 0.04","Excessive speeding of 15 mph or more over the limit","Leaving the scene of an accident","Violating an out-of-service order"],"answer":1,"explanation":"Excessive speeding (15 mph or more above the posted limit) is a serious traffic violation. The other listed items are major offenses or out-of-service violations. Source: Delaware CDL Manual Section 1.3.3.","handbook":"","hbref":""},{"q":"In Delaware, how long is a CDL disqualified for being convicted of TWO serious traffic violations in a CMV within a three-year period?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within any three-year period result in a 60-day CDL disqualification. Source: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the Delaware CDL disqualification period for being convicted of THREE or more serious traffic violations in a CMV within a three-year period?","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three or more serious traffic violations within any three-year period result in a 120-day CDL disqualification. Source: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of these is a serious traffic violation under Delaware CDL rules rather than a major offense?","options":["Following a vehicle too closely","Using a CMV to commit a felony","Causing a fatality through negligent CMV operation","Driving a CMV under the influence of a controlled substance"],"answer":0,"explanation":"Following a vehicle too closely is a serious traffic violation. The other three are major offenses. Source: Delaware CDL Manual Section 1.3.3 (serious) and Section 1.3.2 (major).","handbook":"","hbref":""},{"q":"Texting or using a hand-held mobile telephone while operating a CMV is treated under Delaware CDL rules as which type of violation?","options":["A major offense","A serious traffic violation","An out-of-service order violation","A railroad-crossing violation"],"answer":1,"explanation":"Texting or using a hand-held phone while operating a CMV is a serious traffic violation and counts toward the 60-day/120-day disqualification thresholds. Source: Delaware CDL Manual Section 1.3.3 and texting/phone section; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Delaware/federal CDL rules, a CDL is disqualified for 60 days after how many convictions for using a hand-held mobile phone while operating a CMV (within 3 years)?","options":["One conviction","Two or more convictions","Four convictions","Five convictions"],"answer":1,"explanation":"Two or more convictions of a hand-held phone law while operating a CMV within 3 years bring a 60-day disqualification (120 days for three or more). Source: Delaware CDL Manual hand-held mobile telephone section; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the maximum federal civil penalty a CMV driver may face for a texting-while-driving violation, as stated in the Delaware CDL Manual?","options":["Up to $750","Up to $1,500","Up to $2,750","Up to $11,000"],"answer":2,"explanation":"The Delaware CDL Manual states drivers are subject to civil penalties up to $2,750 for texting/hand-held phone violations (employers up to $11,000). Source: Delaware CDL Manual texting and hand-held mobile telephone section.","handbook":"","hbref":""},{"q":"How long is a Delaware CDL disqualified for a FIRST conviction of a railroad-highway grade crossing violation in a CMV?","options":["No less than 30 days","No less than 60 days","No less than 120 days","No less than 1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation carries a disqualification of no less than 60 days. Source: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Delaware, a SECOND railroad-highway grade crossing violation in a CMV within three years disqualifies the CDL for at least how long?","options":["60 days","120 days","180 days","1 year"],"answer":1,"explanation":"A second railroad-crossing violation within any three-year period results in a disqualification of no less than 120 days. Source: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Delaware CMV driver commits a THIRD railroad-highway grade crossing violation within three years. The CDL is disqualified for at least how long?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third railroad-crossing violation within any three-year period results in a disqualification of no less than 1 year. Source: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Delaware CDL rules, what is the disqualification range for a FIRST conviction of violating an out-of-service order in a CMV (not hauling hazardous materials)?","options":["No less than 30 days nor more than 90 days","No less than 180 days nor more than 1 year","No less than 1 year nor more than 2 years","No less than 3 years nor more than 5 years"],"answer":1,"explanation":"A first out-of-service order violation carries a disqualification of no less than 180 days and no more than 1 year. Source: Delaware CDL Manual MCSIA disqualifying violations section; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Delaware's Move Over law, when you approach a stopped DelDOT, police, tow, or emergency vehicle displaying warning lights on a highway with four or more lanes in your direction, what must you do first?","options":["Make a lane change into a lane not adjacent to the stopped vehicle, if it is safe to do so","Come to a complete stop until the stopped vehicle leaves the shoulder","Move onto the shoulder and pass at no more than 10 mph","Maintain your lane and sound your horn continuously while passing"],"answer":0,"explanation":"Delaware Title 21 § 4134(b) requires drivers on a roadway with at least four lanes in the same direction to yield by changing into a lane not adjacent to the stopped emergency/DelDOT/tow/utility vehicle when safe. Source: 21 Del. C. § 4134.","handbook":"","hbref":""},{"q":"Under Delaware's Move Over law, if you cannot safely change lanes away from a stopped emergency vehicle, what speed reduction is required where the posted limit is 50 mph or higher?","options":["Reduce to a safe speed at least 20 mph below the posted speed limit","Reduce to a safe speed at least 10 mph below the posted speed limit","Reduce to exactly half of the posted speed limit","Reduce to no more than 25 mph regardless of the posted limit"],"answer":0,"explanation":"21 Del. C. § 4134(b) requires that, when a lane change is not possible, a driver reduce to a safe speed at least 20 mph less than the posted limit where the limit is 50 mph or above. Source: 21 Del. C. § 4134.","handbook":"","hbref":""},{"q":"When a Delaware school bus is stopped on an undivided two-lane road with its red lights flashing, which drivers must stop?","options":["Drivers approaching from both the front and the rear","Only drivers approaching from the rear (same direction as the bus)","Only drivers approaching from the front (oncoming)","Only drivers within 20 feet of the bus"],"answer":0,"explanation":"Delaware Title 21 § 4166 requires the driver of any vehicle approaching a stopped school bus from the front or from the rear to stop before passing the bus when its red stop lamps are activated. Source: 21 Del. C. § 4166.","handbook":"","hbref":""},{"q":"On a Delaware roadway (or roadways) with four or more lanes, which approaching driver is NOT required to stop for a school bus displaying flashing red lights?","options":["The driver approaching from the front (oncoming direction)","The driver approaching from the rear (same direction as the bus)","Both the front and rear drivers are exempt","Neither driver is exempt; both must always stop"],"answer":0,"explanation":"21 Del. C. § 4166 provides that on a roadway or roadways with 4 or more lanes, the driver approaching from the front (opposite direction) need not stop; the driver approaching from the rear still must stop. Source: 21 Del. C. § 4166.","handbook":"","hbref":""},{"q":"After stopping for a Delaware school bus with red lights flashing, how long must a driver remain stopped?","options":["Until the bus begins to move or no longer has its red stop lamps activated","For a fixed minimum of 30 seconds","Until the bus driver waves traffic forward","Until all children are at least 100 feet from the bus"],"answer":0,"explanation":"21 Del. C. § 4166 requires a driver to remain stopped until the bus begins to move or no longer displays its activated red stop lamps. Source: 21 Del. C. § 4166.","handbook":"","hbref":""},{"q":"According to the Delaware CDL manual, when a placarded hazardous-materials vehicle must stop at a railroad crossing that has no painted stop line, where must it stop relative to the nearest rail?","options":["No closer than 15 feet and no farther than 50 feet from the nearest rail","No closer than 10 feet and no farther than 25 feet from the nearest rail","No closer than 25 feet and no farther than 75 feet from the nearest rail","No closer than 5 feet and no farther than 35 feet from the nearest rail"],"answer":0,"explanation":"The Delaware CDL Manual (Section 2.15) states vehicles required to stop must stop no closer than 15 feet and no more than 50 feet from the nearest rail of the nearest track. Source: Delaware CDL Manual, Sec. 2.15.","handbook":"","hbref":""},{"q":"Per the Delaware CDL manual, while any part of your commercial vehicle is crossing the railroad tracks, you should NOT do which of the following?","options":["Shift gears while crossing the tracks","Keep both hands on the steering wheel","Cross only after confirming all tracks are clear","Use a pullout lane to stop when one is available"],"answer":0,"explanation":"The Delaware CDL Manual (Section 2.15) instructs drivers not to shift gears while crossing railroad tracks, to avoid stalling on the crossing. Source: Delaware CDL Manual, Sec. 2.15.","handbook":"","hbref":""},{"q":"Under the Delaware CDL manual, if your commercial vehicle must stop on a one-way or divided highway, at what distances should you place your three warning devices?","options":["10 feet, 100 feet, and 200 feet toward approaching traffic","10 feet, 50 feet, and 150 feet toward approaching traffic","25 feet, 100 feet, and 250 feet toward approaching traffic","10 feet, 100 feet, and 100 feet (one ahead and one behind)"],"answer":0,"explanation":"The Delaware CDL Manual (Section 2.5) directs that on a one-way or divided highway the warning devices be placed 10, 100, and 200 feet toward the approaching traffic. Source: Delaware CDL Manual, Sec. 2.5.","handbook":"","hbref":""},{"q":"Per the Delaware CDL manual, on a two-lane undivided road carrying traffic in both directions, where do you place the warning devices after stopping?","options":["Within 10 feet of the vehicle, and 100 feet behind and 100 feet ahead of it","200 feet behind and 200 feet ahead, with none near the vehicle","Only one device 100 feet behind the vehicle","10 feet, 100 feet, and 200 feet, all behind the vehicle"],"answer":0,"explanation":"The Delaware CDL Manual (Section 2.5) directs placing a device within 10 feet of the front or rear corner and devices 100 feet behind and 100 feet ahead of the vehicle on a two-lane/undivided road. Source: Delaware CDL Manual, Sec. 2.5.","handbook":"","hbref":""},{"q":"Under the Delaware CDL manual, within how many minutes after stopping on the roadway or shoulder must you put out your emergency warning devices?","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"answer":0,"explanation":"The Delaware CDL Manual (Section 2.5) requires that emergency warning devices be placed within 10 minutes of stopping on a road or shoulder. Source: Delaware CDL Manual, Sec. 2.5.","handbook":"","hbref":""},{"q":"According to the Delaware CDL manual, what warning equipment must a commercial vehicle carry for use when parked or disabled?","options":["Three reflective triangles, or at least 6 fusees, or 3 liquid-burning flares","Two reflective triangles and one red flag","Four reflective triangles only","One reflective triangle and a battery-powered beacon"],"answer":0,"explanation":"The Delaware CDL Manual lists required emergency equipment as three reflective triangles, or at least 6 fusees, or 3 liquid-burning flares. Source: Delaware CDL Manual, Sec. 2.1 (inspection).","handbook":"","hbref":""},{"q":"Per the Delaware CDL manual, if a hill or curve keeps following drivers from seeing your stopped vehicle within 500 feet, what should you do with your rearmost warning triangle?","options":["Move it farther back down the road, beyond the obstruction, so warning is provided","Leave it at the standard 100 feet and add a fourth triangle","Place it on the hood of the vehicle to raise its visibility","Remove it and rely solely on the four-way flashers"],"answer":0,"explanation":"The Delaware CDL Manual (Section 2.5) says when a hill or curve blocks the view within 500 feet, move the rearmost triangle back beyond the obstruction so following drivers get warning. Source: Delaware CDL Manual, Sec. 2.5.","handbook":"","hbref":""},{"q":"Under Delaware Title 21, what is the statutory speed limit on a two-lane roadway where no other limit is posted?","options":["50 mph","55 mph","45 mph","60 mph"],"answer":0,"explanation":"Delaware Title 21 § 4169 sets 50 mph on 2-lane roadways (and 55 mph on 4-lane and divided roadways) unless otherwise posted. Source: 21 Del. C. § 4169.","handbook":"","hbref":""},{"q":"Under Delaware Title 21, what is the statutory speed limit on a four-lane or divided roadway where no other limit is posted?","options":["55 mph","50 mph","60 mph","65 mph"],"answer":0,"explanation":"Delaware Title 21 § 4169 sets 55 mph on 4-lane and divided roadways unless otherwise posted. Source: 21 Del. C. § 4169.","handbook":"","hbref":""},{"q":"Under Delaware Title 21, what is the speed limit in a business or residential district unless otherwise posted?","options":["25 mph","30 mph","20 mph","35 mph"],"answer":0,"explanation":"Delaware Title 21 § 4169 sets 25 mph in business districts and 25 mph in residential districts unless otherwise posted. Source: 21 Del. C. § 4169.","handbook":"","hbref":""},{"q":"On which Delaware roadway has the Department of Transportation designated a 65 mph maximum speed limit between Red Lion Creek and the Appoquinimink River?","options":["Delaware State Route 1","Interstate 495","U.S. Route 13","Interstate 295"],"answer":0,"explanation":"Delaware Title 21 § 4169 directs DelDOT to designate a 65 mph maximum on the portion of State Route 1 between Red Lion Creek and the Appoquinimink River (excluding the toll plaza area). Source: 21 Del. C. § 4169.","handbook":"","hbref":""},{"q":"Under Delaware's lane-travel restriction law (§ 4114A), which vehicles may generally travel only in the right-hand lane on State Route 1 and Interstate 495?","options":["A vehicle with a gross vehicle weight rating of more than 26,000 pounds","A vehicle with a gross vehicle weight rating of more than 10,000 pounds","Any vehicle towing a trailer of any size","A vehicle with three or more axles regardless of weight"],"answer":0,"explanation":"Delaware Title 21 § 4114A restricts vehicles with a GVWR of more than 26,000 pounds to the right-hand lane on the express/controlled-access portions of SR 1 and I-495, with limited exceptions. Source: 21 Del. C. § 4114A.","handbook":"","hbref":""},{"q":"Under Delaware § 4114A, when may a vehicle subject to the right-lane restriction lawfully use a left lane on SR 1 or I-495?","options":["When overtaking and passing another vehicle, entering or leaving the roadway, or as traffic conditions require","Only between midnight and 6:00 a.m.","Only when the posted speed limit is 35 mph or lower","Never, under any circumstances"],"answer":0,"explanation":"Delaware Title 21 § 4114A allows the heavy vehicle to use a left lane for passing, entering/leaving the roadway, emergencies, obstructions, traffic conditions, or to comply with other law. Source: 21 Del. C. § 4114A.","handbook":"","hbref":""},{"q":"Under Delaware law, a vehicle moving slower than the normal speed of traffic must be driven where, except when passing or preparing for a left turn?","options":["In the right-hand lane available for traffic, or as close as practicable to the right-hand curb or edge","In the center lane of any multi-lane roadway","In whichever lane has the fewest vehicles","In the left lane, leaving the right lane open for merging traffic"],"answer":0,"explanation":"Delaware Title 21 § 4114 requires a vehicle traveling slower than normal traffic to keep to the right-hand lane or as close as practicable to the right-hand curb/edge, except when overtaking or preparing for a left turn. Source: 21 Del. C. § 4114.","handbook":"","hbref":""},{"q":"Per the Delaware CDL manual, a railroad-highway grade crossing violation while operating a CMV results in a CDL disqualification of at least how long for a first offense?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"The Delaware CDL Manual (Section 1.3.5) states a railroad-highway grade crossing violation disqualifies the CDL for at least 60 days (first), 120 days (second within 3 years), and 1 year (third within 3 years). Source: Delaware CDL Manual, Sec. 1.3.5.","handbook":"","hbref":""},{"q":"Which Delaware agency issues Commercial Driver Licenses (CDLs)?","options":["The Delaware Division of Motor Vehicles (DMV), part of DelDOT","The Delaware State Police Commercial Carrier Bureau","The Federal Motor Carrier Safety Administration field office","The Delaware Secretary of State's Office"],"answer":0,"explanation":"In Delaware, CDLs are issued by the Delaware Division of Motor Vehicles (DMV), which operates under the Delaware Department of Transportation. FMCSA sets the federal standards but does not issue the license. Source: Delaware DMV CDL pages; Title 21, Chapter 26 (Uniform Commercial Driver License Act).","handbook":"","hbref":""},{"q":"How are Delaware CDL knowledge (written) tests administered?","options":["By walk-in at any DMV facility, with no appointment required","By appointment only at the Dover headquarters","Online from home with a remote proctor","Only at a single approved third-party testing center"],"answer":0,"explanation":"Delaware DMV states that all CDL knowledge tests are by walk-in only and can be completed at any division (DMV) facility. The appointment requirement applies to the skills test, not the knowledge test. Source: Delaware DMV CDL webpage.","handbook":"","hbref":""},{"q":"How long must a Delaware Commercial Learner Permit (CLP) be held before the holder may take the CDL skills test?","options":["A minimum of 14 days after initial issuance","A minimum of 30 days after initial issuance","A minimum of 10 days after initial issuance","A minimum of 7 days after initial issuance"],"answer":0,"explanation":"A CLP holder is not eligible to take the CDL pre-trip, basic control, or road skills test until the permit has been held for a minimum of 14 days after initial issuance. This is the federal 14-day hold adopted by Delaware. Source: Delaware DMV CDL webpage; 49 CFR 383.25 as adopted under Title 21 Ch. 26.","handbook":"","hbref":""},{"q":"How long is a Delaware Commercial Learner Permit (CLP) valid?","options":["One (1) year, and it may be renewed once during that time","180 days, with no renewal allowed","Two (2) years, renewable annually","Six (6) months, renewable twice"],"answer":0,"explanation":"A Delaware CLP is valid for one (1) year and may not be issued or extended for a period exceeding one year; it may be renewed once during that period. Source: Delaware DMV CDL webpage; Title 21 § 2608.","handbook":"","hbref":""},{"q":"The Delaware CDL skills test is divided into which three parts?","options":["Pre-trip vehicle inspection, basic control skills, and on-road driving","Written exam, eye exam, and road test","Coupling, braking, and backing only","Theory training, behind-the-wheel, and final written exam"],"answer":0,"explanation":"The CDL skills test consists of three parts: the pre-trip vehicle inspection test, the basic control skills test, and the on-road driving test. Delaware modernized these protocols effective February 26, 2025. Source: Delaware DMV CDL webpage; 49 CFR 383.113.","handbook":"","hbref":""},{"q":"What must an entry-level driver complete before taking the Delaware CDL skills test for a Class A, Class B, Passenger (P), or School Bus (S) credential?","options":["Federally required Entry-Level Driver Training (ELDT) from a registered provider","A 30-day apprenticeship logged with the DMV","A defensive-driving course approved by Delaware State Police","Only the general knowledge written test"],"answer":0,"explanation":"Effective February 7, 2022, no entry-level operator may take the CDL skills test for a Class A, Class B, P endorsement, or S endorsement unless they have completed mandatory theory and behind-the-wheel ELDT from a provider listed on the FMCSA Training Provider Registry. Source: Delaware DMV ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"What are the four self-certification categories a Delaware CDL/CLP holder may declare?","options":["Interstate non-excepted, interstate excepted, intrastate non-excepted, intrastate excepted","Class A, Class B, Class C, and Class D","Hazmat, passenger, tanker, and doubles/triples","For-hire, private, exempt, and government"],"answer":0,"explanation":"Every Delaware CDL/CLP holder must self-certify into one of four categories: interstate non-excepted, interstate excepted, intrastate non-excepted, or intrastate excepted. Source: Delaware DMV Self-Certification Affidavit Category Guide; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which self-certification category requires the driver to submit and keep a current DOT medical examiner's certificate on file with the Delaware DMV?","options":["Interstate non-excepted","Interstate excepted","Intrastate excepted","No category needs to submit one"],"answer":0,"explanation":"A driver who self-certifies as interstate non-excepted must provide and maintain a copy of the federal medical examiner's certificate with the Delaware DMV. Excepted categories are not required to submit a federal medical certificate. Source: Delaware DMV Self-Certification Category Guide; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Where must a Delaware CDL applicant obtain the DOT physical that supports the medical examiner's certificate?","options":["From a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","From any licensed physician or chiropractor of the driver's choice","From a Delaware State Police-approved clinic only","From the DMV's in-house medical staff"],"answer":0,"explanation":"The medical certificate must come from a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners. Delaware adopted this federal requirement for all CDL/CLP holders. Source: Delaware DMV Medical Certification page; 49 CFR 390.103 / National Registry.","handbook":"","hbref":""},{"q":"On what schedule does a Delaware CDL expire and become renewable?","options":["On the eighth anniversary of the holder's birth date following issuance (every 8 years)","Every 4 years on the issuance date","Every 5 years on the issuance date","Every 2 years to match the DOT physical"],"answer":0,"explanation":"A Delaware CDL expires and is renewable on the eighth anniversary date of the applicant's birth next following issuance, giving an effective term of up to eight years. Source: Title 21 § 2611(f); Delaware DMV.","handbook":"","hbref":""},{"q":"What is the earliest a Delaware CDL may be renewed before it expires?","options":["Within 30 days prior to the expiration date","Within 90 days prior to the expiration date","Within 6 months prior to the expiration date","Within 1 year prior to the expiration date"],"answer":0,"explanation":"Delaware allows a CDL to be renewed only within 30 days prior to its expiration date. Source: Delaware DMV CDL webpage.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Delaware CDL for intrastate (within-Delaware) driving only?","options":["18 years old","16 years old","21 years old","19 years old"],"answer":0,"explanation":"A person must be at least 18 years old to hold a Delaware CDL for intrastate operation. Source: Delaware DMV; Title 21 Ch. 26.","handbook":"","hbref":""},{"q":"What is the minimum age to drive a commercial vehicle in interstate commerce, carry hazardous materials, or transport passengers under a Delaware CDL?","options":["21 years old","18 years old","19 years old","23 years old"],"answer":0,"explanation":"A driver must be at least 21 years old to operate in interstate commerce, transport hazardous materials requiring placards, or carry passengers. Source: Delaware DMV; 49 CFR 383.","handbook":"","hbref":""},{"q":"What documents must a Delaware applicant present when arriving for the CDL skills (road) test?","options":["Valid learner's permit, valid license of the accompanying 21+ driver, valid vehicle registration, and valid insurance","Only a valid learner's permit and Social Security card","Only a passport and the test fee receipt","A birth certificate and two utility bills"],"answer":0,"explanation":"For the road test the applicant must present a valid learner's permit, the valid driver license of the accompanying driver (21+), a valid vehicle registration card, and a valid insurance card. Source: Delaware DMV CDL webpage.","handbook":"","hbref":""},{"q":"What score is required to pass the Delaware CDL general knowledge written test?","options":["80% correct (40 of 50 questions)","70% correct (35 of 50 questions)","90% correct (45 of 50 questions)","100% correct (all 50 questions)"],"answer":0,"explanation":"The Delaware CDL general knowledge test has 50 questions and requires a score of 80% (40 of 50) or better to pass. Source: Delaware DMV / AAMVA-based CDL testing system used in Delaware.","handbook":"","hbref":""},{"q":"Which document is the primary self-study reference Delaware provides for preparing for the CDL knowledge and skills tests?","options":["The Delaware CDL Manual (Commercial Driver License Manual) published by the DMV","The Delaware Code, Title 21 annotated edition","The FMCSA Pocket Guide to Large Truck and Bus Statistics","The state Driver's Education textbook"],"answer":0,"explanation":"Delaware's DMV publishes the Delaware CDL Manual (based on the AAMVA model), which applicants should obtain and study before testing. Source: Delaware DMV CDL Manual.","handbook":"","hbref":""},{"q":"How is the on-road portion of the Delaware CDL skills test scheduled, and how is the pre-trip portion supported?","options":["The skills test is by appointment, and the DMV provides a pre-trip inspection checklist as an aide to applicants","All three skills parts are walk-in, and no checklist is provided","The road test is online; the pre-trip is waived for ELDT graduates","Scheduling is done only through the applicant's employer"],"answer":0,"explanation":"Delaware CDL skills tests are by appointment only, and the modernized program provides applicants a checklist for the pre-trip vehicle inspection test as a study aide. Source: Delaware DMV CDL webpage (modernized skills test, effective February 26, 2025).","handbook":"","hbref":""},{"q":"What generally happens to a Delaware CDL if the holder who self-certified as interstate non-excepted fails to keep a current medical examiner's certificate on file with the DMV?","options":["The commercial (CDL) privilege is downgraded so the person can no longer operate commercial vehicles","The CDL is permanently revoked and cannot be reinstated","Nothing, because the medical certificate is only an employer record","The license converts automatically to an interstate excepted CDL"],"answer":0,"explanation":"If a required (non-excepted) driver lets the medical certificate lapse or fails to submit it, the state must downgrade the CDL, removing commercial driving privileges until a valid certificate is on file. Source: Delaware DMV Self-Certification FAQ; 49 CFR 383.73.","handbook":"","hbref":""},{"q":"For an interstate non-excepted Delaware driver, how recent must the DOT physical examination supporting the medical certificate generally be?","options":["Dated within the prior 24 months (up to a 2-year maximum certification)","Dated within the prior 6 months","Dated within the prior 12 months only","Dated within the prior 5 years"],"answer":0,"explanation":"The DOT physical must meet 49 CFR 391.41-391.49 and may certify a driver for up to 24 months (a medical examiner can certify for a shorter period for certain conditions). Delaware requires this federal standard. Source: Delaware DMV Medical Certification page; 49 CFR 391.43.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая законом высота транспортного средства, включая груз, на автодорогах штата Делавэр?","options":["13 feet 6 inches","14 feet","13 feet","12 feet 6 inches"],"explanation":"Закон штата Делавэр устанавливает максимальную высоту транспортного средства вместе с грузом на уровне 13 feet 6 inches как на обычных дорогах, так и на системе межштатных магистралей. Источник: Delaware Code Title 21, Ch. 45, sections 4502(b) and 4503(b)."},"1":{"q":"Какова максимальная общая внешняя ширина, разрешённая для большинства коммерческих транспортных средств в штате Делавэр, без учёта оборудования безопасности?","options":["102 inches","96 inches","108 inches","120 inches"],"explanation":"Штат Делавэр ограничивает общую внешнюю ширину транспортного средства до 102 inches (8 feet 6 inches), без учёта оборудования безопасности. Источник: Delaware Code Title 21, sections 4502 and 4503; DelDOT OSOW legal limits."},"2":{"q":"Какова максимальная допустимая длина полуприцепа (без учёта тягача), эксплуатируемого в штате Делавэр?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"Полуприцеп, включая любой груз, не может превышать 53 feet в длину, без учёта тягача. Источник: Delaware Code Title 21, Ch. 45, section 4503(b)."},"3":{"q":"Какова максимальная полная масса для типичного автопоезда с пятью или более осями в штате Делавэр?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"Штат Делавэр ограничивает полную массу автопоезда из пяти или более осей до 80,000 pounds, что соответствует федеральному ограничению. Источник: Delaware Code Title 21, Ch. 45, sections 4502(c) and 4503(c)."},"4":{"q":"Какова максимальная нагрузка на одиночную ось, разрешённая на системе межштатных магистралей в штате Делавэр?","options":["20,000 pounds","22,400 pounds","18,000 pounds","24,000 pounds"],"explanation":"На межштатных магистралях штат Делавэр следует федеральному ограничению нагрузки на одиночную ось в 20,000 pounds. Источник: Delaware Code Title 21, Ch. 45, section 4503(c)."},"5":{"q":"Какова максимальная нагрузка на сдвоенную ось, разрешённая на системе межштатных магистралей в штате Делавэр?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"explanation":"На межштатных магистралях ограничение нагрузки на сдвоенную ось составляет 34,000 pounds, что соответствует федеральному стандарту. Источник: Delaware Code Title 21, Ch. 45, section 4503(c)."},"6":{"q":"Когда требуется разрешение Delaware DOT на перевозку негабаритного/тяжеловесного груза?","options":["Когда транспортное средство или груз превышает ограничения по размерам или массе, установленные в Chapter 45, Title 21 of the Delaware Code","Только когда полная масса превышает 80,000 pounds, независимо от нагрузки на оси","Только для грузов шириной более 12 feet","Только при движении по Interstate 95"],"explanation":"Разрешение требуется всякий раз, когда транспортное средство, автопоезд или самоходное оборудование превышает ограничения по габаритам и/или массе, установленные в Chapter 45, Title 21 of the Delaware Code, в том числе когда отдельная ось перегружена, даже если полная масса находится в пределах нормы. Источник: DelDOT OSOW permit FAQ; Delaware Code Title 21, section 4504."},"7":{"q":"Как получают разрешения штата Делавэр на перевозку негабаритных/тяжеловесных грузов?","options":["Через онлайн-систему разрешений DelDOT Oversize/Overweight (OSOW), которой управляет Hauling Permit Office","Отправив бумажную форму по почте в отдел CDL Delaware DMV","Купив их на любой стойке транспортных услуг DMV","Они выдаются автоматически вместе с регистрацией транспортного средства"],"explanation":"Разрешения на негабаритные/тяжеловесные грузы выдаёт DelDOT через свою онлайн-систему OSOW, которой управляет Hauling Permit Office, а не DMV. Источник: DelDOT OSOW permit system (deldot.gov/osow)."},"8":{"q":"Каков минимальный сбор за стандартное разовое разрешение штата Делавэр на перевозку негабаритного/тяжеловесного груза?","options":["$30.00","$15.00","$50.00","$10.00"],"explanation":"Минимальный сбор за разовое разрешение на перевозку составляет $30.00 ($60.00 за Superload). Источник: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405 permit policy manual."},"9":{"q":"Как рассчитывается дополнительный сбор за перегруз для тяжеловесного разрешения штата Делавэр?","options":["$10.00 за каждые 8,000 pounds (или их часть) сверх установленного законом ограничения массы","$25.00 за каждые 5,000 pounds сверх установленного законом ограничения массы","$5.00 за каждые 1,000 pounds сверх установленного законом ограничения массы","Фиксированные $100.00 независимо от величины перегруза"],"explanation":"Штат Делавэр добавляет сбор за массу в размере $10.00 за каждые 8,000 pounds, или их часть, сверх установленного законом ограничения массы. Источник: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405."},"10":{"q":"В течение какого срока действует стандартное разовое разрешение штата Делавэр на перевозку негабаритного/тяжеловесного груза?","options":["5 days (от даты вступления в силу до даты истечения)","24 hours","30 days","10 days"],"explanation":"Стандартное разрешение на перевозку действительно в течение пяти дней, от даты вступления в силу до даты истечения срока. Источник: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405."},"11":{"q":"В какие часы разрешённый негабаритный груз обычно может перемещаться по автодорогам штата Делавэр, если в разрешении не указано иное?","options":["От восхода до заката, с понедельника по воскресенье","Только с понедельника по пятницу в рабочее время","Только с 9 p.m. до 5 a.m.","В любое время, 24 hours в сутки, без ограничений"],"explanation":"Разрешённым грузам дозволено перемещаться от восхода до заката, с понедельника по воскресенье, если особые условия разрешения не предусматривают иное. Источник: DelDOT OSOW permit FAQ."},"12":{"q":"Какую формулу применяет штат Делавэр для определения максимальной полной массы на группе последовательных осей?","options":["Федеральную формулу моста (Bridge Formula), W = 500[(LN / (N-1)) + 12N + 36]","Фиксированные 1,000 pounds на дюйм ширины шины","GVWR производителя, умноженный на 1.5","Простые 20,000 pounds на ось без учёта расстояния между осями"],"explanation":"Штат Делавэр применяет федеральную формулу моста (Bridge Formula), W = 500[(LN / (N-1)) + 12N + 36], где W — допустимая масса, L — расстояние между крайними осями группы, а N — количество осей. Источник: Delaware Code Title 21, Ch. 45, section 4503(c)."},"13":{"q":"Согласно правилу мостовой нагрузки штата Делавэр, два последовательных комплекта сдвоенных осей могут нести по 34,000 pounds каждый при условии, что расстояние между первой и последней осью этих комплектов составляет не менее:","options":["36 feet","30 feet","40 feet","24 feet"],"explanation":"Исключение из формулы моста позволяет двум последовательным комплектам сдвоенных осей нести по 34,000 pounds каждый, когда общее расстояние между первой и последней осью этих комплектов составляет 36 feet или более. Источник: Delaware Code Title 21, Ch. 45, section 4503(c)."},"14":{"q":"На дорогах штата Делавэр, которые НЕ входят в систему межштатных магистралей или федеральную систему первичных дорог, какова максимальная нагрузка на одиночную ось?","options":["22,400 pounds","20,000 pounds","18,000 pounds","25,000 pounds"],"explanation":"На дорогах штата вне межштатных магистралей штат Делавэр допускает более высокую нагрузку на одиночную ось в 22,400 pounds по сравнению с 20,000 pounds на межштатных магистралях. Источник: Delaware Code Title 21, Ch. 45, section 4502(c)."},"15":{"q":"Штат Делавэр предоставляет послабление по массе для грузовиков, перевозящих определённую сельскохозяйственную продукцию или зерно, выращенные в штате. До какой полной массы могут эксплуатироваться такие транспортные средства?","options":["90,000 pounds","80,000 pounds","100,000 pounds","85,000 pounds"],"explanation":"Штат Делавэр позволяет грузовикам, перевозящим выращенные в штате фрукты, овощи или товарное зерно, достигать массы до 90,000 pounds (или паспортной полной массы автопоезда, установленной производителем, в зависимости от того, что меньше). Источник: Delaware Code Title 21, Ch. 45, section 4502(c)."},"16":{"q":"Положение штата Делавэр о перевозке живой птицы включает допуск на учёт осадков и различий в размерах птицы. Какова эта процентная погрешность?","options":["3%","5%","10%","1%"],"explanation":"Грузовики, перевозящие живую птицу в пределах штата Делавэр, могут эксплуатироваться с массой до 90,000 pounds с погрешностью 3% на различия в массе, вызванные осадками и размером птицы. Источник: Delaware Code Title 21, Ch. 45, section 4502(c)."},"17":{"q":"На дорогах штата Делавэр, отличных от межштатных магистралей и федеральной системы первичных дорог, какова максимальная длина одиночного транспортного средства (не автопоезда)?","options":["40 feet","45 feet","53 feet","35 feet"],"explanation":"На дорогах вне межштатных магистралей одиночное транспортное средство не может превышать 40 feet, а автопоезд не может превышать 60 feet. Источник: Delaware Code Title 21, Ch. 45, section 4502(b)."},"18":{"q":"В составе автопоезда тягач-полуприцеп-прицеп (сдвоенный) в штате Делавэр, какова максимальная длина каждого прицепа или полуприцепа?","options":["29 feet","28 feet","33 feet","31 feet"],"explanation":"Каждый прицеп или полуприцеп в составе автопоезда тягач-полуприцеп-прицеп ограничен 29 feet, без учёта тягача. Источник: Delaware Code Title 21, Ch. 45, section 4503(b)."},"19":{"q":"При каких условиях перевозка негабаритного/тяжеловесного груза в штате Делавэр квалифицируется как 'Superload', что влечёт более высокий минимальный сбор за разрешение?","options":["Длина 120 feet, ширина 15 feet, высота 15 feet или полная масса более 120,000 pounds","Любой груз с полной массой более 90,000 pounds","Любой груз шириной более 10 feet","Длина более 75 feet или масса более 100,000 pounds"],"explanation":"Перевозка классифицируется как Superload, когда длина достигает 120 feet, ширина достигает 15 feet, высота достигает 15 feet или полная масса превышает 120,000 pounds; минимальный сбор за разрешение Superload составляет $60.00. Источник: DelDOT OSOW permit FAQ."},"20":{"q":"В штате Делавэр, какой класс CDL требуется для управления автопоездом с полной массой (GVWR) 26,001 pounds или более при условии, что GVWR буксируемого звена превышает 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Delaware Commercial Driver's Manual (Version 4.0, \"Types of CDL\") гласит, что CDL класса Class A требуется для любого автопоезда с GVWR 26,001 pounds или более при условии, что GVWR буксируемого звена (звеньев) превышает 10,000 pounds."},"21":{"q":"По правилам штата Делавэр, одиночное транспортное средство с GVWR 26,001 pounds или более, которое не буксирует звено массой свыше 10,000 pounds, требует какого класса CDL?","options":["Class A","Class B","Class C","Class M"],"explanation":"Delaware Commercial Driver's Manual определяет Class B как любое одиночное транспортное средство с GVWR 26,001 pounds или более, либо такое транспортное средство, буксирующее транспортное средство с GVWR не более 10,000 pounds."},"22":{"q":"В штате Делавэр транспортное средство с GVWR менее 26,001 pounds, предназначенное для перевозки 16 или более пассажиров (включая водителя) либо перевозящее опасные материалы, требующие нанесения табличек (placard), требует какого класса CDL?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"Согласно Delaware Commercial Driver's Manual, CDL класса Class C требуется для транспортного средства с GVWR менее 26,001 pounds, предназначенного для перевозки 16 или более человек, включая водителя, либо используемого для перевозки опасных материалов, требующих нанесения табличек (placard)."},"23":{"q":"В CDL штата Делавэр какой код подтверждения (endorsement) разрешает управление цистерной?","options":["Code N","Code T","Code H","Code P"],"explanation":"Delaware Commercial Driver's Manual указывает подтверждение для цистерн (Tanker) под кодом N. Подтверждение T предназначено для сдвоенных/строенных прицепов (Doubles/Triples), H — для опасных материалов (Hazardous Materials), а P — для пассажиров (Passenger)."},"24":{"q":"Какое подтверждение (endorsement) CDL штата Делавэр требуется для буксировки сдвоенных или строенных прицепов?","options":["Endorsement T","Endorsement N","Endorsement X","Endorsement P"],"explanation":"Delaware Commercial Driver's Manual указывает подтверждение для сдвоенных/строенных прицепов (Doubles/Triples) под кодом T и требует сдачи специального экзамена на знание проблем, связанных с буксировкой нескольких прицепов."},"25":{"q":"Согласно Delaware Commercial Driver's Manual, подтверждение для цистерн Tank Vehicle (N) требуется, когда транспортное средство предназначено для перевозки жидкости или газа в цистерне с индивидуальной паспортной ёмкостью более 119 gallons и совокупной паспортной ёмкостью не менее скольких галлонов?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"Delaware Commercial Driver's Manual гласит, что подтверждение Tank Vehicle (N) применяется к цистернам с индивидуальной паспортной ёмкостью более 119 gallons и совокупной паспортной ёмкостью 1,000 gallons или более."},"26":{"q":"В штате Делавэр, каков минимальный возраст для получения CDL для управления в пределах штата (только внутри Делавэра)?","options":["16 years","17 years","18 years","21 years"],"explanation":"Базовые требования к CDL в Delaware Commercial Driver's Manual гласят, что для управления в пределах штата заявителю должно быть 18 years и иметь 1 year стажа вождения."},"27":{"q":"Согласно базовым требованиям к CDL штата Делавэр, какой минимальный возраст необходим для управления в межштатном сообщении или для перевозки опасных материалов?","options":["18 years","19 years","20 years","21 years"],"explanation":"Delaware Commercial Driver's Manual требует, чтобы для управления в межштатном сообщении или для перевозки опасных материалов заявителю был 21 year и он имел не менее 1 year стажа вождения."},"28":{"q":"После сдачи экзаменов на знания, как долго владелец ученического коммерческого разрешения Delaware Commercial Learner's Permit (CLP) должен иметь CLP, прежде чем ему будет разрешено сдавать экзамен на навыки CDL?","options":["Минимум 14 full days","Минимум 10 full days","Минимум 7 full days","Минимум 30 full days"],"explanation":"Delaware Commercial Driver's Manual гласит, что вы должны иметь CLP минимум 14 full days, прежде чем сможете сдавать экзамен на навыки CDL, что соответствует федеральному требованию 49 CFR 383."},"29":{"q":"При управлении с ученическим коммерческим разрешением Delaware Commercial Learner's Permit (CLP), владелец должен сопровождаться кем?","options":["Любым лицензированным водителем в возрасте 18 лет или старше","Лицензированным водителем CDL, имеющим квалификацию на тот же тип CMV","Только сертифицированным экзаменатором DMV","Никем; CLP разрешает самостоятельное вождение"],"explanation":"Delaware Commercial Driver's Manual гласит, что CLP позволяет вам управлять CMV в сопровождении другого лицензированного водителя CDL, и вы можете управлять только тем типом транспортного средства, на который вы сдавали экзамен, в сопровождении водителя CDL, имеющего квалификацию на тот же тип CMV."},"30":{"q":"Прежде чем заявителю будет выдан CDL штата Делавэр с подтверждением на опасные материалы (H), что заявитель должен сначала пройти?","options":["Курс безопасного вождения в DMV","30-дневный период ожидания после экзамена на навыки","Оценку угрозы безопасности TSA, включая снятие отпечатков пальцев","Отдельный дорожный экзамен на транспортном средстве с табличками (placard)"],"explanation":"Delaware Commercial Driver's Manual гласит, что CDL с подтверждением hazmat не может быть выдан, если заявитель сначала не прошёл оценку угрозы безопасности TSA (включая снятие отпечатков пальцев и проверку гражданства/законного нахождения) и не получил допуск TSA."},"31":{"q":"Согласно федеральному правилу Entry-Level Driver Training (ELDT), применяемому в штате Делавэр, обучение должно проводиться школой, внесённой в какой реестр?","options":["Список одобренных школ Delaware DMV Approved Schools","Справочник инструкторов AAMVA Instructor Directory","Реестр поставщиков обучения FMCSA Training Provider Registry (TPR)","Реестр сертифицированных инструкторов TSA Certified Trainer Registry"],"explanation":"Страница ELDT на сайте Delaware DMV гласит, что обучение водителей начального уровня должно быть пройдено через зарегистрированного в FMCSA поставщика, внесённого в FMCSA Training Provider Registry (tpr.fmcsa.dot.gov), прежде чем заявитель сможет сдавать экзамен на навыки CDL."},"32":{"q":"Для чего из перечисленного штат Делавэр требует прохождения ELDT (Entry-Level Driver Training) перед тем, как можно сдавать экзамен на навыки/знания?","options":["Добавление подтверждения для цистерн Tanker (N)","Добавление подтверждения для сдвоенных/строенных прицепов Doubles/Triples (T)","Продление существующего CDL","Получение CDL класса Class A или Class B впервые"],"explanation":"Согласно странице ELDT на сайте Delaware DMV (вступило в силу Feb 7, 2022), ELDT требуется для заявителей, впервые получающих Class A или B, для повышения до более высокого класса, а также для подтверждений S, P и H. Оно не требуется для подтверждений N или T, а также при продлении."},"33":{"q":"Штат Делавэр требует, чтобы владельцы CDL самостоятельно подтверждали тип своего вождения. Сколько существует категорий самоподтверждения?","options":["Две","Три","Четыре","Пять"],"explanation":"Delaware Commercial Driver's Manual гласит, что владельцы CDL должны самостоятельно подтвердить статус вождения как non-excepted interstate, non-excepted intrastate, excepted interstate или excepted intrastate — четыре категории."},"34":{"q":"Заявитель на CDL в штате Делавэр, который управляет CMV в межштатном сообщении и подпадает под действие федеральных правил физической пригодности, подтверждает себя в какой категории медицинского самоподтверждения?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Delaware Commercial Driver's Manual поясняет, что владельцы CDL, которые управляют CMV в межштатном сообщении и должны соответствовать федеральному требованию о медицинском сертификате, являются водителями категории non-excepted interstate commerce."},"35":{"q":"Когда CLP штата Делавэр выдаётся с подтверждением для пассажиров Passenger (P), какое ограничение оно также должно содержать?","options":["Ограничение 'K' Intrastate Only (только в пределах штата)","Ограничение 'L' No air brake (без пневмотормозов)","Ограничение 'P' No passengers in a CMV bus (без пассажиров в автобусе CMV)","Ограничение 'E' No manual transmission (без механической коробки передач)"],"explanation":"Delaware Commercial Driver's Manual отмечает, что если CLP выдаётся с подтверждением для пассажиров Passenger (P) или для школьного автобуса School Bus (S), оно также должно содержать ограничение 'P' – No passengers in a CMV bus (разрешая на борту только определённый персонал)."},"36":{"q":"Если CLP штата Делавэр выдаётся с подтверждением для цистерн Tanker (N), какое дополнительное ограничение на него накладывается?","options":["'X' – No cargo in a CMV tank vehicle (без груза в цистерне CMV)","'Z' – No full air brake equipped CMV (без CMV с полной системой пневмотормозов)","'V' – Medical variance (медицинское исключение)","'O' – No tractor-trailer CMV (без CMV типа тягач-прицеп)"],"explanation":"Delaware Commercial Driver's Manual гласит, что CLP, выданное с подтверждением для цистерн Tanker (N), также должно содержать ограничение 'X' – No cargo in a CMV tank vehicle, то есть владелец может управлять только пустой, продутой цистерной."},"37":{"q":"Какие документы требует Delaware DMV предъявить заявителю в отношении проживания в штате Делавэр при подаче заявления на права?","options":["Одно подтверждение проживания в штате Делавэр","Три подтверждения проживания в штате Делавэр","Только нотариально заверенный аффидевит о проживании","Два подтверждения проживания в штате Делавэр"],"explanation":"Delaware DMV требует, чтобы заявители предоставили подтверждение личности (один первичный и один вторичный документ), номер социального страхования при наличии права на него, а также два подтверждения проживания в штате Делавэр; неграждане США также должны предъявить подтверждение законного нахождения (требования Delaware DMV к документам для Driver License/ID)."},"38":{"q":"По правилам штата Делавэр, что требуется от лица, желающего управлять школьным автобусом?","options":["Только CDL класса Class C без подтверждений","CDL с подтверждениями для пассажиров Passenger (P) и для школьного автобуса School Bus (S), а также соответствие требованиям Department of Education","Стандартные права класса Class D со стикером школьного автобуса","Подтверждение для цистерн Tanker (N) и проверка биографии TSA"],"explanation":"Delaware Commercial Driver's Manual гласит, что все водители школьных автобусов в штате Делавэр должны иметь CDL и соответствовать дополнительным требованиям Delaware Department of Education по обучению и медицине; затем DMV выдаёт CDL с подтверждениями P и S (с ограничением M или N в зависимости от класса транспортного средства)."},"39":{"q":"Штат Делавэр предлагает специальное удостоверение без CDL согласно федеральным положениям об освобождении от CDL для какой группы водителей, управляющих CMV?","options":["Дальнобойщики межштатного сообщения","Операторы цистерн с hazmat","Водители чартерных автобусов","Фермеры и пожарные"],"explanation":"Delaware Commercial Driver's Manual гласит, что штат Делавэр имеет специальное Non-CDL для идентификации фермеров и пожарных, которые управляют CMV согласно положениям об освобождении от CDL; такое Non-CDL не может использоваться в межштатном сообщении или в коммерческих перевозках по найму."},"40":{"q":"В штате Делавэр, какова максимальная концентрация алкоголя в крови (BAC), при которой лицо может законно управлять коммерческим транспортным средством (CMV)?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"explanation":"Штат Делавэр считает незаконным управление CMV с BAC 0.04 percent или более, что вдвое меньше предела 0.08 для частных транспортных средств. Источник: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"41":{"q":"Согласно закону штата Делавэр о подразумеваемом согласии, когда лицо управляет коммерческим транспортным средством в штате, считается, что оно дало согласие на что?","options":["Обыск груза транспортного средства","Тестирование на концентрацию алкоголя","Медицинское обследование на пригодность","Раскрытие сведений о трудоустройстве"],"explanation":"Управляя CMV в штате Делавэр, водитель считается давшим согласие на тестирование на алкоголь (химическое тестирование). Источник: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614 (подразумеваемое согласие для водителей CMV)."},"42":{"q":"Как долго владелец CDL штата Делавэр дисквалифицирован за ПЕРВОЕ серьёзное нарушение, например за управление CMV с BAC 0.04 или выше, когда не перевозятся опасные материалы?","options":["60 days","120 days","1 year","3 years"],"explanation":"Первое серьёзное нарушение влечёт за собой дисквалификацию CDL на 1 year в штате Делавэр. Источник: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612 (федеральный стандарт 49 CFR 383.51, применяемый штатом)."},"43":{"q":"В штате Делавэр дисквалификация за первое серьёзное нарушение увеличивается до трёх лет, когда нарушение совершается, пока водитель управляет CMV, который делает что?","options":["Имеет таблички (placard) для опасных материалов","Перевозит пассажиров по найму","Буксирует сдвоенный прицеп","Пересекает границы штатов"],"explanation":"Первое серьёзное нарушение, совершённое при управлении CMV с табличками (placard) для опасных материалов, повышает дисквалификацию с 1 year до 3 years. Источник: Delaware CDL Manual Section 1.3.2; 49 CFR 383.51."},"44":{"q":"Каков срок дисквалификации CDL в штате Делавэр за ВТОРОЕ серьёзное нарушение (например, второе осуждение за управление в состоянии опьянения)?","options":["3 years","10 years","Пожизненно","5 years"],"explanation":"Второе серьёзное нарушение на любом транспортном средстве влечёт за собой пожизненную дисквалификацию CDL в штате Делавэр. Источник: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612; 49 CFR 383.51."},"45":{"q":"По правилам CDL штата Делавэр, отказ пройти обязательное тестирование на алкоголь/химическое тестирование при управлении CMV рассматривается как какой вид нарушения?","options":["Серьёзное нарушение правил дорожного движения","Тяжкое нарушение (major offense)","Нарушение предписания о выводе из эксплуатации (out-of-service)","Незаявляемое нарушение"],"explanation":"Отказ от прохождения тестирования на содержание алкоголя в крови входит в число тяжких нарушений (major offenses), влекущих как минимум дисквалификацию на 1 year за первое нарушение. Источник: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"46":{"q":"Согласно предупреждению штата Делавэр о подразумеваемом согласии для водителей CMV, отказ от теста на алкоголь приводит к немедленному выводу из эксплуатации на какой срок, плюс дисквалификация?","options":["8 hours","12 hours","24 hours","48 hours"],"explanation":"Закон штата Делавэр требует, чтобы сотрудник предупредил водителя, что отказ приводит к немедленному выводу из эксплуатации на 24 hours и дисквалификации не менее чем на 1 year. Источник: 21 Del. C. Section 2614."},"47":{"q":"У водителя CMV в штате Делавэр обнаружен BAC 0.02 (измеримое количество алкоголя ниже 0.04). Каково обязательное последствие?","options":["Дисквалификация CDL на 60 days","Вывод из эксплуатации на 24 hours","Дисквалификация CDL на 1 year","Пожизненная дисквалификация CDL"],"explanation":"Любое обнаруживаемое количество алкоголя ниже 0.04 (измеримое количество от 0.02 до менее 0.04) требует вывода водителя из эксплуатации на 24 hours. Источник: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"48":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения по правилам CDL штата Делавэр?","options":["Управление CMV с BAC 0.04","Чрезмерное превышение скорости на 15 mph или более сверх ограничения","Оставление места происшествия","Нарушение предписания о выводе из эксплуатации (out-of-service)"],"explanation":"Чрезмерное превышение скорости (на 15 mph или более сверх установленного ограничения) является серьёзным нарушением правил дорожного движения. Остальные перечисленные пункты являются тяжкими нарушениями (major offenses) или нарушениями предписания о выводе из эксплуатации. Источник: Delaware CDL Manual Section 1.3.3."},"49":{"q":"В штате Делавэр, как долго CDL дисквалифицирован за осуждение по ДВУМ серьёзным нарушениям правил дорожного движения на CMV в течение трёхлетнего периода?","options":["30 days","60 days","120 days","1 year"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение любого трёхлетнего периода влекут за собой дисквалификацию CDL на 60 days. Источник: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51."},"50":{"q":"Каков срок дисквалификации CDL в штате Делавэр за осуждение по ТРЁМ или более серьёзным нарушениям правил дорожного движения на CMV в течение трёхлетнего периода?","options":["60 days","90 days","120 days","180 days"],"explanation":"Три или более серьёзных нарушения правил дорожного движения в течение любого трёхлетнего периода влекут за собой дисквалификацию CDL на 120 days. Источник: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51."},"51":{"q":"Что из перечисленного является серьёзным нарушением правил дорожного движения по правилам CDL штата Делавэр, а не тяжким нарушением (major offense)?","options":["Движение за транспортным средством на слишком близком расстоянии","Использование CMV для совершения тяжкого преступления (felony)","Причинение смерти в результате небрежного управления CMV","Управление CMV в состоянии опьянения контролируемым веществом"],"explanation":"Движение за транспортным средством на слишком близком расстоянии является серьёзным нарушением правил дорожного движения. Остальные три являются тяжкими нарушениями (major offenses). Источник: Delaware CDL Manual Section 1.3.3 (серьёзные) и Section 1.3.2 (тяжкие)."},"52":{"q":"Отправка текстовых сообщений или использование портативного мобильного телефона при управлении CMV рассматривается по правилам CDL штата Делавэр как какой вид нарушения?","options":["Тяжкое нарушение (major offense)","Серьёзное нарушение правил дорожного движения","Нарушение предписания о выводе из эксплуатации (out-of-service)","Нарушение на железнодорожном переезде"],"explanation":"Отправка текстовых сообщений или использование портативного телефона при управлении CMV является серьёзным нарушением правил дорожного движения и засчитывается в пороги дисквалификации на 60 days/120 days. Источник: Delaware CDL Manual Section 1.3.3 и раздел об отправке сообщений/телефоне; 49 CFR 383.51."},"53":{"q":"По правилам CDL штата Делавэр/федеральным правилам, CDL дисквалифицируется на 60 days после скольких осуждений за использование портативного мобильного телефона при управлении CMV (в течение 3 years)?","options":["Одного осуждения","Двух или более осуждений","Четырёх осуждений","Пяти осуждений"],"explanation":"Два или более осуждения за нарушение закона о портативном телефоне при управлении CMV в течение 3 years влекут за собой дисквалификацию на 60 days (120 days за три или более). Источник: раздел Delaware CDL Manual о портативном мобильном телефоне; 49 CFR 383.51."},"54":{"q":"Каков максимальный федеральный гражданский штраф, который может грозить водителю CMV за нарушение, связанное с отправкой текстовых сообщений за рулём, как указано в Delaware CDL Manual?","options":["До $750","До $1,500","До $2,750","До $11,000"],"explanation":"Delaware CDL Manual гласит, что водители подлежат гражданским штрафам до $2,750 за нарушения, связанные с отправкой сообщений/портативным телефоном (работодатели — до $11,000). Источник: раздел Delaware CDL Manual об отправке сообщений и портативном мобильном телефоне."},"55":{"q":"Как долго CDL штата Делавэр дисквалифицирован за ПЕРВОЕ осуждение за нарушение на железнодорожно-автомобильном переезде на CMV?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Первое нарушение на железнодорожно-автомобильном переезде влечёт за собой дисквалификацию не менее чем на 60 days. Источник: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"56":{"q":"В штате Делавэр ВТОРОЕ нарушение на железнодорожно-автомобильном переезде на CMV в течение трёх лет дисквалифицирует CDL не менее чем на какой срок?","options":["60 days","120 days","180 days","1 year"],"explanation":"Второе нарушение на железнодорожном переезде в течение любого трёхлетнего периода влечёт за собой дисквалификацию не менее чем на 120 days. Источник: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"57":{"q":"Водитель CMV в штате Делавэр совершает ТРЕТЬЕ нарушение на железнодорожно-автомобильном переезде в течение трёх лет. CDL дисквалифицируется не менее чем на какой срок?","options":["120 days","180 days","1 year","3 years"],"explanation":"Третье нарушение на железнодорожном переезде в течение любого трёхлетнего периода влечёт за собой дисквалификацию не менее чем на 1 year. Источник: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"58":{"q":"По правилам CDL штата Делавэр, каков диапазон дисквалификации за ПЕРВОЕ осуждение за нарушение предписания о выводе из эксплуатации (out-of-service) на CMV (без перевозки опасных материалов)?","options":["Не менее 30 days и не более 90 days","Не менее 180 days и не более 1 year","Не менее 1 year и не более 2 years","Не менее 3 years и не более 5 years"],"explanation":"Первое нарушение предписания о выводе из эксплуатации влечёт за собой дисквалификацию не менее чем на 180 days и не более чем на 1 year. Источник: раздел Delaware CDL Manual о дисквалифицирующих нарушениях MCSIA; 49 CFR 383.51."},"59":{"q":"Согласно закону штата Делавэр «Move Over» («Уступи дорогу»), когда вы приближаетесь к остановившемуся автомобилю DelDOT, полиции, эвакуатора или экстренной службы с включёнными проблесковыми маячками на шоссе, имеющем четыре или более полос в вашем направлении, что вы должны сделать в первую очередь?","options":["Перестроиться в полосу, не примыкающую к остановившемуся автомобилю, если это можно сделать безопасно","Полностью остановиться и стоять, пока остановившийся автомобиль не покинет обочину","Съехать на обочину и проехать со скоростью не более 10 mph","Сохранять свою полосу и непрерывно сигналить клаксоном во время проезда"],"explanation":"Раздел 21 Свода законов Делавэра § 4134(b) требует, чтобы водители на проезжей части, имеющей не менее четырёх полос в одном направлении, уступали дорогу, перестраиваясь в полосу, не примыкающую к остановившемуся автомобилю экстренной службы / DelDOT / эвакуатора / коммунальной службы, когда это безопасно. Источник: 21 Del. C. § 4134."},"60":{"q":"Согласно закону штата Делавэр «Move Over», если вы не можете безопасно перестроиться в сторону от остановившегося экстренного автомобиля, какое снижение скорости требуется там, где установленное ограничение составляет 50 mph или выше?","options":["Снизить до безопасной скорости, по меньшей мере на 20 mph ниже установленного ограничения скорости","Снизить до безопасной скорости, по меньшей мере на 10 mph ниже установленного ограничения скорости","Снизить ровно до половины установленного ограничения скорости","Снизить до не более чем 25 mph независимо от установленного ограничения"],"explanation":"21 Del. C. § 4134(b) требует, чтобы при невозможности перестроения водитель снизил скорость до безопасной, по меньшей мере на 20 mph ниже установленного ограничения там, где ограничение составляет 50 mph или выше. Источник: 21 Del. C. § 4134."},"61":{"q":"Когда школьный автобус в Делавэре остановился на неразделённой двухполосной дороге с мигающими красными огнями, какие водители обязаны остановиться?","options":["Водители, приближающиеся как спереди, так и сзади","Только водители, приближающиеся сзади (в том же направлении, что и автобус)","Только водители, приближающиеся спереди (встречные)","Только водители в пределах 20 футов от автобуса"],"explanation":"Раздел 21 Свода законов Делавэра § 4166 требует, чтобы водитель любого транспортного средства, приближающегося к остановившемуся школьному автобусу спереди или сзади, остановился перед проездом автобуса, когда его красные стоп-сигналы включены. Источник: 21 Del. C. § 4166."},"62":{"q":"На проезжей части (или проезжих частях) в Делавэре, имеющей четыре или более полос, какой приближающийся водитель НЕ обязан останавливаться перед школьным автобусом с мигающими красными огнями?","options":["Водитель, приближающийся спереди (встречное направление)","Водитель, приближающийся сзади (в том же направлении, что и автобус)","Оба водителя, спереди и сзади, освобождены от обязанности","Ни один из водителей не освобождён; оба всегда обязаны останавливаться"],"explanation":"21 Del. C. § 4166 предусматривает, что на проезжей части или проезжих частях, имеющих 4 или более полос, водитель, приближающийся спереди (с противоположного направления), останавливаться не обязан; водитель, приближающийся сзади, по-прежнему обязан остановиться. Источник: 21 Del. C. § 4166."},"63":{"q":"После остановки перед школьным автобусом в Делавэре с мигающими красными огнями, как долго водитель должен оставаться на месте?","options":["Пока автобус не начнёт движение или пока его красные стоп-сигналы не перестанут гореть","В течение фиксированного минимума в 30 секунд","Пока водитель автобуса не махнёт рукой, разрешая движение","Пока все дети не окажутся на расстоянии не менее 100 футов от автобуса"],"explanation":"21 Del. C. § 4166 требует, чтобы водитель оставался на месте, пока автобус не начнёт движение или пока на нём не погаснут включённые красные стоп-сигналы. Источник: 21 Del. C. § 4166."},"64":{"q":"Согласно руководству CDL штата Делавэр, когда транспортное средство с табличками опасных грузов (HazMat) должно остановиться на железнодорожном переезде, где нет нанесённой стоп-линии, где оно должно остановиться относительно ближайшего рельса?","options":["Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Не ближе 10 футов и не дальше 25 футов от ближайшего рельса","Не ближе 25 футов и не дальше 75 футов от ближайшего рельса","Не ближе 5 футов и не дальше 35 футов от ближайшего рельса"],"explanation":"Руководство CDL штата Делавэр (раздел 2.15) указывает, что транспортные средства, обязанные остановиться, должны остановиться не ближе 15 футов и не дальше 50 футов от ближайшего рельса ближайшего пути. Источник: Delaware CDL Manual, Sec. 2.15."},"65":{"q":"Согласно руководству CDL штата Делавэр, пока любая часть вашего коммерческого транспортного средства пересекает железнодорожные пути, чего из перечисленного вы НЕ должны делать?","options":["Переключать передачи во время пересечения путей","Держать обе руки на рулевом колесе","Пересекать только после того, как убедитесь, что все пути свободны","Использовать карман для остановки, когда он доступен"],"explanation":"Руководство CDL штата Делавэр (раздел 2.15) предписывает водителям не переключать передачи во время пересечения железнодорожных путей, чтобы избежать остановки двигателя на переезде. Источник: Delaware CDL Manual, Sec. 2.15."},"66":{"q":"Согласно руководству CDL штата Делавэр, если ваше коммерческое транспортное средство вынуждено остановиться на дороге с односторонним движением или разделённой автомагистрали, на каких расстояниях следует разместить три предупреждающих устройства?","options":["10 футов, 100 футов и 200 футов в сторону приближающегося транспорта","10 футов, 50 футов и 150 футов в сторону приближающегося транспорта","25 футов, 100 футов и 250 футов в сторону приближающегося транспорта","10 футов, 100 футов и 100 футов (одно впереди и одно позади)"],"explanation":"Руководство CDL штата Делавэр (раздел 2.5) предписывает, чтобы на дороге с односторонним движением или разделённой автомагистрали предупреждающие устройства размещались на 10, 100 и 200 футах в сторону приближающегося транспорта. Источник: Delaware CDL Manual, Sec. 2.5."},"67":{"q":"Согласно руководству CDL штата Делавэр, на двухполосной неразделённой дороге с движением в обоих направлениях, где вы размещаете предупреждающие устройства после остановки?","options":["В пределах 10 футов от транспортного средства, а также в 100 футах позади и в 100 футах впереди него","В 200 футах позади и в 200 футах впереди, без устройств возле транспортного средства","Только одно устройство в 100 футах позади транспортного средства","10 футов, 100 футов и 200 футов, все позади транспортного средства"],"explanation":"Руководство CDL штата Делавэр (раздел 2.5) предписывает разместить устройство в пределах 10 футов от переднего или заднего угла, а также устройства в 100 футах позади и в 100 футах впереди транспортного средства на двухполосной / неразделённой дороге. Источник: Delaware CDL Manual, Sec. 2.5."},"68":{"q":"Согласно руководству CDL штата Делавэр, в течение скольких минут после остановки на проезжей части или обочине вы должны выставить аварийные предупреждающие устройства?","options":["10 минут","5 минут","15 минут","30 минут"],"explanation":"Руководство CDL штата Делавэр (раздел 2.5) требует, чтобы аварийные предупреждающие устройства были выставлены в течение 10 минут после остановки на дороге или обочине. Источник: Delaware CDL Manual, Sec. 2.5."},"69":{"q":"Согласно руководству CDL штата Делавэр, какое предупреждающее оборудование должно иметь при себе коммерческое транспортное средство для использования при стоянке или поломке?","options":["Три светоотражающих треугольника, либо не менее 6 фальшфейеров, либо 3 жидкотопливных факела","Два светоотражающих треугольника и один красный флаг","Только четыре светоотражающих треугольника","Один светоотражающий треугольник и маяк на батарейках"],"explanation":"Руководство CDL штата Делавэр перечисляет требуемое аварийное оборудование как три светоотражающих треугольника, либо не менее 6 фальшфейеров, либо 3 жидкотопливных факела. Источник: Delaware CDL Manual, Sec. 2.1 (inspection)."},"70":{"q":"Согласно руководству CDL штата Делавэр, если из-за подъёма или поворота едущие следом водители не видят ваше остановившееся транспортное средство в пределах 500 футов, что вам следует сделать с самым задним предупреждающим треугольником?","options":["Переместить его дальше назад по дороге, за пределы препятствия, чтобы обеспечить предупреждение","Оставить его на стандартных 100 футах и добавить четвёртый треугольник","Поставить его на капот транспортного средства, чтобы повысить его видимость","Убрать его и полагаться только на аварийную сигнализацию"],"explanation":"Руководство CDL штата Делавэр (раздел 2.5) гласит, что когда подъём или поворот закрывает обзор в пределах 500 футов, нужно переместить самый задний треугольник дальше назад за пределы препятствия, чтобы едущие следом водители получили предупреждение. Источник: Delaware CDL Manual, Sec. 2.5."},"71":{"q":"Согласно Разделу 21 Свода законов Делавэра, каково установленное законом ограничение скорости на двухполосной проезжей части, где не установлено другое ограничение?","options":["50 mph","55 mph","45 mph","60 mph"],"explanation":"Раздел 21 Свода законов Делавэра § 4169 устанавливает 50 mph на 2-полосных проезжих частях (и 55 mph на 4-полосных и разделённых проезжих частях), если не установлено иное. Источник: 21 Del. C. § 4169."},"72":{"q":"Согласно Разделу 21 Свода законов Делавэра, каково установленное законом ограничение скорости на четырёхполосной или разделённой проезжей части, где не установлено другое ограничение?","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"Раздел 21 Свода законов Делавэра § 4169 устанавливает 55 mph на 4-полосных и разделённых проезжих частях, если не установлено иное. Источник: 21 Del. C. § 4169."},"73":{"q":"Согласно Разделу 21 Свода законов Делавэра, каково ограничение скорости в деловом или жилом районе, если не установлено иное?","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"Раздел 21 Свода законов Делавэра § 4169 устанавливает 25 mph в деловых районах и 25 mph в жилых районах, если не установлено иное. Источник: 21 Del. C. § 4169."},"74":{"q":"На какой проезжей части Делавэра Департамент транспорта установил максимальное ограничение скорости 65 mph на участке между Red Lion Creek и рекой Appoquinimink?","options":["Трасса штата Делавэр № 1 (Delaware State Route 1)","Interstate 495","U.S. Route 13","Interstate 295"],"explanation":"Раздел 21 Свода законов Делавэра § 4169 предписывает DelDOT установить максимум 65 mph на участке State Route 1 между Red Lion Creek и рекой Appoquinimink (за исключением зоны пункта взимания платы). Источник: 21 Del. C. § 4169."},"75":{"q":"Согласно закону Делавэра об ограничении движения по полосам (§ 4114A), какие транспортные средства, как правило, могут двигаться только по крайней правой полосе на State Route 1 и Interstate 495?","options":["Транспортное средство с полной разрешённой массой более 26,000 фунтов","Транспортное средство с полной разрешённой массой более 10,000 фунтов","Любое транспортное средство, буксирующее прицеп любого размера","Транспортное средство с тремя или более осями независимо от массы"],"explanation":"Раздел 21 Свода законов Делавэра § 4114A ограничивает движение транспортных средств с полной разрешённой массой более 26,000 фунтов крайней правой полосой на скоростных участках / участках с ограниченным доступом SR 1 и I-495, с ограниченными исключениями. Источник: 21 Del. C. § 4114A."},"76":{"q":"Согласно § 4114A Делавэра, когда транспортное средство, подпадающее под ограничение по правой полосе, может законно использовать левую полосу на SR 1 или I-495?","options":["При обгоне и опережении другого транспортного средства, при въезде на проезжую часть или съезде с неё, либо когда этого требуют условия движения","Только с полуночи до 6:00 утра","Только когда установленное ограничение скорости составляет 35 mph или ниже","Никогда, ни при каких обстоятельствах"],"explanation":"Раздел 21 Свода законов Делавэра § 4114A разрешает тяжёлому транспортному средству использовать левую полосу для обгона, въезда на проезжую часть / съезда с неё, в экстренных случаях, при наличии препятствий, по условиям движения или для соблюдения иного закона. Источник: 21 Del. C. § 4114A."},"77":{"q":"Согласно закону Делавэра, транспортное средство, движущееся медленнее обычной скорости потока, должно двигаться где, за исключением случаев обгона или подготовки к левому повороту?","options":["По крайней правой полосе, доступной для движения, или как можно ближе к правому бордюру или краю проезжей части","По центральной полосе любой многополосной проезжей части","По той полосе, где меньше всего транспортных средств","По левой полосе, оставляя правую полосу свободной для въезжающего транспорта"],"explanation":"Раздел 21 Свода законов Делавэра § 4114 требует, чтобы транспортное средство, движущееся медленнее обычного потока, держалось крайней правой полосы или как можно ближе к правому бордюру / краю, за исключением случаев обгона или подготовки к левому повороту. Источник: 21 Del. C. § 4114."},"78":{"q":"Согласно руководству CDL штата Делавэр, нарушение на железнодорожно-автомобильном переезде во время управления коммерческим транспортным средством (CMV) приводит к дисквалификации CDL на срок не менее чем на сколько за первое нарушение?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Руководство CDL штата Делавэр (раздел 1.3.5) указывает, что нарушение на железнодорожно-автомобильном переезде влечёт дисквалификацию CDL на срок не менее 60 дней (первое), 120 дней (второе в течение 3 лет) и 1 год (третье в течение 3 лет). Источник: Delaware CDL Manual, Sec. 1.3.5."},"79":{"q":"Какое ведомство Делавэра выдаёт коммерческие водительские удостоверения (CDL)?","options":["Delaware Division of Motor Vehicles (DMV), входящее в состав DelDOT","Бюро коммерческих перевозчиков полиции штата Делавэр","Полевой офис Federal Motor Carrier Safety Administration","Офис госсекретаря штата Делавэр"],"explanation":"В Делавэре CDL выдаёт Delaware Division of Motor Vehicles (DMV), которое работает в составе Delaware Department of Transportation. FMCSA устанавливает федеральные стандарты, но не выдаёт удостоверение. Источник: Delaware DMV CDL pages; Title 21, Chapter 26 (Uniform Commercial Driver License Act)."},"80":{"q":"Как проводятся теоретические (письменные) тесты CDL в Делавэре?","options":["В порядке живой очереди в любом учреждении DMV, без предварительной записи","Только по предварительной записи в штаб-квартире в Дувре (Dover)","Онлайн из дома с удалённым наблюдателем","Только в одном утверждённом стороннем центре тестирования"],"explanation":"Delaware DMV заявляет, что все теоретические тесты CDL сдаются только в порядке живой очереди и могут быть пройдены в любом учреждении DMV. Требование о предварительной записи относится к практическому тесту (skills test), а не к теоретическому. Источник: Delaware DMV CDL webpage."},"81":{"q":"Как долго необходимо удерживать Commercial Learner Permit (CLP) Делавэра, прежде чем его обладатель сможет сдавать практический тест CDL?","options":["Минимум 14 дней после первоначальной выдачи","Минимум 30 дней после первоначальной выдачи","Минимум 10 дней после первоначальной выдачи","Минимум 7 дней после первоначальной выдачи"],"explanation":"Обладатель CLP не имеет права сдавать тест CDL по предрейсовому осмотру, базовому управлению или вождению на дороге, пока разрешение не удерживалось минимум 14 дней после первоначальной выдачи. Это федеральный 14-дневный период удержания, принятый Делавэром. Источник: Delaware DMV CDL webpage; 49 CFR 383.25 в редакции, принятой согласно Title 21 Ch. 26."},"82":{"q":"Как долго действителен Commercial Learner Permit (CLP) Делавэра?","options":["Один (1) год, и за это время он может быть продлён один раз","180 дней, без возможности продления","Два (2) года, с ежегодным продлением","Шесть (6) месяцев, с продлением дважды"],"explanation":"CLP Делавэра действителен в течение одного (1) года и не может быть выдан или продлён на срок, превышающий один год; он может быть продлён один раз в течение этого периода. Источник: Delaware DMV CDL webpage; Title 21 § 2608."},"83":{"q":"На какие три части делится практический тест CDL в Делавэре?","options":["Предрейсовый осмотр транспортного средства, базовые навыки управления и вождение по дороге","Письменный экзамен, проверка зрения и дорожный тест","Только сцепка, торможение и движение задним ходом","Теоретическое обучение, вождение за рулём и итоговый письменный экзамен"],"explanation":"Практический тест CDL состоит из трёх частей: тест предрейсового осмотра транспортного средства, тест базовых навыков управления и тест вождения по дороге. Делавэр модернизировал эти протоколы с 26 февраля 2025 года. Источник: Delaware DMV CDL webpage; 49 CFR 383.113."},"84":{"q":"Что должен пройти начинающий водитель, прежде чем сдавать практический тест CDL в Делавэре для категорий Class A, Class B, Passenger (P) или School Bus (S)?","options":["Федерально обязательное обучение начинающих водителей (ELDT) у зарегистрированного поставщика","30-дневную стажировку, зарегистрированную в DMV","Курс безопасного вождения, утверждённый полицией штата Делавэр","Только общий теоретический письменный тест"],"explanation":"С 7 февраля 2022 года ни один начинающий водитель не может сдавать практический тест CDL для категории Class A, Class B, endorsement P или endorsement S, не пройдя обязательное теоретическое обучение и обучение вождению (ELDT) у поставщика, указанного в реестре поставщиков обучения FMCSA (Training Provider Registry). Источник: Delaware DMV ELDT page; 49 CFR Part 380."},"85":{"q":"Каковы четыре категории самосертификации, которые обладатель CDL/CLP Делавэра может заявить?","options":["Interstate non-excepted, interstate excepted, intrastate non-excepted, intrastate excepted","Class A, Class B, Class C и Class D","Hazmat, пассажирские перевозки, цистерны и сдвоенные/строенные прицепы","По найму, частные, освобождённые и государственные"],"explanation":"Каждый обладатель CDL/CLP Делавэра должен самостоятельно сертифицироваться в одну из четырёх категорий: interstate non-excepted, interstate excepted, intrastate non-excepted или intrastate excepted. Источник: Delaware DMV Self-Certification Affidavit Category Guide; 49 CFR 383.71."},"86":{"q":"Какая категория самосертификации требует, чтобы водитель предоставил и хранил действующую медицинскую справку DOT (medical examiner's certificate) в Delaware DMV?","options":["Interstate non-excepted","Interstate excepted","Intrastate excepted","Ни одна категория не обязана её предоставлять"],"explanation":"Водитель, самостоятельно сертифицировавшийся как interstate non-excepted, обязан предоставить и хранить копию федеральной медицинской справки (medical examiner's certificate) в Delaware DMV. Категории excepted не обязаны предоставлять федеральную медицинскую справку. Источник: Delaware DMV Self-Certification Category Guide; 49 CFR 383.71."},"87":{"q":"Где соискатель CDL в Делавэре должен пройти медосмотр DOT, на основании которого выдаётся медицинская справка (medical examiner's certificate)?","options":["У медицинского эксперта, внесённого в FMCSA National Registry of Certified Medical Examiners","У любого лицензированного врача или мануального терапевта по выбору водителя","Только в клинике, утверждённой полицией штата Делавэр","У штатного медицинского персонала DMV"],"explanation":"Медицинская справка должна быть выдана медицинским экспертом, внесённым в FMCSA National Registry of Certified Medical Examiners. Делавэр принял это федеральное требование для всех обладателей CDL/CLP. Источник: Delaware DMV Medical Certification page; 49 CFR 390.103 / National Registry."},"88":{"q":"По какому графику истекает срок действия CDL Делавэра и наступает возможность его продления?","options":["В восьмую годовщину дня рождения обладателя, следующую за выдачей (каждые 8 лет)","Каждые 4 года в дату выдачи","Каждые 5 лет в дату выдачи","Каждые 2 года, в соответствии с медосмотром DOT"],"explanation":"Срок действия CDL Делавэра истекает и подлежит продлению в восьмую годовщину дня рождения соискателя, следующую за выдачей, что даёт фактический срок действия до восьми лет. Источник: Title 21 § 2611(f); Delaware DMV."},"89":{"q":"Когда раньше всего можно продлить CDL Делавэра до истечения его срока действия?","options":["В течение 30 дней до даты истечения срока","В течение 90 дней до даты истечения срока","В течение 6 месяцев до даты истечения срока","В течение 1 года до даты истечения срока"],"explanation":"Делавэр разрешает продлевать CDL только в течение 30 дней до даты истечения его срока действия. Источник: Delaware DMV CDL webpage."},"90":{"q":"Каков минимальный возраст для получения CDL Делавэра только для внутриштатного вождения (в пределах Делавэра)?","options":["18 лет","16 лет","21 год","19 лет"],"explanation":"Лицу должно быть не менее 18 лет, чтобы иметь CDL Делавэра для внутриштатной эксплуатации. Источник: Delaware DMV; Title 21 Ch. 26."},"91":{"q":"Каков минимальный возраст для управления коммерческим транспортным средством в межштатной торговле, перевозки опасных грузов или перевозки пассажиров по CDL Делавэра?","options":["21 год","18 лет","19 лет","23 года"],"explanation":"Водителю должно быть не менее 21 года, чтобы работать в межштатной торговле, перевозить опасные грузы, требующие табличек, или перевозить пассажиров. Источник: Delaware DMV; 49 CFR 383."},"92":{"q":"Какие документы соискатель в Делавэре должен предъявить, явившись на практический (дорожный) тест CDL?","options":["Действующее ученическое разрешение, действующее удостоверение сопровождающего водителя возрастом 21+, действующую регистрацию транспортного средства и действующую страховку","Только действующее ученическое разрешение и карточку социального страхования","Только паспорт и квитанцию об оплате теста","Свидетельство о рождении и два счёта за коммунальные услуги"],"explanation":"Для дорожного теста соискатель должен предъявить действующее ученическое разрешение, действующее водительское удостоверение сопровождающего водителя (21+), действующую карточку регистрации транспортного средства и действующую страховую карточку. Источник: Delaware DMV CDL webpage."},"93":{"q":"Какой результат требуется для прохождения общего теоретического письменного теста CDL в Делавэре?","options":["80% правильных ответов (40 из 50 вопросов)","70% правильных ответов (35 из 50 вопросов)","90% правильных ответов (45 из 50 вопросов)","100% правильных ответов (все 50 вопросов)"],"explanation":"Общий теоретический тест CDL Делавэра состоит из 50 вопросов и требует результата 80% (40 из 50) или выше для прохождения. Источник: Delaware DMV / используемая в Делавэре система тестирования CDL на основе AAMVA."},"94":{"q":"Какой документ является основным справочным материалом для самостоятельной подготовки, предоставляемым Делавэром для подготовки к теоретическому и практическому тестам CDL?","options":["Delaware CDL Manual (Commercial Driver License Manual), издаваемое DMV","Свод законов Делавэра, Title 21, аннотированное издание","FMCSA Pocket Guide to Large Truck and Bus Statistics","Учебник по автошколе штата (Driver's Education textbook)"],"explanation":"DMV Делавэра издаёт Delaware CDL Manual (на основе модели AAMVA), которое соискатели должны получить и изучить перед тестированием. Источник: Delaware DMV CDL Manual."},"95":{"q":"Как назначается дорожная часть практического теста CDL в Делавэре и как обеспечивается поддержка по части предрейсового осмотра?","options":["Практический тест проводится по предварительной записи, и DMV предоставляет соискателям контрольный список предрейсового осмотра в качестве вспомогательного материала","Все три части практического теста проводятся в порядке живой очереди, и контрольный список не предоставляется","Дорожный тест проводится онлайн; предрейсовый осмотр отменяется для выпускников ELDT","Запись осуществляется только через работодателя соискателя"],"explanation":"Практические тесты CDL Делавэра проводятся только по предварительной записи, и модернизированная программа предоставляет соискателям контрольный список для теста предрейсового осмотра транспортного средства в качестве вспомогательного материала. Источник: Delaware DMV CDL webpage (модернизированный практический тест, действует с 26 февраля 2025 года)."},"96":{"q":"Что обычно происходит с CDL Делавэра, если его обладатель, самостоятельно сертифицировавшийся как interstate non-excepted, не поддерживает действующую медицинскую справку (medical examiner's certificate) в DMV?","options":["Коммерческое право (CDL) понижается, так что лицо больше не может управлять коммерческими транспортными средствами","CDL аннулируется навсегда и не может быть восстановлено","Ничего, поскольку медицинская справка является лишь учётным документом работодателя","Удостоверение автоматически преобразуется в CDL категории interstate excepted"],"explanation":"Если требуемый (non-excepted) водитель допускает истечение срока действия медицинской справки или не предоставляет её, штат обязан понизить CDL, изымая коммерческие права на вождение до тех пор, пока действующая справка не будет находиться в DMV. Источник: Delaware DMV Self-Certification FAQ; 49 CFR 383.73."},"97":{"q":"Для водителя Делавэра категории interstate non-excepted, насколько свежим, как правило, должен быть медосмотр DOT, на основании которого выдаётся медицинская справка?","options":["Датированным в пределах предыдущих 24 месяцев (с максимальным сроком сертификации до 2 лет)","Датированным в пределах предыдущих 6 месяцев","Датированным только в пределах предыдущих 12 месяцев","Датированным в пределах предыдущих 5 лет"],"explanation":"Медосмотр DOT должен соответствовать 49 CFR 391.41-391.49 и может сертифицировать водителя на срок до 24 месяцев (медицинский эксперт может сертифицировать на меньший срок при определённых состояниях). Делавэр требует соблюдения этого федерального стандарта. Источник: Delaware DMV Medical Certification page; 49 CFR 391.43."}},"tr":{"0":{"q":"Delaware karayollarında, yük dahil olmak üzere bir aracın izin verilen maksimum yüksekliği nedir?","options":["13 feet 6 inches","14 feet","13 feet","12 feet 6 inches"],"explanation":"Delaware yasaları, hem genel yollarda hem de Eyaletlerarası (Interstate) sistemde bir aracın ve yükünün maksimum yüksekliğini 13 feet 6 inches olarak belirler. Kaynak: Delaware Code Title 21, Ch. 45, sections 4502(b) ve 4503(b)."},"1":{"q":"Güvenlik ekipmanları hariç, Delaware'de çoğu ticari araç için izin verilen maksimum toplam dış genişlik nedir?","options":["102 inches","96 inches","108 inches","120 inches"],"explanation":"Delaware, güvenlik ekipmanları hariç olmak üzere toplam dış araç genişliğini 102 inches (8 feet 6 inches) ile sınırlar. Kaynak: Delaware Code Title 21, sections 4502 ve 4503; DelDOT OSOW yasal limitleri."},"2":{"q":"Delaware'de çalışan bir yarı römork (çekici hariç) için izin verilen maksimum uzunluk nedir?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"Bir yarı römork, yük dahil olmak üzere ve çekici hariç, uzunlukta 53 feet'i aşamaz. Kaynak: Delaware Code Title 21, Ch. 45, section 4503(b)."},"3":{"q":"Delaware'de tipik bir beş veya daha fazla akslı kombinasyon için maksimum brüt araç ağırlığı nedir?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"Delaware, beş veya daha fazla akslı bir araç kombinasyonunun brüt ağırlığını, federal limitle uyumlu olarak 80,000 pounds ile sınırlar. Kaynak: Delaware Code Title 21, Ch. 45, sections 4502(c) ve 4503(c)."},"4":{"q":"Delaware'deki Eyaletlerarası (Interstate) sistemde, tek bir aks üzerine izin verilen maksimum ağırlık nedir?","options":["20,000 pounds","22,400 pounds","18,000 pounds","24,000 pounds"],"explanation":"Eyaletlerarası karayollarında Delaware, 20,000 pounds olan federal tek aks limitini takip eder. Kaynak: Delaware Code Title 21, Ch. 45, section 4503(c)."},"5":{"q":"Delaware'deki Eyaletlerarası (Interstate) sistemde, bir çift aks (tandem) üzerine izin verilen maksimum ağırlık nedir?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"explanation":"Eyaletlerarası karayollarında çift aks (tandem) limiti, federal standartla eşleşen 34,000 pounds'tur. Kaynak: Delaware Code Title 21, Ch. 45, section 4503(c)."},"6":{"q":"Bir Delaware DOT aşırı boyut/aşırı ağırlık taşıma izni ne zaman gereklidir?","options":["Bir araç veya yük, Delaware Code'un Title 21, Chapter 45 bölümünde belirtilen boyut veya ağırlık limitlerini aştığında","Yalnızca aks ağırlıklarından bağımsız olarak brüt ağırlık 80,000 pounds'u aştığında","Yalnızca 12 feet'ten geniş yükler için","Yalnızca Interstate 95 üzerinde seyahat edildiğinde"],"explanation":"Bir araç, kombinasyon veya kendinden tahrikli ekipman, Delaware Code'un Title 21, Chapter 45 bölümünde belirtilen boyutsal ve/veya ağırlık limitlerini aştığında, brüt ağırlık yasal olsa bile tek bir aks aşırı ağırlıkta olduğunda dahil olmak üzere bir izin gereklidir. Kaynak: DelDOT OSOW izin SSS; Delaware Code Title 21, section 4504."},"7":{"q":"Delaware aşırı boyut/aşırı ağırlık taşıma izinleri nasıl alınır?","options":["Taşıma İzni Ofisi (Hauling Permit Office) tarafından yönetilen DelDOT çevrimiçi Aşırı Boyut/Aşırı Ağırlık (OSOW) izin sistemi aracılığıyla","Delaware DMV CDL bölümüne kağıt bir form posta ile gönderilerek","Herhangi bir DMV araç hizmetleri gişesinden satın alınarak","Araç tescili ile birlikte otomatik olarak verilerek"],"explanation":"Aşırı boyut/aşırı ağırlık izinleri, DMV tarafından değil, Taşıma İzni Ofisi (Hauling Permit Office) tarafından yönetilen çevrimiçi OSOW izin sistemi aracılığıyla DelDOT tarafından verilir. Kaynak: DelDOT OSOW izin sistemi (deldot.gov/osow)."},"8":{"q":"Standart tek seferlik bir Delaware aşırı boyut/aşırı ağırlık izni için minimum ücret nedir?","options":["$30.00","$15.00","$50.00","$10.00"],"explanation":"Tek seferlik bir taşıma izni için minimum ücret $30.00'dır (Superload için $60.00). Kaynak: DelDOT OSOW izin SSS; Delaware Administrative Code 2405 izin politikası el kitabı."},"9":{"q":"Aşırı ağırlık taşıyan bir Delaware izni için ek ağırlık ücreti nasıl hesaplanır?","options":["Yasal ağırlık limitinin üzerindeki her 8,000 pounds (veya bunun bir kısmı) için $10.00","Yasal ağırlık limitinin üzerindeki her 5,000 pounds için $25.00","Yasal ağırlık limitinin üzerindeki her 1,000 pounds için $5.00","Aşırı ağırlık miktarından bağımsız olarak sabit $100.00"],"explanation":"Delaware, yasal ağırlık limitinin üzerindeki her 8,000 pounds veya bunun bir kısmı için $10.00 tutarında bir ağırlık ücreti ekler. Kaynak: DelDOT OSOW izin SSS; Delaware Administrative Code 2405."},"10":{"q":"Standart bir Delaware tek seferlik aşırı boyut/aşırı ağırlık taşıma izni ne kadar süreyle geçerlidir?","options":["5 gün (yürürlük tarihinden sona erme tarihine kadar)","24 saat","30 gün","10 gün"],"explanation":"Standart bir taşıma izni, yürürlük tarihinden sona erme tarihine kadar beş gün boyunca geçerlidir. Kaynak: DelDOT OSOW izin SSS; Delaware Administrative Code 2405."},"11":{"q":"İzin aksini belirtmedikçe, izinli bir aşırı boyutlu yük genellikle hangi saatlerde Delaware karayollarında seyahat edebilir?","options":["Gün doğumundan gün batımına, Pazartesi'den Pazar'a","Yalnızca Pazartesi'den Cuma'ya mesai saatleri içinde","Yalnızca akşam 9 ile sabah 5 arasında","Herhangi bir zamanda, günde 24 saat, kısıtlama olmaksızın"],"explanation":"İzinli yükler, iznin özel hükümleri aksini belirtmedikçe, gün doğumundan gün batımına, Pazartesi'den Pazar'a kadar hareket etmeye yetkilidir. Kaynak: DelDOT OSOW izin SSS."},"12":{"q":"Delaware, bir grup ardışık aks üzerindeki maksimum brüt ağırlığı belirlemek için hangi formülü uygular?","options":["Federal Köprü Formülü, W = 500[(LN / (N-1)) + 12N + 36]","Lastik genişliğinin her inch'i için sabit 1,000 pounds","Üreticinin GVWR'sinin 1.5 ile çarpımı","Aralık faktörü olmaksızın her aks için basitçe 20,000 pounds"],"explanation":"Delaware, W'nin izin verilen ağırlık, L'nin grubun en uçtaki aksları arasındaki mesafe ve N'nin aks sayısı olduğu federal Köprü Formülü'nü, W = 500[(LN / (N-1)) + 12N + 36], benimser. Kaynak: Delaware Code Title 21, Ch. 45, section 4503(c)."},"13":{"q":"Delaware'nin köprü ağırlığı kuralına göre, iki ardışık çift aks (tandem) seti, ilk setin ilk aksı ile son setin son aksı arasındaki mesafe en az şu kadar olması koşuluyla her biri 34,000 pounds taşıyabilir:","options":["36 feet","30 feet","40 feet","24 feet"],"explanation":"Köprü formülüne yönelik bir istisna, iki ardışık çift aks (tandem) setinin, bu setlerin ilk ve son aksı arasındaki toplam mesafe 36 feet veya daha fazla olduğunda her biri 34,000 pounds taşımasına izin verir. Kaynak: Delaware Code Title 21, Ch. 45, section 4503(c)."},"14":{"q":"Delaware'de, Eyaletlerarası (Interstate) veya federal yardımlı birincil (federal-aid primary) sistemin parçası OLMAYAN yollarda, maksimum tek aks ağırlığı nedir?","options":["22,400 pounds","20,000 pounds","18,000 pounds","25,000 pounds"],"explanation":"Eyaletlerarası olmayan eyalet yollarında Delaware, Eyaletlerarası'ndaki 20,000 pounds ile karşılaştırıldığında, daha yüksek bir tek aks ağırlığı olan 22,400 pounds'a izin verir. Kaynak: Delaware Code Title 21, Ch. 45, section 4502(c)."},"15":{"q":"Delaware, eyalet içi belirli tarım ürünlerini veya tahılı taşıyan kamyonlar için bir ağırlık muafiyeti tanır. Bu tür araçlar hangi brüt ağırlığa kadar çalışabilir?","options":["90,000 pounds","80,000 pounds","100,000 pounds","85,000 pounds"],"explanation":"Delaware, eyalet içi meyve, sebze veya emtia tahılları taşıyan kamyonların 90,000 pounds'a (veya üreticinin brüt kombine ağırlık derecesine, hangisi daha düşükse) kadar ulaşmasına izin verir. Kaynak: Delaware Code Title 21, Ch. 45, section 4502(c)."},"16":{"q":"Delaware'nin canlı kümes hayvanı taşıma ağırlığı hükmü, yağış ve kuş boyutundaki değişiklikleri hesaba katmak için bir tolerans içerir. Bu yüzde sapma nedir?","options":["3%","5%","10%","1%"],"explanation":"Delaware içinde canlı kümes hayvanı taşıyan kamyonlar, yağış ve kuş boyutundan kaynaklanan ağırlık farklılıkları için %3'lük bir sapma ile 90,000 pounds'a kadar çalışabilir. Kaynak: Delaware Code Title 21, Ch. 45, section 4502(c)."},"17":{"q":"Delaware'de, Eyaletlerarası (Interstate) ve federal yardımlı birincil (federal-aid primary) sistem dışındaki yollarda, tek bir aracın (bir kombinasyon değil) maksimum uzunluğu nedir?","options":["40 feet","45 feet","53 feet","35 feet"],"explanation":"Eyaletlerarası olmayan yollarda tek bir araç 40 feet'i aşamaz ve bir araç kombinasyonu 60 feet'i aşamaz. Kaynak: Delaware Code Title 21, Ch. 45, section 4502(b)."},"18":{"q":"Delaware'de bir çekici-yarı römork-römork (ikiz) kombinasyonunda, her römork veya yarı römorkun maksimum uzunluğu nedir?","options":["29 feet","28 feet","33 feet","31 feet"],"explanation":"Bir çekici-yarı römork-römork kombinasyonundaki her römork veya yarı römork, çekici hariç olmak üzere 29 feet ile sınırlıdır. Kaynak: Delaware Code Title 21, Ch. 45, section 4503(b)."},"19":{"q":"Bir Delaware aşırı boyut/aşırı ağırlık taşıması, daha yüksek bir minimum izin ücreti taşıyan bir 'Superload' olarak hangi noktada nitelendirilir?","options":["Uzunluk 120 feet'te, genişlik 15 feet'te, yükseklik 15 feet'te veya brüt ağırlık 120,000 pounds'un üzerinde","Brüt ağırlığı 90,000 pounds'un üzerindeki herhangi bir yük","10 feet'ten geniş herhangi bir yük","75 feet'in üzerinde uzunluk veya 100,000 pounds'un üzerinde ağırlık"],"explanation":"Bir taşıma, uzunluk 120 feet'e, genişlik 15 feet'e, yükseklik 15 feet'e ulaştığında veya brüt ağırlık 120,000 pounds'u aştığında bir Superload olarak sınıflandırılır; minimum Superload izin ücreti $60.00'dır. Kaynak: DelDOT OSOW izin SSS."},"20":{"q":"Delaware'de, çekilen ünitenin GVWR'si 10,000 pounds'u aşması koşuluyla, 26,001 pounds veya daha fazla Brüt Araç Ağırlık Derecesi (GVWR) olan bir araç kombinasyonunu kullanmak için hangi sınıf CDL gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Delaware Ticari Sürücü El Kitabı (Sürüm 4.0, \"Types of CDL\"), çekilen ünite(ler)in GVWR'si 10,000 pounds'u aşması koşuluyla, 26,001 pounds veya daha fazla GVWR'ye sahip herhangi bir araç kombinasyonu için bir Class A CDL gerektiğini belirtir."},"21":{"q":"Delaware kurallarına göre, 26,001 pounds veya daha fazla GVWR'ye sahip ve 10,000 pounds'un üzerinde bir ünite çekmeyen tek bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class M"],"explanation":"Delaware Ticari Sürücü El Kitabı, Class B'yi 26,001 pounds veya daha fazla GVWR'ye sahip herhangi bir tek araç ya da 10,000 pounds GVWR'yi aşmayan bir aracı çeken böyle bir araç olarak tanımlar."},"22":{"q":"Delaware'de, GVWR'si 26,001 pounds'un altında olan, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakartlı tehlikeli madde taşıyan bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Hiçbir CDL gerekmez"],"explanation":"Delaware Ticari Sürücü El Kitabı'na göre, GVWR'si 26,001 pounds'tan az olan, sürücü dahil 16 veya daha fazla kişiyi taşımak için tasarlanmış ya da plakart gerektiren tehlikeli madde taşımak için kullanılan bir araç için bir Class C CDL gereklidir."},"23":{"q":"Bir Delaware CDL'de, hangi onay kodu bir tank aracının kullanımına yetki verir?","options":["Code N","Code T","Code H","Code P"],"explanation":"Delaware Ticari Sürücü El Kitabı, Tanker onayını N kodu olarak listeler. T onayı Doubles/Triples (İkili/Üçlü), H Tehlikeli Maddeler (HazMat) ve P Yolcu içindir."},"24":{"q":"İkili veya üçlü römork çekmek için hangi Delaware CDL onayı gereklidir?","options":["Onay T","Onay N","Onay X","Onay P"],"explanation":"Delaware Ticari Sürücü El Kitabı, Doubles/Triples (İkili/Üçlü) onayını T kodu olarak listeler ve birden fazla römork çekmeyle ilgili sorunlar üzerine özel bir bilgi sınavını geçmeyi gerektirir."},"25":{"q":"Delaware Ticari Sürücü El Kitabı'na göre, bir Tank Aracı (N) onayı, araç bireysel derecelendirilmiş kapasitesi 119 gallons'tan fazla olan bir tankta sıvı veya gaz taşımak için tasarlandığında ve toplam derecelendirilmiş kapasitesi en az kaç gallons olduğunda gereklidir?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"Delaware Ticari Sürücü El Kitabı, Tank Aracı (N) onayının, bireysel derecelendirilmiş kapasitesi 119 gallons'tan fazla ve toplam derecelendirilmiş kapasitesi 1,000 gallons veya daha fazla olan tanklara uygulandığını belirtir."},"26":{"q":"Delaware'de, eyalet içi (yalnızca Delaware içinde) sürüş için bir CDL almak için minimum yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Delaware Ticari Sürücü El Kitabı'nın Temel CDL Gereksinimleri, bir başvuranın eyalet içi sürüş yapabilmek için 1 yıl sürüş deneyimine sahip ve 18 yaşında olması gerektiğini belirtir."},"27":{"q":"Delaware'nin temel CDL gereksinimlerine göre, eyaletlerarası ticarette sürüş yapmak veya tehlikeli madde taşımak için gereken minimum yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Delaware Ticari Sürücü El Kitabı, eyaletlerarası ticarette sürüş yapmak veya tehlikeli madde taşımak için bir başvuranın en az 1 yıl sürüş deneyimine sahip ve 21 yaşında olmasını gerektirir."},"28":{"q":"Bilgi sınavlarını geçtikten sonra, bir Delaware Ticari Öğrenci Ehliyeti (CLP) sahibinin CDL beceri sınavına girmesine izin verilmeden önce CLP'yi ne kadar süre elinde tutması gerekir?","options":["En az 14 tam gün","En az 10 tam gün","En az 7 tam gün","En az 30 tam gün"],"explanation":"Delaware Ticari Sürücü El Kitabı, federal 49 CFR 383 gereksinimiyle eşleşecek şekilde, CDL beceri sınavını yapabilmeniz için CLP'nizi en az 14 tam gün elinizde tutmanız gerektiğini belirtir."},"29":{"q":"Bir Delaware Ticari Öğrenci Ehliyeti (CLP) ile sürüş yaparken, sahibine kim eşlik etmelidir?","options":["18 yaş veya üzeri herhangi bir ehliyetli sürücü","Aynı tip CMV'de yetkili, ehliyetli bir CDL sürücüsü","Yalnızca sertifikalı bir DMV sınav görevlisi","Hiç kimse; CLP tek başına sürüşe izin verir"],"explanation":"Delaware Ticari Sürücü El Kitabı, bir CLP'nin başka bir ehliyetli CDL sürücüsü eşliğinde bir CMV kullanmanıza izin verdiğini ve yalnızca, aynı tip CMV'de yetkili bir CDL sürücüsü ile sınava girdiğiniz araç tipini kullanabileceğinizi belirtir."},"30":{"q":"Tehlikeli maddeler (H) onayı olan bir Delaware CDL verilmeden önce, bir başvuranın ilk olarak neyi tamamlaması gerekir?","options":["DMV'de bir savunmacı sürüş kursu","Beceri sınavından sonra 30 günlük bir bekleme süresi","Parmak izi alımı dahil bir TSA güvenlik tehdidi değerlendirmesi","Plakartlı bir araçta ayrı bir yol sınavı"],"explanation":"Delaware Ticari Sürücü El Kitabı, başvuran ilk olarak TSA güvenlik tehdidi değerlendirmesinden (parmak izi alımı ve vatandaşlık/yasal varlık doğrulaması dahil) geçmedikçe ve TSA onayı almadıkça, hazmat onayı olan hiçbir CDL'nin verilemeyeceğini belirtir."},"31":{"q":"Delaware'de uygulanan federal Giriş Seviyesi Sürücü Eğitimi (ELDT) kuralına göre, eğitim hangi sicile kayıtlı bir okul tarafından verilmelidir?","options":["Delaware DMV Onaylı Okullar listesi","AAMVA Eğitmen Dizini","FMCSA Eğitim Sağlayıcı Sicili (TPR)","TSA Sertifikalı Eğitmen Sicili"],"explanation":"Delaware DMV'nin ELDT sayfası, başvuran CDL beceri sınavına girebilmeden önce giriş seviyesi sürücü eğitiminin, FMCSA Eğitim Sağlayıcı Sicili'nde (tpr.fmcsa.dot.gov) listelenen FMCSA kayıtlı bir sağlayıcı aracılığıyla tamamlanması gerektiğini belirtir."},"32":{"q":"Aşağıdakilerden hangisi için Delaware, beceri/bilgi sınavına girilebilmeden önce ELDT (Giriş Seviyesi Sürücü Eğitimi) gerektirir?","options":["Bir Tanker (N) onayı eklemek","Bir Doubles/Triples (T) onayı eklemek","Mevcut bir CDL'yi yenilemek","İlk kez bir Class A veya Class B CDL almak"],"explanation":"Delaware DMV'nin ELDT sayfasına göre (7 Şubat 2022 itibarıyla yürürlükte), ELDT ilk kez Class A veya B başvuranları, daha yüksek bir sınıfa yükseltmeler ve S, P ve H onayları için gereklidir. N veya T onayları ya da yenilemeler için gerekli değildir."},"33":{"q":"Delaware, CDL sahiplerinin sürüş tiplerini kendi kendilerine beyan etmelerini (self-certify) gerektirir. Kaç tane kendi kendine beyan kategorisi vardır?","options":["İki","Üç","Dört","Beş"],"explanation":"Delaware Ticari Sürücü El Kitabı, CDL sahiplerinin bir sürüş durumunu non-excepted interstate (muafiyetsiz eyaletlerarası), non-excepted intrastate (muafiyetsiz eyalet içi), excepted interstate (muaf eyaletlerarası) veya excepted intrastate (muaf eyalet içi) olarak kendi kendilerine beyan etmeleri gerektiğini belirtir — dört kategori."},"34":{"q":"Eyaletlerarası ticarette bir CMV kullanan ve federal fiziksel yeterlilik kurallarına tabi olan bir Delaware CDL başvuranı, hangi tıbbi kendi kendine beyan kategorisi olarak beyanda bulunur?","options":["Non-excepted interstate (muafiyetsiz eyaletlerarası)","Excepted interstate (muaf eyaletlerarası)","Non-excepted intrastate (muafiyetsiz eyalet içi)","Excepted intrastate (muaf eyalet içi)"],"explanation":"Delaware Ticari Sürücü El Kitabı, eyaletlerarası ticarette CMV kullanan ve federal tıbbi sertifika gereksinimini karşılaması gereken CDL sahiplerinin non-excepted interstate commerce (muafiyetsiz eyaletlerarası ticaret) sürücüleri olduğunu açıklar."},"35":{"q":"Bir Delaware CLP'si bir Yolcu (P) onayı ile verildiğinde, ayrıca hangi kısıtlamayı taşımalıdır?","options":["Bir 'K' Yalnızca Eyalet İçi (Intrastate Only) kısıtlaması","Bir 'L' Hava freni yok (No air brake) kısıtlaması","Bir 'P' Bir CMV otobüsünde yolcu yok (No passengers in a CMV bus) kısıtlaması","Bir 'E' Manuel şanzıman yok (No manual transmission) kısıtlaması"],"explanation":"Delaware Ticari Sürücü El Kitabı, bir CLP bir Yolcu (P) veya Okul Otobüsü (S) onayı ile verilirse, ayrıca bir 'P' – Bir CMV otobüsünde yolcu yok (No passengers in a CMV bus) kısıtlamasını da içermesi gerektiğini (yalnızca belirtilen personelin araçta bulunmasına izin vererek) belirtir."},"36":{"q":"Bir Delaware CLP'si bir Tanker (N) onayı ile verilirse, üzerine hangi ek kısıtlama konur?","options":["'X' – Bir CMV tank aracında yük yok (No cargo in a CMV tank vehicle)","'Z' – Tam hava frenli CMV yok (No full air brake equipped CMV)","'V' – Tıbbi muafiyet (Medical variance)","'O' – Çekici-römork CMV yok (No tractor-trailer CMV)"],"explanation":"Delaware Ticari Sürücü El Kitabı, bir Tanker (N) onayı ile verilen bir CLP'nin ayrıca bir 'X' – Bir CMV tank aracında yük yok (No cargo in a CMV tank vehicle) kısıtlamasını da içermesi gerektiğini, yani sahibinin yalnızca boş ve temizlenmiş bir tank aracını kullanabileceğini belirtir."},"37":{"q":"Delaware DMV, bir ehliyet başvurusunda bulunurken bir başvuranın Delaware ikametgahına ilişkin hangi belgeyi sunmasını gerektirir?","options":["Bir Delaware ikametgah kanıtı","Üç Delaware ikametgah kanıtı","Yalnızca noter onaylı bir ikametgah beyannamesi","İki Delaware ikametgah kanıtı"],"explanation":"Delaware DMV, başvuranların kimlik kanıtı (bir birincil ve bir ikincil belge), uygunsa bir Sosyal Güvenlik numarası ve iki Delaware ikametgah kanıtı sunmasını gerektirir; ABD vatandaşı olmayanlar ayrıca yasal varlık kanıtı göstermelidir (Delaware DMV Sürücü Ehliyeti/Kimlik belge gereksinimleri)."},"38":{"q":"Delaware kurallarına göre, bir okul otobüsü kullanmak isteyen bir kişiden ne istenir?","options":["Yalnızca onaysız bir Class C CDL","Hem bir Yolcu (P) hem de bir Okul Otobüsü (S) onayı içeren bir CDL, artı Eğitim Bakanlığı (Department of Education) gereksinimleri","Okul otobüsü çıkartması olan standart bir Class D ehliyeti","Bir Tanker (N) onayı ve bir TSA geçmiş kontrolü"],"explanation":"Delaware Ticari Sürücü El Kitabı, tüm Delaware okul otobüsü sürücülerinin bir CDL'ye sahip olması ve ek Delaware Eğitim Bakanlığı (Department of Education) eğitim ve tıbbi gereksinimlerini karşılaması gerektiğini belirtir; DMV daha sonra P ve S onaylarını içeren bir CDL verir (araç sınıfına bağlı olarak bir M veya N kısıtlamasıyla)."},"39":{"q":"Delaware, federal CDL muafiyet hükümleri kapsamında bir CMV kullanan hangi sürücü grubu için özel bir CDL dışı belge sunar?","options":["Uzun mesafe eyaletlerarası kamyoncular","Hazmat tanker operatörleri","Charter otobüs sürücüleri","Çiftçiler ve itfaiyeciler"],"explanation":"Delaware Ticari Sürücü El Kitabı, Delaware'nin CDL muafiyet hükümleri kapsamında CMV kullanan çiftçileri ve itfaiyecileri tanımlamak için özel bir CDL dışı belgeye sahip olduğunu belirtir; bu CDL dışı belge eyaletlerarası ticarette veya ücretli (for-hire) durumlarda kullanılamaz."},"40":{"q":"Delaware'de, bir kişinin yasal olarak bir ticari motorlu araç (CMV) kullanabileceği maksimum kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"explanation":"Delaware, özel araçlar için olan 0.08 limitinin yarısı olan 0.04 percent veya daha fazla BAC ile bir CMV kullanmayı yasa dışı kılar. Kaynak: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"41":{"q":"Delaware'nin örtülü rıza (implied-consent) yasası uyarınca, bir kişi eyalette bir ticari motorlu araç kullandığında, neye rıza göstermiş sayılır?","options":["Aracın yükünün aranmasına","Alkol konsantrasyonu testine","Bir tıbbi uygunluk muayenesine","İstihdam kayıtlarının açıklanmasına"],"explanation":"Delaware'de bir CMV kullanarak, bir sürücü alkol (kimyasal) testine rıza göstermiş sayılır. Kaynak: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614 (CMV sürücüleri için örtülü rıza)."},"42":{"q":"Tehlikeli madde taşımıyorken, 0.04 veya daha yüksek bir BAC ile bir CMV kullanmak gibi İLK büyük suç için bir Delaware CDL sahibi ne kadar süreyle ehliyetten men edilir?","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"İlk büyük ihlal, Delaware'de 1 yıllık bir CDL men cezasıyla sonuçlanır. Kaynak: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612 (eyalet tarafından uygulanan federal standart 49 CFR 383.51)."},"43":{"q":"Delaware'de, ilk büyük suç için men cezası, suç sürücü ne yapan bir CMV kullanırken işlendiğinde üç yıla çıkar?","options":["Tehlikeli maddeler için plakartlı","Ücretli yolcu taşıyan","Bir ikili römork çeken","Eyalet sınırlarını geçen"],"explanation":"Tehlikeli maddeler için plakartlı bir CMV kullanılırken işlenen ilk büyük suç, men cezasını 1 yıldan 3 yıla yükseltir. Kaynak: Delaware CDL Manual Section 1.3.2; 49 CFR 383.51."},"44":{"q":"İKİNCİ büyük suç (örneğin, alkollü araç kullanmaktan ikinci bir mahkumiyet) için Delaware CDL men cezası süresi nedir?","options":["3 yıl","10 yıl","Ömür boyu","5 yıl"],"explanation":"Herhangi bir araçta ikinci bir büyük ihlal, Delaware'de ömür boyu CDL men cezasıyla sonuçlanır. Kaynak: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612; 49 CFR 383.51."},"45":{"q":"Delaware CDL kurallarına göre, bir CMV kullanırken gerekli bir alkol/kimyasal testi vermeyi reddetmek ne tür bir ihlal olarak değerlendirilir?","options":["Ciddi bir trafik ihlali","Büyük bir suç","Bir hizmet dışı (out-of-service) ihlali","Bildirilemez bir kabahat"],"explanation":"Kandaki alkol testinden geçmeyi reddetmek, ilk suç için en az 1 yıllık bir men cezası taşıyan büyük suçlar arasında listelenir. Kaynak: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"46":{"q":"Delaware'nin CMV sürücüleri için örtülü rıza uyarısı uyarınca, alkol testini reddetmek, men cezasına ek olarak ne kadar süreyle derhal hizmet dışı bırakılmayla sonuçlanır?","options":["8 saat","12 saat","24 saat","48 saat"],"explanation":"Delaware yasaları, görevlinin sürücüyü bir reddin derhal 24 saat boyunca hizmet dışı bırakılma ve en az 1 yıl men edilme ile sonuçlanacağı konusunda uyarmasını gerektirir. Kaynak: 21 Del. C. Section 2614."},"47":{"q":"Bir Delaware CMV sürücüsünün 0.02 BAC (0.04'ün altında ölçülebilir bir miktar alkol) ile olduğu tespit ediliyor. Gerekli sonuç nedir?","options":["60 günlük bir CDL men cezası","24 saat boyunca hizmet dışı bırakılma","1 yıllık bir CDL men cezası","Ömür boyu CDL men cezası"],"explanation":"0.04'ün altındaki herhangi bir saptanabilir miktar alkol (0.02 ile 0.04'ün altında ölçülebilir bir miktar), sürücünün 24 saat boyunca hizmet dışı bırakılmasını gerektirir. Kaynak: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"48":{"q":"Aşağıdakilerden hangisi Delaware CDL kurallarına göre CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["0.04 BAC ile bir CMV kullanmak","Limitin 15 mph veya daha fazla üzerinde aşırı hız yapmak","Bir kaza yerini terk etmek","Bir hizmet dışı (out-of-service) emrini ihlal etmek"],"explanation":"Aşırı hız (belirtilen limitin 15 mph veya daha fazla üzerinde) ciddi bir trafik ihlalidir. Listelenen diğer maddeler büyük suçlar veya hizmet dışı ihlallerdir. Kaynak: Delaware CDL Manual Section 1.3.3."},"49":{"q":"Delaware'de, üç yıllık bir süre içinde bir CMV'de İKİ ciddi trafik ihlalinden mahkum olmak için bir CDL ne kadar süreyle men edilir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"Herhangi bir üç yıllık süre içinde iki ciddi trafik ihlali, 60 günlük bir CDL men cezasıyla sonuçlanır. Kaynak: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51."},"50":{"q":"Üç yıllık bir süre içinde bir CMV'de ÜÇ veya daha fazla ciddi trafik ihlalinden mahkum olmak için Delaware CDL men cezası süresi nedir?","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"Herhangi bir üç yıllık süre içinde üç veya daha fazla ciddi trafik ihlali, 120 günlük bir CDL men cezasıyla sonuçlanır. Kaynak: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51."},"51":{"q":"Bunlardan hangisi Delaware CDL kurallarına göre büyük bir suç değil, ciddi bir trafik ihlalidir?","options":["Bir aracı çok yakından takip etmek","Bir suç işlemek için bir CMV kullanmak","İhmalkar CMV kullanımı yoluyla bir ölüme neden olmak","Kontrollü bir maddenin etkisi altında bir CMV kullanmak"],"explanation":"Bir aracı çok yakından takip etmek ciddi bir trafik ihlalidir. Diğer üçü büyük suçlardır. Kaynak: Delaware CDL Manual Section 1.3.3 (ciddi) ve Section 1.3.2 (büyük)."},"52":{"q":"Bir CMV kullanırken mesaj atmak veya elde tutulan bir cep telefonu kullanmak, Delaware CDL kurallarına göre hangi tür ihlal olarak değerlendirilir?","options":["Büyük bir suç","Ciddi bir trafik ihlali","Bir hizmet dışı (out-of-service) emir ihlali","Bir demiryolu geçidi ihlali"],"explanation":"Bir CMV kullanırken mesaj atmak veya elde tutulan bir telefon kullanmak ciddi bir trafik ihlalidir ve 60 günlük/120 günlük men cezası eşiklerine doğru sayılır. Kaynak: Delaware CDL Manual Section 1.3.3 ve mesajlaşma/telefon bölümü; 49 CFR 383.51."},"53":{"q":"Delaware/federal CDL kurallarına göre, bir CMV kullanırken elde tutulan bir cep telefonu kullanmaktan kaç mahkumiyetten sonra (3 yıl içinde) bir CDL 60 gün men edilir?","options":["Bir mahkumiyet","İki veya daha fazla mahkumiyet","Dört mahkumiyet","Beş mahkumiyet"],"explanation":"Bir CMV kullanırken 3 yıl içinde elde tutulan bir telefon yasasından iki veya daha fazla mahkumiyet, 60 günlük bir men cezası getirir (üç veya daha fazlası için 120 gün). Kaynak: Delaware CDL Manual elde tutulan cep telefonu bölümü; 49 CFR 383.51."},"54":{"q":"Delaware CDL Manual'da belirtildiği üzere, bir CMV sürücüsünün araç kullanırken mesaj atma ihlali için karşılaşabileceği maksimum federal idari para cezası nedir?","options":["$750'ye kadar","$1,500'ye kadar","$2,750'ye kadar","$11,000'e kadar"],"explanation":"Delaware CDL Manual, sürücülerin mesaj atma/elde tutulan telefon ihlalleri için $2,750'ye kadar idari para cezasına tabi olduğunu belirtir (işverenler $11,000'e kadar). Kaynak: Delaware CDL Manual mesajlaşma ve elde tutulan cep telefonu bölümü."},"55":{"q":"Bir CMV'de bir demiryolu-karayolu hemzemin geçit ihlalinin İLK mahkumiyeti için bir Delaware CDL ne kadar süreyle men edilir?","options":["30 günden az olmamak üzere","60 günden az olmamak üzere","120 günden az olmamak üzere","1 yıldan az olmamak üzere"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, 60 günden az olmamak üzere bir men cezası taşır. Kaynak: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"56":{"q":"Delaware'de, üç yıl içinde bir CMV'de İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali, CDL'yi en az ne kadar süreyle men eder?","options":["60 gün","120 gün","180 gün","1 yıl"],"explanation":"Herhangi bir üç yıllık süre içinde ikinci bir demiryolu geçidi ihlali, 120 günden az olmamak üzere bir men cezasıyla sonuçlanır. Kaynak: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"57":{"q":"Bir Delaware CMV sürücüsü, üç yıl içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işliyor. CDL en az ne kadar süreyle men edilir?","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"Herhangi bir üç yıllık süre içinde üçüncü bir demiryolu geçidi ihlali, 1 yıldan az olmamak üzere bir men cezasıyla sonuçlanır. Kaynak: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"58":{"q":"Delaware CDL kurallarına göre, bir CMV'de (tehlikeli madde taşımıyorken) bir hizmet dışı (out-of-service) emrini ihlal etmenin İLK mahkumiyeti için men cezası aralığı nedir?","options":["30 günden az ve 90 günden fazla olmamak üzere","180 günden az ve 1 yıldan fazla olmamak üzere","1 yıldan az ve 2 yıldan fazla olmamak üzere","3 yıldan az ve 5 yıldan fazla olmamak üzere"],"explanation":"İlk bir hizmet dışı emir ihlali, 180 günden az ve 1 yıldan fazla olmamak üzere bir men cezası taşır. Kaynak: Delaware CDL Manual MCSIA men cezası gerektiren ihlaller bölümü; 49 CFR 383.51."},"59":{"q":"Delaware'in \"Move Over\" (Şerit Değiştir) yasası uyarınca, kendi yönünüzde dört veya daha fazla şeridi olan bir otoyolda uyarı ışıklarını yakmış, durmuş bir DelDOT, polis, çekici veya acil durum aracına yaklaştığınızda önce ne yapmanız gerekir?","options":["Güvenliyse, durmuş araca bitişik olmayan bir şeride geçiş yapmak","Durmuş araç banketten ayrılana kadar tamamen durmak","Bankete geçip en fazla 10 mph hızla geçmek","Şeridinizi koruyup geçerken sürekli korna çalmak"],"explanation":"Delaware Title 21 § 4134(b), aynı yönde en az dört şeridi olan bir yolda sürücülerin, durmuş acil durum/DelDOT/çekici/altyapı aracına bitişik olmayan bir şeride güvenli olduğunda geçerek yol vermesini gerektirir. Kaynak: 21 Del. C. § 4134."},"60":{"q":"Delaware'in \"Move Over\" yasası uyarınca, durmuş bir acil durum aracından güvenli bir şekilde uzağa şerit değiştiremiyorsanız, belirlenen hız sınırının 50 mph veya daha yüksek olduğu yerlerde hangi hız azaltması gereklidir?","options":["Belirlenen hız sınırının en az 20 mph altında güvenli bir hıza düşmek","Belirlenen hız sınırının en az 10 mph altında güvenli bir hıza düşmek","Belirlenen hız sınırının tam olarak yarısına düşmek","Belirlenen sınırdan bağımsız olarak en fazla 25 mph'ye düşmek"],"explanation":"21 Del. C. § 4134(b), şerit değiştirmenin mümkün olmadığı durumlarda, sınırın 50 mph veya üzeri olduğu yerlerde sürücünün belirlenen sınırdan en az 20 mph daha düşük güvenli bir hıza düşmesini gerektirir. Kaynak: 21 Del. C. § 4134."},"61":{"q":"Bir Delaware okul otobüsü, bölünmemiş iki şeritli bir yolda kırmızı ışıkları yanıp sönerek durduğunda hangi sürücüler durmak zorundadır?","options":["Hem önden hem de arkadan yaklaşan sürücüler","Yalnızca arkadan yaklaşan sürücüler (otobüsle aynı yönde)","Yalnızca önden yaklaşan sürücüler (karşıdan gelen)","Yalnızca otobüse 20 fit mesafedeki sürücüler"],"explanation":"Delaware Title 21 § 4166, durmuş bir okul otobüsüne önden veya arkadan yaklaşan herhangi bir aracın sürücüsünün, otobüsün kırmızı durma lambaları yanıyorken otobüsü geçmeden önce durmasını gerektirir. Kaynak: 21 Del. C. § 4166."},"62":{"q":"Dört veya daha fazla şeridi olan bir Delaware yolunda (veya yollarında), yanıp sönen kırmızı ışıklar gösteren bir okul otobüsü için hangi yaklaşan sürücünün durması GEREKMEZ?","options":["Önden yaklaşan sürücü (karşı yönden gelen)","Arkadan yaklaşan sürücü (otobüsle aynı yönde)","Hem önden hem de arkadan gelen sürücüler muaftır","Hiçbir sürücü muaf değildir; her ikisi de daima durmalıdır"],"explanation":"21 Del. C. § 4166, 4 veya daha fazla şeridi olan bir yolda veya yollarda önden (karşı yönden) yaklaşan sürücünün durmasının gerekmediğini; arkadan yaklaşan sürücünün ise yine de durması gerektiğini belirtir. Kaynak: 21 Del. C. § 4166."},"63":{"q":"Kırmızı ışıkları yanıp sönen bir Delaware okul otobüsü için durduktan sonra, bir sürücü ne kadar süre durmuş halde kalmalıdır?","options":["Otobüs hareket etmeye başlayana veya kırmızı durma lambaları artık yanmayana kadar","En az sabit 30 saniye boyunca","Otobüs şoförü trafiğe ilerlemesini işaret edene kadar","Tüm çocuklar otobüsten en az 100 fit uzakta olana kadar"],"explanation":"21 Del. C. § 4166, sürücünün otobüs hareket etmeye başlayana veya yanan kırmızı durma lambalarını artık göstermeyene kadar durmuş halde kalmasını gerektirir. Kaynak: 21 Del. C. § 4166."},"64":{"q":"Delaware CDL kılavuzuna göre, plakalı tehlikeli madde taşıyan bir araç, boyalı durma çizgisi olmayan bir demiryolu geçidinde durmak zorunda kaldığında, en yakın raya göre nerede durmalıdır?","options":["En yakın raya 15 fitten yakın ve 50 fitten uzak olmayacak şekilde","En yakın raya 10 fitten yakın ve 25 fitten uzak olmayacak şekilde","En yakın raya 25 fitten yakın ve 75 fitten uzak olmayacak şekilde","En yakın raya 5 fitten yakın ve 35 fitten uzak olmayacak şekilde"],"explanation":"Delaware CDL Kılavuzu (Bölüm 2.15), durmak zorunda olan araçların en yakın hattın en yakın rayından 15 fitten yakın ve 50 fitten fazla olmayacak şekilde durması gerektiğini belirtir. Kaynak: Delaware CDL Manual, Sec. 2.15."},"65":{"q":"Delaware CDL kılavuzuna göre, ticari aracınızın herhangi bir kısmı demiryolu raylarından geçerken aşağıdakilerden hangisini YAPMAMALISINIZ?","options":["Raylardan geçerken vites değiştirmek","İki elinizi de direksiyonda tutmak","Yalnızca tüm rayların boş olduğunu doğruladıktan sonra geçmek","Mevcut olduğunda durmak için bir kenara çekilme şeridi kullanmak"],"explanation":"Delaware CDL Kılavuzu (Bölüm 2.15), geçitte stop yapmamak için sürücülere demiryolu raylarından geçerken vites değiştirmemelerini söyler. Kaynak: Delaware CDL Manual, Sec. 2.15."},"66":{"q":"Delaware CDL kılavuzuna göre, ticari aracınız tek yönlü veya bölünmüş bir otoyolda durmak zorunda kalırsa, üç uyarı cihazınızı hangi mesafelere yerleştirmelisiniz?","options":["Yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit","Yaklaşan trafiğe doğru 10 fit, 50 fit ve 150 fit","Yaklaşan trafiğe doğru 25 fit, 100 fit ve 250 fit","10 fit, 100 fit ve 100 fit (biri önde, biri arkada)"],"explanation":"Delaware CDL Kılavuzu (Bölüm 2.5), tek yönlü veya bölünmüş bir otoyolda uyarı cihazlarının yaklaşan trafiğe doğru 10, 100 ve 200 fite yerleştirilmesini belirtir. Kaynak: Delaware CDL Manual, Sec. 2.5."},"67":{"q":"Delaware CDL kılavuzuna göre, her iki yönde de trafik taşıyan iki şeritli bölünmemiş bir yolda durduktan sonra uyarı cihazlarını nereye yerleştirirsiniz?","options":["Aracın 10 fit içinde ve aracın 100 fit arkasında ve 100 fit önünde","Aracın yakınında hiçbiri olmadan 200 fit arkada ve 200 fit önde","Yalnızca aracın 100 fit arkasında bir cihaz","10 fit, 100 fit ve 200 fit, hepsi aracın arkasında"],"explanation":"Delaware CDL Kılavuzu (Bölüm 2.5), iki şeritli/bölünmemiş bir yolda aracın ön veya arka köşesine 10 fit içinde bir cihaz ve aracın 100 fit arkasına ve 100 fit önüne cihazlar yerleştirmeyi belirtir. Kaynak: Delaware CDL Manual, Sec. 2.5."},"68":{"q":"Delaware CDL kılavuzuna göre, yolda veya bankette durduktan sonra acil durum uyarı cihazlarınızı kaç dakika içinde yerleştirmelisiniz?","options":["10 dakika","5 dakika","15 dakika","30 dakika"],"explanation":"Delaware CDL Kılavuzu (Bölüm 2.5), acil durum uyarı cihazlarının bir yolda veya bankette durduktan sonra 10 dakika içinde yerleştirilmesini gerektirir. Kaynak: Delaware CDL Manual, Sec. 2.5."},"69":{"q":"Delaware CDL kılavuzuna göre, ticari bir aracın park edildiğinde veya arızalandığında kullanmak üzere hangi uyarı ekipmanını taşıması gerekir?","options":["Üç yansıtıcı üçgen veya en az 6 fişek (fusee) veya 3 sıvı yakıtlı işaret fişeği","İki yansıtıcı üçgen ve bir kırmızı bayrak","Yalnızca dört yansıtıcı üçgen","Bir yansıtıcı üçgen ve pille çalışan bir işaret lambası"],"explanation":"Delaware CDL Kılavuzu, gerekli acil durum ekipmanını üç yansıtıcı üçgen veya en az 6 fişek (fusee) veya 3 sıvı yakıtlı işaret fişeği olarak listeler. Kaynak: Delaware CDL Manual, Sec. 2.1 (muayene)."},"70":{"q":"Delaware CDL kılavuzuna göre, bir tepe veya viraj, arkadan gelen sürücülerin durmuş aracınızı 500 fit içinde görmesini engelliyorsa, en arkadaki uyarı üçgeninizle ne yapmalısınız?","options":["Uyarı sağlanması için onu yolda daha geriye, engelin ötesine taşımak","Standart 100 fitte bırakıp dördüncü bir üçgen eklemek","Görünürlüğünü artırmak için onu aracın kaputuna yerleştirmek","Onu kaldırıp yalnızca dörtlü flaşörlere güvenmek"],"explanation":"Delaware CDL Kılavuzu (Bölüm 2.5), bir tepe veya viraj 500 fit içindeki görüşü engellediğinde, arkadan gelen sürücülerin uyarı alması için en arkadaki üçgeni engelin ötesine geriye taşımayı söyler. Kaynak: Delaware CDL Manual, Sec. 2.5."},"71":{"q":"Delaware Title 21 uyarınca, başka bir sınırın belirtilmediği iki şeritli bir yolda yasal hız sınırı nedir?","options":["50 mph","55 mph","45 mph","60 mph"],"explanation":"Delaware Title 21 § 4169, aksi belirtilmedikçe 2 şeritli yollarda 50 mph (ve 4 şeritli ve bölünmüş yollarda 55 mph) belirler. Kaynak: 21 Del. C. § 4169."},"72":{"q":"Delaware Title 21 uyarınca, başka bir sınırın belirtilmediği dört şeritli veya bölünmüş bir yolda yasal hız sınırı nedir?","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"Delaware Title 21 § 4169, aksi belirtilmedikçe 4 şeritli ve bölünmüş yollarda 55 mph belirler. Kaynak: 21 Del. C. § 4169."},"73":{"q":"Delaware Title 21 uyarınca, aksi belirtilmedikçe bir ticari veya yerleşim bölgesinde hız sınırı nedir?","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"Delaware Title 21 § 4169, aksi belirtilmedikçe ticari bölgelerde 25 mph ve yerleşim bölgelerinde 25 mph belirler. Kaynak: 21 Del. C. § 4169."},"74":{"q":"Ulaştırma Departmanı, Red Lion Creek ile Appoquinimink Nehri arasında hangi Delaware yolunda 65 mph maksimum hız sınırı belirlemiştir?","options":["Delaware Eyalet Yolu 1 (State Route 1)","Interstate 495","U.S. Route 13","Interstate 295"],"explanation":"Delaware Title 21 § 4169, DelDOT'a State Route 1'in Red Lion Creek ile Appoquinimink Nehri arasındaki kısmında (ücret gişesi alanı hariç) 65 mph maksimum belirlemesi talimatını verir. Kaynak: 21 Del. C. § 4169."},"75":{"q":"Delaware'in şerit kullanım kısıtlaması yasası (§ 4114A) uyarınca, State Route 1 ve Interstate 495'te genellikle hangi araçlar yalnızca en sağdaki şeritte seyahat edebilir?","options":["Brüt araç ağırlık derecesi (GVWR) 26.000 pounddan fazla olan bir araç","Brüt araç ağırlık derecesi (GVWR) 10.000 pounddan fazla olan bir araç","Herhangi bir boyutta römork çeken her araç","Ağırlıktan bağımsız olarak üç veya daha fazla akslı bir araç"],"explanation":"Delaware Title 21 § 4114A, GVWR'si 26.000 pounddan fazla olan araçları, SR 1 ve I-495'in ekspres/kontrollü erişimli kısımlarında, sınırlı istisnalarla birlikte en sağdaki şeritle kısıtlar. Kaynak: 21 Del. C. § 4114A."},"76":{"q":"Delaware § 4114A uyarınca, sağ şerit kısıtlamasına tabi bir araç SR 1 veya I-495'te ne zaman yasal olarak bir sol şeridi kullanabilir?","options":["Başka bir aracı geçerken ve sollarken, yola girerken veya yoldan çıkarken ya da trafik koşullarının gerektirdiği durumlarda","Yalnızca gece yarısı ile 06:00 arasında","Yalnızca belirlenen hız sınırı 35 mph veya daha düşük olduğunda","Hiçbir koşulda asla"],"explanation":"Delaware Title 21 § 4114A, ağır aracın geçiş yapmak, yola girmek/çıkmak, acil durumlar, engeller, trafik koşulları veya başka bir yasaya uymak için bir sol şeridi kullanmasına izin verir. Kaynak: 21 Del. C. § 4114A."},"77":{"q":"Delaware yasalarına göre, normal trafik hızından daha yavaş giden bir araç, sollama yaparken veya sola dönüşe hazırlanırken hariç, nerede sürülmelidir?","options":["Trafiğe açık en sağdaki şeritte veya sağdaki bordüre ya da kenara mümkün olduğunca yakın","Çok şeritli herhangi bir yolun orta şeridinde","En az aracın bulunduğu şeritte","Sol şeritte, sağ şeridi katılan trafiğe açık bırakarak"],"explanation":"Delaware Title 21 § 4114, normal trafikten daha yavaş giden bir aracın, sollama yaparken veya sola dönüşe hazırlanırken hariç, en sağdaki şeritte veya sağdaki bordüre/kenara mümkün olduğunca yakın kalmasını gerektirir. Kaynak: 21 Del. C. § 4114."},"78":{"q":"Delaware CDL kılavuzuna göre, bir CMV kullanırken yapılan demiryolu-karayolu hemzemin geçit ihlali, ilk suç için en az ne kadar süreyle CDL diskalifikasyonuyla sonuçlanır?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Delaware CDL Kılavuzu (Bölüm 1.3.5), bir demiryolu-karayolu hemzemin geçit ihlalinin CDL'yi en az 60 gün (ilk), 120 gün (3 yıl içinde ikinci) ve 1 yıl (3 yıl içinde üçüncü) diskalifiye ettiğini belirtir. Kaynak: Delaware CDL Manual, Sec. 1.3.5."},"79":{"q":"Ticari Sürücü Belgelerini (CDL) hangi Delaware kurumu verir?","options":["DelDOT'un bir parçası olan Delaware Motorlu Taşıtlar Dairesi (DMV)","Delaware Eyalet Polisi Ticari Taşıyıcı Bürosu","Federal Motorlu Taşıyıcı Güvenliği İdaresi saha ofisi","Delaware Eyalet Sekreteri Ofisi"],"explanation":"Delaware'de CDL'ler, Delaware Ulaştırma Departmanı bünyesinde faaliyet gösteren Delaware Motorlu Taşıtlar Dairesi (DMV) tarafından verilir. FMCSA federal standartları belirler ancak belgeyi vermez. Kaynak: Delaware DMV CDL sayfaları; Title 21, Chapter 26 (Uniform Commercial Driver License Act)."},"80":{"q":"Delaware CDL bilgi (yazılı) testleri nasıl uygulanır?","options":["Randevu gerekmeden, herhangi bir DMV tesisinde randevusuz (walk-in) olarak","Yalnızca Dover merkezinde randevuyla","Evden, uzaktan bir gözetmen eşliğinde çevrimiçi olarak","Yalnızca onaylı tek bir üçüncü taraf test merkezinde"],"explanation":"Delaware DMV, tüm CDL bilgi testlerinin yalnızca randevusuz (walk-in) olduğunu ve herhangi bir bölüm (DMV) tesisinde tamamlanabileceğini belirtir. Randevu gerekliliği beceri testi için geçerlidir, bilgi testi için değil. Kaynak: Delaware DMV CDL web sayfası."},"81":{"q":"Bir Delaware Ticari Öğrenci İzni (CLP), sahibinin CDL beceri testine girebilmesi için ne kadar süre elde tutulmalıdır?","options":["İlk verildikten sonra en az 14 gün","İlk verildikten sonra en az 30 gün","İlk verildikten sonra en az 10 gün","İlk verildikten sonra en az 7 gün"],"explanation":"Bir CLP sahibi, izin ilk verildikten sonra en az 14 gün elde tutulana kadar CDL yol öncesi (pre-trip), temel kontrol veya yol beceri testine girmeye uygun değildir. Bu, Delaware tarafından benimsenen 14 günlük federal bekleme süresidir. Kaynak: Delaware DMV CDL web sayfası; Title 21 Ch. 26 kapsamında benimsenen 49 CFR 383.25."},"82":{"q":"Bir Delaware Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir?","options":["Bir (1) yıl ve bu süre içinde bir kez yenilenebilir","180 gün, yenileme izni yok","İki (2) yıl, yıllık olarak yenilenebilir","Altı (6) ay, iki kez yenilenebilir"],"explanation":"Bir Delaware CLP bir (1) yıl geçerlidir ve bir yılı aşan bir süre için verilemez veya uzatılamaz; bu süre içinde bir kez yenilenebilir. Kaynak: Delaware DMV CDL web sayfası; Title 21 § 2608."},"83":{"q":"Delaware CDL beceri testi hangi üç bölüme ayrılır?","options":["Yol öncesi (pre-trip) araç muayenesi, temel kontrol becerileri ve yolda sürüş","Yazılı sınav, göz muayenesi ve yol testi","Yalnızca bağlama, frenleme ve geri gitme","Teorik eğitim, direksiyon başında uygulama ve son yazılı sınav"],"explanation":"CDL beceri testi üç bölümden oluşur: yol öncesi (pre-trip) araç muayenesi testi, temel kontrol becerileri testi ve yolda sürüş testi. Delaware bu protokolleri 26 Şubat 2025'ten itibaren geçerli olacak şekilde modernize etti. Kaynak: Delaware DMV CDL web sayfası; 49 CFR 383.113."},"84":{"q":"Giriş seviyesi bir sürücünün, Class A, Class B, Yolcu (P) veya Okul Otobüsü (S) belgesi için Delaware CDL beceri testine girmeden önce neyi tamamlaması gerekir?","options":["Kayıtlı bir sağlayıcıdan federal olarak zorunlu Giriş Seviyesi Sürücü Eğitimi (ELDT)","DMV'ye kaydedilmiş 30 günlük bir çıraklık","Delaware Eyalet Polisi tarafından onaylanmış bir savunmacı sürüş kursu","Yalnızca genel bilgi yazılı testi"],"explanation":"7 Şubat 2022'den itibaren, hiçbir giriş seviyesi operatör, FMCSA Eğitim Sağlayıcı Kaydı'nda (Training Provider Registry) listelenen bir sağlayıcıdan zorunlu teorik ve direksiyon başında ELDT'yi tamamlamadıkça Class A, Class B, P onayı veya S onayı için CDL beceri testine giremez. Kaynak: Delaware DMV ELDT sayfası; 49 CFR Part 380."},"85":{"q":"Bir Delaware CDL/CLP sahibinin beyan edebileceği dört öz-sertifikasyon (self-certification) kategorisi nelerdir?","options":["Eyaletler arası muaf olmayan, eyaletler arası muaf, eyalet içi muaf olmayan, eyalet içi muaf","Class A, Class B, Class C ve Class D","HazMat, yolcu, tanker ve ikili/üçlü römork (doubles/triples)","Ücretli (for-hire), özel, muaf ve devlet"],"explanation":"Her Delaware CDL/CLP sahibi dört kategoriden birine kendini sertifikalandırmalıdır: eyaletler arası muaf olmayan, eyaletler arası muaf, eyalet içi muaf olmayan veya eyalet içi muaf. Kaynak: Delaware DMV Self-Certification Affidavit Category Guide; 49 CFR 383.71."},"86":{"q":"Hangi öz-sertifikasyon kategorisi, sürücünün Delaware DMV'ye güncel bir DOT tıbbi muayene sertifikası sunmasını ve dosyada tutmasını gerektirir?","options":["Eyaletler arası muaf olmayan","Eyaletler arası muaf","Eyalet içi muaf","Hiçbir kategorinin sunması gerekmez"],"explanation":"Kendini eyaletler arası muaf olmayan olarak sertifikalandıran bir sürücü, federal tıbbi muayene sertifikasının bir kopyasını Delaware DMV'ye sunmalı ve dosyada tutmalıdır. Muaf kategorilerin federal tıbbi sertifika sunması gerekmez. Kaynak: Delaware DMV Self-Certification Category Guide; 49 CFR 383.71."},"87":{"q":"Bir Delaware CDL başvuru sahibi, tıbbi muayene sertifikasını destekleyen DOT fiziksel muayenesini nereden almalıdır?","options":["FMCSA Sertifikalı Tıbbi Muayeneciler Ulusal Kayıt Sistemi'nde (National Registry of Certified Medical Examiners) listelenen bir tıbbi muayeneciden","Sürücünün seçtiği herhangi bir lisanslı hekim veya kayropraktörden","Yalnızca Delaware Eyalet Polisi tarafından onaylanmış bir klinikten","DMV'nin kendi bünyesindeki tıbbi personelden"],"explanation":"Tıbbi sertifika, FMCSA Sertifikalı Tıbbi Muayeneciler Ulusal Kayıt Sistemi'nde listelenen bir tıbbi muayeneciden gelmelidir. Delaware bu federal gerekliliği tüm CDL/CLP sahipleri için benimsemiştir. Kaynak: Delaware DMV Medical Certification sayfası; 49 CFR 390.103 / National Registry."},"88":{"q":"Bir Delaware CDL hangi takvime göre sona erer ve yenilenebilir hale gelir?","options":["Verilmeyi takip eden sahibinin doğum tarihinin sekizinci yıl dönümünde (her 8 yılda bir)","Veriliş tarihinde her 4 yılda bir","Veriliş tarihinde her 5 yılda bir","DOT fiziksel muayenesine uyacak şekilde her 2 yılda bir"],"explanation":"Bir Delaware CDL, başvuru sahibinin verilmeyi takip eden ilk doğum gününün sekizinci yıl dönümünde sona erer ve yenilenebilir; bu, sekiz yıla kadar etkili bir geçerlilik süresi sağlar. Kaynak: Title 21 § 2611(f); Delaware DMV."},"89":{"q":"Bir Delaware CDL'si, süresi dolmadan en erken ne zaman yenilenebilir?","options":["Sona erme tarihinden önceki 30 gün içinde","Sona erme tarihinden önceki 90 gün içinde","Sona erme tarihinden önceki 6 ay içinde","Sona erme tarihinden önceki 1 yıl içinde"],"explanation":"Delaware, bir CDL'nin yalnızca sona erme tarihinden önceki 30 gün içinde yenilenmesine izin verir. Kaynak: Delaware DMV CDL web sayfası."},"90":{"q":"Yalnızca eyalet içi (Delaware içinde) sürüş için bir Delaware CDL'si almak için asgari yaş nedir?","options":["18 yaşında","16 yaşında","21 yaşında","19 yaşında"],"explanation":"Bir kişinin eyalet içi operasyon için bir Delaware CDL'sine sahip olabilmesi için en az 18 yaşında olması gerekir. Kaynak: Delaware DMV; Title 21 Ch. 26."},"91":{"q":"Bir Delaware CDL kapsamında eyaletler arası ticarette ticari bir araç sürmek, tehlikeli madde taşımak veya yolcu taşımak için asgari yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","23 yaşında"],"explanation":"Bir sürücünün eyaletler arası ticarette faaliyet göstermesi, plaka gerektiren tehlikeli madde taşıması veya yolcu taşıması için en az 21 yaşında olması gerekir. Kaynak: Delaware DMV; 49 CFR 383."},"92":{"q":"Bir Delaware başvuru sahibi, CDL beceri (yol) testi için geldiğinde hangi belgeleri sunmalıdır?","options":["Geçerli öğrenci izni, eşlik eden 21+ yaşındaki sürücünün geçerli ehliyeti, geçerli araç ruhsatı ve geçerli sigorta","Yalnızca geçerli bir öğrenci izni ve Sosyal Güvenlik kartı","Yalnızca bir pasaport ve test ücreti makbuzu","Bir doğum belgesi ve iki fatura"],"explanation":"Yol testi için başvuru sahibi geçerli bir öğrenci izni, eşlik eden sürücünün (21+) geçerli ehliyetini, geçerli bir araç ruhsat kartını ve geçerli bir sigorta kartını sunmalıdır. Kaynak: Delaware DMV CDL web sayfası."},"93":{"q":"Delaware CDL genel bilgi yazılı testini geçmek için hangi puan gereklidir?","options":["%80 doğru (50 sorudan 40'ı)","%70 doğru (50 sorudan 35'i)","%90 doğru (50 sorudan 45'i)","%100 doğru (50 sorunun tamamı)"],"explanation":"Delaware CDL genel bilgi testi 50 sorudan oluşur ve geçmek için %80 (50'de 40) veya daha yüksek bir puan gerektirir. Kaynak: Delaware DMV / Delaware'de kullanılan AAMVA tabanlı CDL test sistemi."},"94":{"q":"Delaware'in CDL bilgi ve beceri testlerine hazırlanmak için sağladığı birincil bireysel çalışma kaynağı hangi belgedir?","options":["DMV tarafından yayınlanan Delaware CDL Kılavuzu (Commercial Driver License Manual)","Delaware Code, Title 21 açıklamalı baskısı","FMCSA Büyük Kamyon ve Otobüs İstatistikleri Cep Kılavuzu","Eyalet Sürücü Eğitimi ders kitabı"],"explanation":"Delaware DMV, başvuru sahiplerinin test öncesinde edinip çalışması gereken (AAMVA modeline dayalı) Delaware CDL Kılavuzu'nu yayınlar. Kaynak: Delaware DMV CDL Manual."},"95":{"q":"Delaware CDL beceri testinin yolda yapılan bölümü nasıl planlanır ve yol öncesi (pre-trip) bölümü nasıl desteklenir?","options":["Beceri testi randevuyladır ve DMV, başvuru sahiplerine yardımcı olarak bir yol öncesi muayene kontrol listesi sağlar","Üç beceri bölümünün tamamı randevusuzdur (walk-in) ve hiçbir kontrol listesi sağlanmaz","Yol testi çevrimiçidir; yol öncesi muayene ELDT mezunları için muaf tutulur","Planlama yalnızca başvuru sahibinin işvereni aracılığıyla yapılır"],"explanation":"Delaware CDL beceri testleri yalnızca randevuyladır ve modernize edilmiş program, başvuru sahiplerine yol öncesi araç muayenesi testi için bir çalışma yardımcısı olarak bir kontrol listesi sağlar. Kaynak: Delaware DMV CDL web sayfası (modernize edilmiş beceri testi, 26 Şubat 2025'ten itibaren geçerli)."},"96":{"q":"Kendini eyaletler arası muaf olmayan olarak sertifikalandıran sahibi, DMV'de güncel bir tıbbi muayene sertifikasını dosyada tutmazsa bir Delaware CDL'sine genellikle ne olur?","options":["Ticari (CDL) ayrıcalığı, kişi artık ticari araç kullanamayacak şekilde düşürülür (downgrade)","CDL kalıcı olarak iptal edilir ve yeniden tesis edilemez","Hiçbir şey, çünkü tıbbi sertifika yalnızca bir işveren kaydıdır","Ehliyet otomatik olarak eyaletler arası muaf bir CDL'ye dönüşür"],"explanation":"Gerekli (muaf olmayan) bir sürücü, tıbbi sertifikanın süresinin dolmasına izin verir veya sunmazsa, eyalet CDL'yi düşürmeli (downgrade) ve geçerli bir sertifika dosyaya girene kadar ticari sürüş ayrıcalıklarını kaldırmalıdır. Kaynak: Delaware DMV Self-Certification FAQ; 49 CFR 383.73."},"97":{"q":"Eyaletler arası muaf olmayan bir Delaware sürücüsü için, tıbbi sertifikayı destekleyen DOT fiziksel muayenesi genellikle ne kadar güncel olmalıdır?","options":["Önceki 24 ay içinde tarihli (en fazla 2 yıllık sertifikasyona kadar)","Önceki 6 ay içinde tarihli","Yalnızca önceki 12 ay içinde tarihli","Önceki 5 yıl içinde tarihli"],"explanation":"DOT fiziksel muayenesi 49 CFR 391.41-391.49'a uygun olmalı ve bir sürücüyü en fazla 24 aya kadar sertifikalandırabilir (bir tıbbi muayeneci, belirli durumlar için daha kısa bir süre sertifikalandırabilir). Delaware bu federal standardı gerektirir. Kaynak: Delaware DMV Medical Certification sayfası; 49 CFR 391.43."}},"es":{"0":{"q":"¿Cuál es la altura máxima legal de un vehículo, incluyendo cualquier carga, en las carreteras de Delaware?","options":["13 pies 6 pulgadas","14 pies","13 pies","12 pies 6 pulgadas"],"explanation":"La ley de Delaware fija la altura máxima de un vehículo y su carga en 13 pies 6 pulgadas, tanto en las carreteras generales como en el sistema interestatal. Fuente: Delaware Code Title 21, Ch. 45, secciones 4502(b) y 4503(b)."},"1":{"q":"Sin contar el equipo de seguridad, ¿cuál es el ancho exterior total máximo permitido para la mayoría de los vehículos comerciales en Delaware?","options":["102 pulgadas","96 pulgadas","108 pulgadas","120 pulgadas"],"explanation":"Delaware limita el ancho exterior total del vehículo a 102 pulgadas (8 pies 6 pulgadas), sin incluir el equipo de seguridad. Fuente: Delaware Code Title 21, secciones 4502 y 4503; límites legales OSOW de DelDOT."},"2":{"q":"¿Cuál es la longitud máxima permitida de un semirremolque (sin incluir el tractocamión) que opera en Delaware?","options":["53 pies","48 pies","57 pies","45 pies"],"explanation":"Un semirremolque, incluyendo cualquier carga, no puede exceder los 53 pies de longitud, sin contar el tractocamión. Fuente: Delaware Code Title 21, Ch. 45, sección 4503(b)."},"3":{"q":"¿Cuál es el peso bruto vehicular máximo para una combinación típica de cinco o más ejes en Delaware?","options":["80,000 libras","73,280 libras","88,000 libras","90,000 libras"],"explanation":"Delaware limita el peso bruto de una combinación de vehículos de cinco o más ejes a 80,000 libras, en concordancia con el límite federal. Fuente: Delaware Code Title 21, Ch. 45, secciones 4502(c) y 4503(c)."},"4":{"q":"En el sistema interestatal de Delaware, ¿cuál es el peso máximo permitido sobre un solo eje?","options":["20,000 libras","22,400 libras","18,000 libras","24,000 libras"],"explanation":"En las carreteras interestatales, Delaware sigue el límite federal de 20,000 libras por eje sencillo. Fuente: Delaware Code Title 21, Ch. 45, sección 4503(c)."},"5":{"q":"En el sistema interestatal de Delaware, ¿cuál es el peso máximo permitido sobre un eje tándem?","options":["34,000 libras","36,000 libras","40,000 libras","32,000 libras"],"explanation":"En las carreteras interestatales, el límite por eje tándem es de 34,000 libras, igual que el estándar federal. Fuente: Delaware Code Title 21, Ch. 45, sección 4503(c)."},"6":{"q":"¿Cuándo se requiere un permiso de transporte de carga sobredimensionada o con sobrepeso del DOT de Delaware?","options":["Cuando un vehículo o carga excede los límites de tamaño o peso establecidos en el Chapter 45, Title 21 del Delaware Code","Solo cuando el peso bruto excede las 80,000 libras, sin importar los pesos por eje","Solo para cargas más anchas de 12 pies","Solo cuando se viaja por la Interstate 95"],"explanation":"Se requiere un permiso siempre que un vehículo, combinación o equipo autopropulsado exceda los límites dimensionales o de peso establecidos en el Chapter 45, Title 21 del Delaware Code, incluso cuando un eje individual tenga sobrepeso aunque el peso bruto sea legal. Fuente: preguntas frecuentes de permisos OSOW de DelDOT; Delaware Code Title 21, sección 4504."},"7":{"q":"¿Cómo se obtienen los permisos de transporte de carga sobredimensionada o con sobrepeso en Delaware?","options":["A través del sistema en línea de permisos de Sobredimensión/Sobrepeso (OSOW) de DelDOT, administrado por la Oficina de Permisos de Transporte (Hauling Permit Office)","Enviando un formulario en papel por correo a la división de CDL del DMV de Delaware","Comprándolos en cualquier mostrador de servicios vehiculares del DMV","Se emiten automáticamente con el registro del vehículo"],"explanation":"Los permisos de sobredimensión/sobrepeso los emite DelDOT a través de su sistema en línea de permisos OSOW, gestionado por la Oficina de Permisos de Transporte (Hauling Permit Office), no por el DMV. Fuente: sistema de permisos OSOW de DelDOT (deldot.gov/osow)."},"8":{"q":"¿Cuál es la tarifa mínima para un permiso estándar de viaje único de sobredimensión/sobrepeso de Delaware?","options":["$30.00","$15.00","$50.00","$10.00"],"explanation":"La tarifa mínima para un permiso de transporte de viaje único es de $30.00 ($60.00 para una Supercarga). Fuente: preguntas frecuentes de permisos OSOW de DelDOT; manual de políticas de permisos del Delaware Administrative Code 2405."},"9":{"q":"Para un permiso de sobrepeso de Delaware, ¿cómo se calcula la tarifa adicional por peso?","options":["$10.00 por cada 8,000 libras (o fracción de ellas) por encima del límite de peso legal","$25.00 por cada 5,000 libras por encima del límite de peso legal","$5.00 por cada 1,000 libras por encima del límite de peso legal","Una tarifa fija de $100.00 sin importar el exceso de peso"],"explanation":"Delaware agrega una tarifa por peso de $10.00 por cada 8,000 libras, o fracción de ellas, por encima del límite de peso legal. Fuente: preguntas frecuentes de permisos OSOW de DelDOT; Delaware Administrative Code 2405."},"10":{"q":"¿Por cuánto tiempo es válido un permiso estándar de transporte de viaje único de sobredimensión/sobrepeso de Delaware?","options":["5 días (de la fecha de vigencia a la fecha de vencimiento)","24 horas","30 días","10 días"],"explanation":"Un permiso estándar de transporte es válido por cinco días, desde la fecha de vigencia hasta la fecha de vencimiento. Fuente: preguntas frecuentes de permisos OSOW de DelDOT; Delaware Administrative Code 2405."},"11":{"q":"¿Durante qué horario puede circular generalmente una carga sobredimensionada con permiso por las carreteras de Delaware, a menos que el permiso indique lo contrario?","options":["Del amanecer al atardecer, de lunes a domingo","Solo de lunes a viernes durante el horario laboral","Solo entre las 9 p.m. y las 5 a.m.","A cualquier hora, las 24 horas del día, sin restricción"],"explanation":"Las cargas con permiso están autorizadas a circular del amanecer al atardecer, de lunes a domingo, a menos que las disposiciones especiales del permiso indiquen lo contrario. Fuente: preguntas frecuentes de permisos OSOW de DelDOT."},"12":{"q":"¿Qué fórmula aplica Delaware para determinar el peso bruto máximo sobre un grupo de ejes consecutivos?","options":["La Fórmula del Puente (Bridge Formula) federal, W = 500[(LN / (N-1)) + 12N + 36]","Una tarifa fija de 1,000 libras por pulgada de ancho de neumático","El GVWR del fabricante multiplicado por 1.5","Un simple 20,000 libras por eje sin factor de separación"],"explanation":"Delaware adopta la Fórmula del Puente (Bridge Formula) federal, W = 500[(LN / (N-1)) + 12N + 36], donde W es el peso permitido, L es la distancia entre los ejes extremos del grupo y N es el número de ejes. Fuente: Delaware Code Title 21, Ch. 45, sección 4503(c)."},"13":{"q":"Según la regla de peso por puente de Delaware, dos conjuntos consecutivos de ejes tándem pueden cargar cada uno 34,000 libras siempre que la distancia entre el primer y el último eje de los conjuntos sea de al menos:","options":["36 pies","30 pies","40 pies","24 pies"],"explanation":"Una excepción a la fórmula del puente permite que dos conjuntos consecutivos de ejes tándem carguen cada uno 34,000 libras cuando la distancia total entre el primer y el último eje de esos conjuntos es de 36 pies o más. Fuente: Delaware Code Title 21, Ch. 45, sección 4503(c)."},"14":{"q":"En las carreteras de Delaware que NO forman parte del sistema interestatal ni del sistema primario de ayuda federal, ¿cuál es el peso máximo por eje sencillo?","options":["22,400 libras","20,000 libras","18,000 libras","25,000 libras"],"explanation":"En las carreteras estatales no interestatales, Delaware permite un peso por eje sencillo más alto, de 22,400 libras, en comparación con las 20,000 libras en la interestatal. Fuente: Delaware Code Title 21, Ch. 45, sección 4502(c)."},"15":{"q":"Delaware otorga una excepción de peso para camiones que transportan ciertos productos agrícolas o granos del estado. ¿Hasta qué peso bruto pueden operar dichos vehículos?","options":["90,000 libras","80,000 libras","100,000 libras","85,000 libras"],"explanation":"Delaware permite que los camiones que transportan frutas, verduras o granos básicos del estado alcancen hasta 90,000 libras (o la capacidad nominal de peso combinado bruto del fabricante, lo que sea menor). Fuente: Delaware Code Title 21, Ch. 45, sección 4502(c)."},"16":{"q":"La disposición de Delaware sobre el transporte de aves vivas incluye una tolerancia para tener en cuenta la precipitación y las variaciones en el tamaño de las aves. ¿Cuál es ese porcentaje de variación?","options":["3%","5%","10%","1%"],"explanation":"Los camiones que transportan aves vivas dentro de Delaware pueden operar hasta 90,000 libras con una variación del 3% por las diferencias de peso causadas por la precipitación y el tamaño de las aves. Fuente: Delaware Code Title 21, Ch. 45, sección 4502(c)."},"17":{"q":"En las carreteras de Delaware distintas a la interestatal y al sistema primario de ayuda federal, ¿cuál es la longitud máxima de un vehículo individual (no una combinación)?","options":["40 pies","45 pies","53 pies","35 pies"],"explanation":"En las carreteras no interestatales, un vehículo individual no puede exceder los 40 pies, y una combinación de vehículos no puede exceder los 60 pies. Fuente: Delaware Code Title 21, Ch. 45, sección 4502(b)."},"18":{"q":"En una combinación de tractocamión-semirremolque-remolque (doble) en Delaware, ¿cuál es la longitud máxima de cada remolque o semirremolque?","options":["29 pies","28 pies","33 pies","31 pies"],"explanation":"Cada remolque o semirremolque en una combinación de tractocamión-semirremolque-remolque está limitado a 29 pies, sin contar el tractocamión. Fuente: Delaware Code Title 21, Ch. 45, sección 4503(b)."},"19":{"q":"¿En qué punto un transporte sobredimensionado o con sobrepeso de Delaware se clasifica como 'Supercarga' (Superload), lo cual conlleva una tarifa mínima de permiso más alta?","options":["Longitud de 120 pies, ancho de 15 pies, altura de 15 pies, o peso bruto mayor a 120,000 libras","Cualquier carga de más de 90,000 libras de peso bruto","Cualquier carga más ancha de 10 pies","Longitud mayor a 75 pies o peso mayor a 100,000 libras"],"explanation":"Un transporte se clasifica como Supercarga (Superload) cuando la longitud alcanza los 120 pies, el ancho alcanza los 15 pies, la altura alcanza los 15 pies, o el peso bruto excede las 120,000 libras; la tarifa mínima del permiso de Supercarga es de $60.00. Fuente: preguntas frecuentes de permisos OSOW de DelDOT."},"20":{"q":"En Delaware, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Capacidad Nominal de Peso Bruto Vehicular (GVWR) de 26,001 libras o más, siempre que el GVWR de la unidad remolcada exceda las 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"El Manual del Conductor Comercial de Delaware (Versión 4.0, \"Tipos de CDL\") establece que se requiere un CDL Clase A para cualquier combinación de vehículos con un GVWR de 26,001 libras o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) exceda las 10,000 libras."},"21":{"q":"Según las normas de Delaware, un vehículo individual con un GVWR de 26,001 libras o más que no remolca una unidad de más de 10,000 libras, ¿qué clase de CDL requiere?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"El Manual del Conductor Comercial de Delaware define la Clase B como cualquier vehículo individual con un GVWR de 26,001 libras o más, o dicho vehículo remolcando un vehículo que no exceda las 10,000 libras de GVWR."},"22":{"q":"En Delaware, un vehículo con un GVWR menor a 26,001 libras que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que lleva materiales peligrosos con placas (placarded), ¿qué clase de CDL requiere?","options":["Clase A","Clase B","Clase C","No se requiere CDL"],"explanation":"Según el Manual del Conductor Comercial de Delaware, se requiere un CDL Clase C para un vehículo con un GVWR menor a 26,001 libras que está diseñado para transportar 16 o más personas incluido el conductor, o que se usa para transportar materiales peligrosos que requieren placas (placarding)."},"23":{"q":"En un CDL de Delaware, ¿qué código de endoso autoriza la operación de un vehículo cisterna (tank vehicle)?","options":["Código N","Código T","Código H","Código P"],"explanation":"El Manual del Conductor Comercial de Delaware enumera el endoso de Cisterna (Tanker) como código N. El endoso T es para Dobles/Triples, H es para Materiales Peligrosos (HazMat) y P es para Pasajeros."},"24":{"q":"¿Qué endoso de CDL de Delaware se requiere para arrastrar remolques dobles o triples?","options":["Endoso T","Endoso N","Endoso X","Endoso P"],"explanation":"El Manual del Conductor Comercial de Delaware enumera el endoso de Dobles/Triples como código T y exige aprobar un examen especial de conocimientos sobre los problemas asociados con arrastrar múltiples remolques."},"25":{"q":"Según el Manual del Conductor Comercial de Delaware, se requiere un endoso de Vehículo Cisterna (N) cuando el vehículo está diseñado para transportar líquido o gas en un tanque con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de al menos cuántos galones?","options":["500 galones","750 galones","1,000 galones","1,500 galones"],"explanation":"El Manual del Conductor Comercial de Delaware establece que el endoso de Vehículo Cisterna (N) aplica a tanques que tienen una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más."},"26":{"q":"En Delaware, ¿cuál es la edad mínima para obtener un CDL para conducir de forma intraestatal (solo dentro de Delaware)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Los Requisitos Básicos del CDL del Manual del Conductor Comercial de Delaware establecen que un solicitante debe tener 18 años de edad con 1 año de experiencia de conducción para conducir de forma intraestatal."},"27":{"q":"Según los requisitos básicos del CDL de Delaware, ¿qué edad mínima se necesita para conducir en el comercio interestatal o para transportar materiales peligrosos?","options":["18 años","19 años","20 años","21 años"],"explanation":"El Manual del Conductor Comercial de Delaware exige que un solicitante tenga 21 años de edad con al menos 1 año de experiencia de conducción para conducir en el comercio interestatal o para transportar materiales peligrosos."},"28":{"q":"Después de aprobar los exámenes de conocimientos, ¿por cuánto tiempo debe el titular de un Permiso de Aprendiz Comercial (CLP) de Delaware conservar el CLP antes de que se le permita realizar el examen de habilidades del CDL?","options":["Un mínimo de 14 días completos","Un mínimo de 10 días completos","Un mínimo de 7 días completos","Un mínimo de 30 días completos"],"explanation":"El Manual del Conductor Comercial de Delaware establece que debe conservar su CLP por un mínimo de 14 días completos antes de poder realizar el examen de habilidades del CDL, lo que coincide con el requisito federal 49 CFR 383."},"29":{"q":"Al conducir con un Permiso de Aprendiz Comercial (CLP) de Delaware, ¿por quién debe estar acompañado el titular?","options":["Cualquier conductor con licencia de 18 años o más","Un conductor con licencia CDL calificado en el mismo tipo de CMV","Únicamente un examinador certificado del DMV","Nadie; el CLP permite conducir solo"],"explanation":"El Manual del Conductor Comercial de Delaware establece que un CLP le permite conducir un CMV acompañado de otro conductor con licencia CDL, y solo puede conducir el tipo de vehículo para el cual se examinó con un conductor CDL calificado en el mismo tipo de CMV."},"30":{"q":"Antes de que se emita un CDL de Delaware con un endoso de materiales peligrosos (H), ¿qué debe completar primero un solicitante?","options":["Un curso de manejo defensivo en el DMV","Un período de espera de 30 días después del examen de habilidades","Una evaluación de amenazas de seguridad de la TSA que incluye toma de huellas dactilares","Un examen de conducción aparte en un vehículo con placas (placarded)"],"explanation":"El Manual del Conductor Comercial de Delaware establece que no se puede emitir ningún CDL con endoso de HazMat a menos que el solicitante haya pasado primero por la evaluación de amenazas de seguridad de la TSA (incluyendo la toma de huellas dactilares y la verificación de ciudadanía/presencia legal) y haya obtenido la autorización de la TSA."},"31":{"q":"Según la regla federal de Capacitación para Conductores Principiantes (ELDT) aplicada en Delaware, la capacitación debe ser proporcionada por una escuela incluida en cuál registro?","options":["La lista de Escuelas Aprobadas del DMV de Delaware","El Directorio de Instructores de AAMVA","El Registro de Proveedores de Capacitación (TPR) de la FMCSA","El Registro de Capacitadores Certificados de la TSA"],"explanation":"La página de ELDT del DMV de Delaware establece que la capacitación para conductores principiantes debe completarse a través de un proveedor registrado ante la FMCSA que figure en el Registro de Proveedores de Capacitación (TPR) de la FMCSA (tpr.fmcsa.dot.gov) antes de que el solicitante pueda realizar el examen de habilidades del CDL."},"32":{"q":"¿Para cuál de los siguientes exige Delaware la ELDT (Capacitación para Conductores Principiantes) antes de poder realizar el examen de habilidades/conocimientos?","options":["Agregar un endoso de Cisterna (N)","Agregar un endoso de Dobles/Triples (T)","Renovar un CDL existente","Obtener un CDL Clase A o Clase B por primera vez"],"explanation":"Según la página de ELDT del DMV de Delaware (vigente desde el 7 de febrero de 2022), la ELDT se requiere para solicitantes de Clase A o B por primera vez, ascensos a una clase superior y los endosos S, P y H. No se requiere para los endosos N o T ni para las renovaciones."},"33":{"q":"Delaware exige que los titulares de CDL autocertifiquen su tipo de conducción. ¿Cuántas categorías de autocertificación hay?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"El Manual del Conductor Comercial de Delaware establece que los titulares de CDL deben autocertificar un estado de conducción de interestatal no exceptuado, intraestatal no exceptuado, interestatal exceptuado o intraestatal exceptuado: cuatro categorías."},"34":{"q":"Un solicitante de CDL de Delaware que conduce un CMV en el comercio interestatal y está sujeto a las reglas federales de calificación física, ¿en qué categoría de autocertificación médica se certifica?","options":["Interestatal no exceptuado","Interestatal exceptuado","Intraestatal no exceptuado","Intraestatal exceptuado"],"explanation":"El Manual del Conductor Comercial de Delaware explica que los titulares de CDL que conducen CMV en el comercio interestatal y deben cumplir con el requisito federal del certificado médico son conductores de comercio interestatal no exceptuado."},"35":{"q":"Cuando se emite un CLP de Delaware con un endoso de Pasajeros (P), ¿qué restricción debe llevar también?","options":["Una restricción 'K' Solo Intraestatal","Una restricción 'L' Sin frenos de aire","Una restricción 'P' Sin pasajeros en un autobús CMV","Una restricción 'E' Sin transmisión manual"],"explanation":"El Manual del Conductor Comercial de Delaware señala que si se emite un CLP con un endoso de Pasajeros (P) o de Autobús Escolar (S), también debe contener una restricción 'P' – Sin pasajeros en un autobús CMV (permitiendo solo a bordo al personal especificado)."},"36":{"q":"Si se emite un CLP de Delaware con un endoso de Cisterna (N), ¿qué restricción adicional se le impone?","options":["'X' – Sin carga en un vehículo cisterna CMV","'Z' – Sin CMV equipado con frenos de aire completos","'V' – Variación médica","'O' – Sin CMV tractocamión-remolque"],"explanation":"El Manual del Conductor Comercial de Delaware establece que un CLP emitido con un endoso de Cisterna (N) también debe contener una restricción 'X' – Sin carga en un vehículo cisterna CMV, lo que significa que el titular solo puede operar un vehículo cisterna vacío y purgado."},"37":{"q":"¿Qué documentación exige el DMV de Delaware que presente un solicitante con respecto a la residencia en Delaware al solicitar una licencia?","options":["Un comprobante de residencia en Delaware","Tres comprobantes de residencia en Delaware","Únicamente una declaración jurada de residencia notariada","Dos comprobantes de residencia en Delaware"],"explanation":"El DMV de Delaware exige que los solicitantes proporcionen un comprobante de identidad (un documento primario y uno secundario), un número de Seguro Social si es elegible, y dos comprobantes de residencia en Delaware; los no ciudadanos de EE. UU. también deben mostrar comprobante de presencia legal (requisitos de documentos para Licencia de Conducir/Identificación del DMV de Delaware)."},"38":{"q":"Según las normas de Delaware, ¿qué se le exige a una persona que desea conducir un autobús escolar?","options":["Únicamente un CDL Clase C sin endosos","Un CDL con un endoso de Pasajeros (P) y uno de Autobús Escolar (S), además de los requisitos del Departamento de Educación","Una licencia estándar Clase D con una calcomanía de autobús escolar","Un endoso de Cisterna (N) y una verificación de antecedentes de la TSA"],"explanation":"El Manual del Conductor Comercial de Delaware establece que todos los conductores de autobús escolar de Delaware deben tener un CDL y cumplir con los requisitos adicionales de capacitación y médicos del Departamento de Educación de Delaware; luego el DMV emite un CDL con endosos P y S (con una restricción M o N según la clase del vehículo)."},"39":{"q":"Delaware ofrece una credencial especial que no es CDL, bajo las disposiciones federales de exención de CDL, ¿para cuál grupo de conductores que operan un CMV?","options":["Camioneros interestatales de larga distancia","Operadores de cisternas de HazMat","Conductores de autobuses chárter","Agricultores y bomberos"],"explanation":"El Manual del Conductor Comercial de Delaware establece que Delaware tiene un Non-CDL especial para identificar a agricultores y bomberos que operan CMV bajo las disposiciones de exención de CDL; este Non-CDL no puede usarse en el comercio interestatal ni en situaciones de alquiler (for-hire)."},"40":{"q":"En Delaware, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.02 por ciento","0.04 por ciento","0.08 por ciento","0.10 por ciento"],"explanation":"Delaware considera ilegal operar un CMV con un BAC de 0.04 por ciento o más, la mitad del límite de 0.08 para vehículos privados. Fuente: Manual del CDL de Delaware Sección 1.3.2; 21 Del. C. Sección 2614."},"41":{"q":"Según la ley de consentimiento implícito de Delaware, cuando una persona opera un vehículo motorizado comercial en el estado, se considera que ha dado su consentimiento para qué?","options":["Una inspección de la carga del vehículo","Una prueba de concentración de alcohol","Un examen de aptitud médica","La divulgación de sus registros de empleo"],"explanation":"Al operar un CMV en Delaware, se considera que un conductor ha consentido a la prueba de alcohol (química). Fuente: Manual del CDL de Delaware Sección 1.3.2; 21 Del. C. Sección 2614 (consentimiento implícito para conductores de CMV)."},"42":{"q":"¿Por cuánto tiempo se descalifica a un titular de CDL de Delaware por una PRIMERA infracción grave, como conducir un CMV con un BAC de 0.04 o más, cuando no transporta materiales peligrosos?","options":["60 días","120 días","1 año","3 años"],"explanation":"Una primera infracción mayor resulta en una descalificación del CDL de 1 año en Delaware. Fuente: Manual del CDL de Delaware Sección 1.3.2; 21 Del. C. Sección 2612 (estándar federal 49 CFR 383.51 aplicado por el estado)."},"43":{"q":"En Delaware, la descalificación por una primera infracción grave aumenta a tres años cuando la infracción ocurre mientras el conductor opera un CMV que está haciendo qué?","options":["Con placas (placarded) de materiales peligrosos","Transportando pasajeros por alquiler","Arrastrando un remolque doble","Cruzando líneas estatales"],"explanation":"Una primera infracción mayor cometida mientras se opera un CMV con placas (placarded) de materiales peligrosos eleva la descalificación de 1 año a 3 años. Fuente: Manual del CDL de Delaware Sección 1.3.2; 49 CFR 383.51."},"44":{"q":"¿Cuál es el período de descalificación del CDL de Delaware por una SEGUNDA infracción grave (por ejemplo, una segunda condena por conducir bajo la influencia)?","options":["3 años","10 años","De por vida","5 años"],"explanation":"Una segunda infracción mayor en cualquier vehículo resulta en una descalificación del CDL de por vida en Delaware. Fuente: Manual del CDL de Delaware Sección 1.3.2; 21 Del. C. Sección 2612; 49 CFR 383.51."},"45":{"q":"Según las reglas del CDL de Delaware, negarse a someterse a una prueba de alcohol/química requerida mientras se opera un CMV, ¿se trata como qué tipo de infracción?","options":["Una infracción de tránsito grave","Una infracción mayor","Una infracción de fuera de servicio (out-of-service)","Una infracción no reportable"],"explanation":"Negarse a someterse a la prueba de alcohol en la sangre figura entre las infracciones mayores, con al menos 1 año de descalificación por una primera infracción. Fuente: Manual del CDL de Delaware Sección 1.3.2; 21 Del. C. Sección 2614."},"46":{"q":"Según la advertencia de consentimiento implícito de Delaware para conductores de CMV, negarse a la prueba de alcohol resulta en ser puesto fuera de servicio de inmediato por cuánto tiempo, además de la descalificación?","options":["8 horas","12 horas","24 horas","48 horas"],"explanation":"La ley de Delaware exige que el oficial advierta al conductor que una negativa resulta en ser puesto fuera de servicio de inmediato por 24 horas y descalificado por al menos 1 año. Fuente: 21 Del. C. Sección 2614."},"47":{"q":"A un conductor de CMV de Delaware se le detecta un BAC de 0.02 (una cantidad medible de alcohol por debajo de 0.04). ¿Cuál es la consecuencia requerida?","options":["Una descalificación del CDL de 60 días","Ser puesto fuera de servicio por 24 horas","Una descalificación del CDL de 1 año","Descalificación del CDL de por vida"],"explanation":"Cualquier cantidad detectable de alcohol por debajo de 0.04 (una cantidad medible de 0.02 a menos de 0.04) requiere que el conductor sea puesto fuera de servicio por 24 horas. Fuente: Manual del CDL de Delaware Sección 1.3.2; 21 Del. C. Sección 2614."},"48":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE según las reglas del CDL de Delaware?","options":["Conducir un CMV con un BAC de 0.04","Exceso de velocidad de 15 mph o más por encima del límite","Abandonar el lugar de un accidente","Violar una orden de fuera de servicio (out-of-service)"],"explanation":"El exceso de velocidad (15 mph o más por encima del límite señalizado) es una infracción de tránsito grave. Los demás elementos enumerados son infracciones mayores o de fuera de servicio. Fuente: Manual del CDL de Delaware Sección 1.3.3."},"49":{"q":"En Delaware, ¿por cuánto tiempo se descalifica un CDL por ser condenado por DOS infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de cualquier período de tres años resultan en una descalificación del CDL de 60 días. Fuente: Manual del CDL de Delaware Sección 1.3.3; 49 CFR 383.51."},"50":{"q":"¿Cuál es el período de descalificación del CDL de Delaware por ser condenado por TRES o más infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["60 días","90 días","120 días","180 días"],"explanation":"Tres o más infracciones de tránsito graves dentro de cualquier período de tres años resultan en una descalificación del CDL de 120 días. Fuente: Manual del CDL de Delaware Sección 1.3.3; 49 CFR 383.51."},"51":{"q":"¿Cuál de estas es una infracción de tránsito grave según las reglas del CDL de Delaware, en lugar de una infracción mayor?","options":["Seguir a un vehículo demasiado de cerca","Usar un CMV para cometer un delito grave","Causar una muerte por operación negligente de un CMV","Conducir un CMV bajo la influencia de una sustancia controlada"],"explanation":"Seguir a un vehículo demasiado de cerca es una infracción de tránsito grave. Las otras tres son infracciones mayores. Fuente: Manual del CDL de Delaware Sección 1.3.3 (graves) y Sección 1.3.2 (mayores)."},"52":{"q":"Enviar mensajes de texto o usar un teléfono móvil de mano mientras se opera un CMV se trata, según las reglas del CDL de Delaware, ¿como qué tipo de infracción?","options":["Una infracción mayor","Una infracción de tránsito grave","Una violación de orden de fuera de servicio (out-of-service)","Una infracción de cruce ferroviario"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se opera un CMV es una infracción de tránsito grave y cuenta para los umbrales de descalificación de 60 días/120 días. Fuente: Manual del CDL de Delaware Sección 1.3.3 y la sección de mensajes de texto/teléfono; 49 CFR 383.51."},"53":{"q":"Según las reglas del CDL de Delaware/federales, ¿después de cuántas condenas por usar un teléfono móvil de mano mientras se opera un CMV (dentro de 3 años) se descalifica un CDL por 60 días?","options":["Una condena","Dos o más condenas","Cuatro condenas","Cinco condenas"],"explanation":"Dos o más condenas de una ley de teléfono de mano mientras se opera un CMV dentro de 3 años conllevan una descalificación de 60 días (120 días por tres o más). Fuente: sección de teléfono móvil de mano del Manual del CDL de Delaware; 49 CFR 383.51."},"54":{"q":"¿Cuál es la máxima sanción civil federal que puede enfrentar un conductor de CMV por una infracción de enviar mensajes de texto mientras conduce, según lo establecido en el Manual del CDL de Delaware?","options":["Hasta $750","Hasta $1,500","Hasta $2,750","Hasta $11,000"],"explanation":"El Manual del CDL de Delaware establece que los conductores están sujetos a sanciones civiles de hasta $2,750 por infracciones de mensajes de texto/teléfono de mano (los empleadores hasta $11,000). Fuente: sección de mensajes de texto y teléfono móvil de mano del Manual del CDL de Delaware."},"55":{"q":"¿Por cuánto tiempo se descalifica un CDL de Delaware por una PRIMERA condena de una infracción de cruce a nivel ferroviario-carretero en un CMV?","options":["No menos de 30 días","No menos de 60 días","No menos de 120 días","No menos de 1 año"],"explanation":"Una primera infracción de cruce a nivel ferroviario-carretero conlleva una descalificación de no menos de 60 días. Fuente: Manual del CDL de Delaware Sección 1.3.5; 49 CFR 383.51."},"56":{"q":"En Delaware, una SEGUNDA infracción de cruce a nivel ferroviario-carretero en un CMV dentro de tres años descalifica el CDL por al menos cuánto tiempo?","options":["60 días","120 días","180 días","1 año"],"explanation":"Una segunda infracción de cruce ferroviario dentro de cualquier período de tres años resulta en una descalificación de no menos de 120 días. Fuente: Manual del CDL de Delaware Sección 1.3.5; 49 CFR 383.51."},"57":{"q":"Un conductor de CMV de Delaware comete una TERCERA infracción de cruce a nivel ferroviario-carretero dentro de tres años. El CDL se descalifica por al menos cuánto tiempo?","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera infracción de cruce ferroviario dentro de cualquier período de tres años resulta en una descalificación de no menos de 1 año. Fuente: Manual del CDL de Delaware Sección 1.3.5; 49 CFR 383.51."},"58":{"q":"Según las reglas del CDL de Delaware, ¿cuál es el rango de descalificación por una PRIMERA condena de violar una orden de fuera de servicio (out-of-service) en un CMV (sin transportar materiales peligrosos)?","options":["No menos de 30 días ni más de 90 días","No menos de 180 días ni más de 1 año","No menos de 1 año ni más de 2 años","No menos de 3 años ni más de 5 años"],"explanation":"Una primera violación de orden de fuera de servicio conlleva una descalificación de no menos de 180 días y no más de 1 año. Fuente: sección de infracciones descalificantes MCSIA del Manual del CDL de Delaware; 49 CFR 383.51."},"59":{"q":"Conforme a la ley \"Move Over\" (Cámbiate de carril) de Delaware, cuando te aproximas a un vehículo detenido de DelDOT, de la policía, de remolque o de emergencia que muestra luces de advertencia en una autopista con cuatro o más carriles en tu dirección, ¿qué debes hacer primero?","options":["Cambiarte a un carril que no esté contiguo al vehículo detenido, si es seguro hacerlo","Detenerte por completo hasta que el vehículo detenido abandone el acotamiento","Pasarte al acotamiento y rebasar a no más de 10 mph","Mantener tu carril y tocar el claxon de forma continua mientras rebasas"],"explanation":"El Título 21 § 4134(b) de Delaware exige que los conductores en una vía con al menos cuatro carriles en la misma dirección cedan el paso cambiándose a un carril que no esté contiguo al vehículo detenido de emergencia/DelDOT/remolque/servicios públicos cuando sea seguro. Fuente: 21 Del. C. § 4134."},"60":{"q":"Conforme a la ley \"Move Over\" de Delaware, si no puedes cambiarte de carril de forma segura para alejarte de un vehículo de emergencia detenido, ¿qué reducción de velocidad se requiere donde el límite señalizado es de 50 mph o más?","options":["Reducir a una velocidad segura de al menos 20 mph por debajo del límite de velocidad señalizado","Reducir a una velocidad segura de al menos 10 mph por debajo del límite de velocidad señalizado","Reducir exactamente a la mitad del límite de velocidad señalizado","Reducir a no más de 25 mph sin importar el límite señalizado"],"explanation":"El 21 Del. C. § 4134(b) exige que, cuando no sea posible cambiar de carril, el conductor reduzca a una velocidad segura de al menos 20 mph menos que el límite señalizado donde el límite es de 50 mph o más. Fuente: 21 Del. C. § 4134."},"61":{"q":"Cuando un autobús escolar de Delaware está detenido en una carretera de dos carriles sin división con sus luces rojas intermitentes encendidas, ¿qué conductores deben detenerse?","options":["Los conductores que se aproximan tanto de frente como por detrás","Solo los conductores que se aproximan por detrás (en la misma dirección que el autobús)","Solo los conductores que se aproximan de frente (en sentido contrario)","Solo los conductores que están a menos de 20 pies del autobús"],"explanation":"El Título 21 § 4166 de Delaware exige que el conductor de cualquier vehículo que se aproxime a un autobús escolar detenido, ya sea de frente o por detrás, se detenga antes de rebasar el autobús cuando sus luces rojas de alto estén activadas. Fuente: 21 Del. C. § 4166."},"62":{"q":"En una vía (o vías) de Delaware con cuatro o más carriles, ¿qué conductor que se aproxima NO está obligado a detenerse ante un autobús escolar que muestra luces rojas intermitentes?","options":["El conductor que se aproxima de frente (en sentido contrario)","El conductor que se aproxima por detrás (en la misma dirección que el autobús)","Tanto el conductor de frente como el de atrás están exentos","Ningún conductor está exento; ambos siempre deben detenerse"],"explanation":"El 21 Del. C. § 4166 dispone que en una vía o vías con 4 o más carriles, el conductor que se aproxima de frente (sentido contrario) no necesita detenerse; el conductor que se aproxima por detrás sí debe detenerse. Fuente: 21 Del. C. § 4166."},"63":{"q":"Después de detenerse ante un autobús escolar de Delaware con las luces rojas intermitentes encendidas, ¿cuánto tiempo debe permanecer detenido el conductor?","options":["Hasta que el autobús comience a moverse o deje de tener sus luces rojas de alto activadas","Por un mínimo fijo de 30 segundos","Hasta que el conductor del autobús indique con la mano que el tránsito puede avanzar","Hasta que todos los niños estén al menos a 100 pies del autobús"],"explanation":"El 21 Del. C. § 4166 exige que el conductor permanezca detenido hasta que el autobús comience a moverse o deje de mostrar sus luces rojas de alto activadas. Fuente: 21 Del. C. § 4166."},"64":{"q":"Según el manual de CDL de Delaware, cuando un vehículo con materiales peligrosos rotulado debe detenerse en un cruce de ferrocarril que no tiene línea de alto pintada, ¿dónde debe detenerse con respecto al riel más cercano?","options":["A no menos de 15 pies y no más de 50 pies del riel más cercano","A no menos de 10 pies y no más de 25 pies del riel más cercano","A no menos de 25 pies y no más de 75 pies del riel más cercano","A no menos de 5 pies y no más de 35 pies del riel más cercano"],"explanation":"El Manual de CDL de Delaware (Sección 2.15) establece que los vehículos obligados a detenerse deben hacerlo a no menos de 15 pies y no más de 50 pies del riel más cercano de la vía más cercana. Fuente: Manual de CDL de Delaware, Sec. 2.15."},"65":{"q":"Según el manual de CDL de Delaware, mientras cualquier parte de tu vehículo comercial está cruzando las vías del ferrocarril, ¿qué NO debes hacer de lo siguiente?","options":["Cambiar de velocidad (engranaje) mientras cruzas las vías","Mantener ambas manos en el volante","Cruzar solo después de confirmar que todas las vías están despejadas","Usar un carril de salida para detenerte cuando haya uno disponible"],"explanation":"El Manual de CDL de Delaware (Sección 2.15) indica a los conductores que no cambien de velocidad (engranaje) mientras cruzan las vías del ferrocarril, para evitar quedarse parados sobre el cruce. Fuente: Manual de CDL de Delaware, Sec. 2.15."},"66":{"q":"Según el manual de CDL de Delaware, si tu vehículo comercial debe detenerse en una autopista de un solo sentido o dividida, ¿a qué distancias debes colocar tus tres dispositivos de advertencia?","options":["A 10 pies, 100 pies y 200 pies en dirección al tránsito que se aproxima","A 10 pies, 50 pies y 150 pies en dirección al tránsito que se aproxima","A 25 pies, 100 pies y 250 pies en dirección al tránsito que se aproxima","A 10 pies, 100 pies y 100 pies (uno adelante y uno atrás)"],"explanation":"El Manual de CDL de Delaware (Sección 2.5) indica que en una autopista de un solo sentido o dividida los dispositivos de advertencia se coloquen a 10, 100 y 200 pies en dirección al tránsito que se aproxima. Fuente: Manual de CDL de Delaware, Sec. 2.5."},"67":{"q":"Según el manual de CDL de Delaware, en un camino de dos carriles sin división que lleva tránsito en ambos sentidos, ¿dónde colocas los dispositivos de advertencia después de detenerte?","options":["A menos de 10 pies del vehículo, y a 100 pies por detrás y 100 pies por delante de este","A 200 pies por detrás y 200 pies por delante, sin ninguno cerca del vehículo","Solo un dispositivo a 100 pies por detrás del vehículo","A 10 pies, 100 pies y 200 pies, todos por detrás del vehículo"],"explanation":"El Manual de CDL de Delaware (Sección 2.5) indica colocar un dispositivo a menos de 10 pies de la esquina delantera o trasera y dispositivos a 100 pies por detrás y 100 pies por delante del vehículo en un camino de dos carriles/sin división. Fuente: Manual de CDL de Delaware, Sec. 2.5."},"68":{"q":"Según el manual de CDL de Delaware, ¿dentro de cuántos minutos después de detenerte en la vía o el acotamiento debes colocar tus dispositivos de advertencia de emergencia?","options":["10 minutos","5 minutos","15 minutos","30 minutos"],"explanation":"El Manual de CDL de Delaware (Sección 2.5) exige que los dispositivos de advertencia de emergencia se coloquen dentro de los 10 minutos posteriores a detenerse en una vía o acotamiento. Fuente: Manual de CDL de Delaware, Sec. 2.5."},"69":{"q":"Según el manual de CDL de Delaware, ¿qué equipo de advertencia debe llevar un vehículo comercial para usarlo cuando esté estacionado o averiado?","options":["Tres triángulos reflectantes, o al menos 6 bengalas (fusees), o 3 antorchas de combustible líquido","Dos triángulos reflectantes y una bandera roja","Solo cuatro triángulos reflectantes","Un triángulo reflectante y una baliza a pilas"],"explanation":"El Manual de CDL de Delaware enumera como equipo de emergencia obligatorio tres triángulos reflectantes, o al menos 6 bengalas (fusees), o 3 antorchas de combustible líquido. Fuente: Manual de CDL de Delaware, Sec. 2.1 (inspección)."},"70":{"q":"Según el manual de CDL de Delaware, si una colina o una curva impide que los conductores que vienen detrás vean tu vehículo detenido dentro de los 500 pies, ¿qué debes hacer con tu triángulo de advertencia más alejado hacia atrás?","options":["Moverlo más atrás por el camino, más allá del obstáculo, para que se proporcione la advertencia","Dejarlo a los 100 pies estándar y agregar un cuarto triángulo","Colocarlo sobre el cofre del vehículo para aumentar su visibilidad","Quitarlo y depender únicamente de las luces intermitentes de emergencia"],"explanation":"El Manual de CDL de Delaware (Sección 2.5) indica que cuando una colina o una curva bloquea la vista dentro de los 500 pies, hay que mover el triángulo más alejado hacia atrás, más allá del obstáculo, para que los conductores que vienen detrás reciban la advertencia. Fuente: Manual de CDL de Delaware, Sec. 2.5."},"71":{"q":"Conforme al Título 21 de Delaware, ¿cuál es el límite de velocidad legal en una vía de dos carriles donde no haya otro límite señalizado?","options":["50 mph","55 mph","45 mph","60 mph"],"explanation":"El Título 21 § 4169 de Delaware fija 50 mph en vías de 2 carriles (y 55 mph en vías de 4 carriles y divididas) a menos que se señalice lo contrario. Fuente: 21 Del. C. § 4169."},"72":{"q":"Conforme al Título 21 de Delaware, ¿cuál es el límite de velocidad legal en una vía de cuatro carriles o dividida donde no haya otro límite señalizado?","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"El Título 21 § 4169 de Delaware fija 55 mph en vías de 4 carriles y divididas a menos que se señalice lo contrario. Fuente: 21 Del. C. § 4169."},"73":{"q":"Conforme al Título 21 de Delaware, ¿cuál es el límite de velocidad en un distrito comercial o residencial a menos que se señalice lo contrario?","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"El Título 21 § 4169 de Delaware fija 25 mph en distritos comerciales y 25 mph en distritos residenciales a menos que se señalice lo contrario. Fuente: 21 Del. C. § 4169."},"74":{"q":"¿En qué vía de Delaware el Departamento de Transporte ha designado un límite máximo de velocidad de 65 mph entre Red Lion Creek y el río Appoquinimink?","options":["Ruta Estatal 1 de Delaware","Interestatal 495","Ruta 13 de EE. UU.","Interestatal 295"],"explanation":"El Título 21 § 4169 de Delaware ordena a DelDOT designar un máximo de 65 mph en la porción de la Ruta Estatal 1 entre Red Lion Creek y el río Appoquinimink (excluyendo la zona de la caseta de peaje). Fuente: 21 Del. C. § 4169."},"75":{"q":"Conforme a la ley de restricción de circulación por carril de Delaware (§ 4114A), ¿qué vehículos pueden circular en general solo por el carril derecho en la Ruta Estatal 1 y la Interestatal 495?","options":["Un vehículo con un peso bruto vehicular nominal (GVWR) de más de 26,000 libras","Un vehículo con un peso bruto vehicular nominal (GVWR) de más de 10,000 libras","Cualquier vehículo que remolque un tráiler de cualquier tamaño","Un vehículo con tres o más ejes sin importar el peso"],"explanation":"El Título 21 § 4114A de Delaware restringe a los vehículos con un GVWR de más de 26,000 libras al carril derecho en las porciones de acceso controlado/exprés de la SR 1 y la I-495, con excepciones limitadas. Fuente: 21 Del. C. § 4114A."},"76":{"q":"Conforme al § 4114A de Delaware, ¿cuándo puede un vehículo sujeto a la restricción del carril derecho usar legalmente un carril izquierdo en la SR 1 o la I-495?","options":["Al alcanzar y rebasar a otro vehículo, al entrar o salir de la vía, o cuando las condiciones del tránsito lo requieran","Solo entre la medianoche y las 6:00 a. m.","Solo cuando el límite de velocidad señalizado sea de 35 mph o menos","Nunca, bajo ninguna circunstancia"],"explanation":"El Título 21 § 4114A de Delaware permite que el vehículo pesado use un carril izquierdo para rebasar, entrar/salir de la vía, emergencias, obstrucciones, condiciones del tránsito o para cumplir con otra ley. Fuente: 21 Del. C. § 4114A."},"77":{"q":"Conforme a la ley de Delaware, ¿dónde debe conducirse un vehículo que se mueve más despacio que la velocidad normal del tránsito, salvo cuando rebasa o se prepara para una vuelta a la izquierda?","options":["En el carril derecho disponible para el tránsito, o tan cerca como sea posible del borde o la guarnición del lado derecho","En el carril central de cualquier vía de varios carriles","En el carril que tenga menos vehículos","En el carril izquierdo, dejando el carril derecho libre para el tránsito que se incorpora"],"explanation":"El Título 21 § 4114 de Delaware exige que un vehículo que circula más despacio que el tránsito normal se mantenga en el carril derecho o tan cerca como sea posible del borde/la guarnición del lado derecho, salvo cuando rebasa o se prepara para una vuelta a la izquierda. Fuente: 21 Del. C. § 4114."},"78":{"q":"Según el manual de CDL de Delaware, una infracción en un cruce a nivel de ferrocarril y carretera mientras se opera un CMV resulta en una descalificación de la CDL de al menos cuánto tiempo por una primera infracción?","options":["60 días","30 días","120 días","1 año"],"explanation":"El Manual de CDL de Delaware (Sección 1.3.5) establece que una infracción en un cruce a nivel de ferrocarril y carretera descalifica la CDL por al menos 60 días (primera), 120 días (segunda dentro de 3 años) y 1 año (tercera dentro de 3 años). Fuente: Manual de CDL de Delaware, Sec. 1.3.5."},"79":{"q":"¿Qué agencia de Delaware emite las Licencias de Conducir Comerciales (CDL)?","options":["La División de Vehículos Motorizados (DMV) de Delaware, parte de DelDOT","La Oficina de Transportistas Comerciales de la Policía Estatal de Delaware","La oficina regional de la Federal Motor Carrier Safety Administration","La Oficina del Secretario de Estado de Delaware"],"explanation":"En Delaware, las CDL son emitidas por la División de Vehículos Motorizados (DMV) de Delaware, que opera bajo el Departamento de Transporte de Delaware. La FMCSA establece los estándares federales, pero no emite la licencia. Fuente: páginas de CDL del Delaware DMV; Título 21, Capítulo 26 (Uniform Commercial Driver License Act)."},"80":{"q":"¿Cómo se administran los exámenes de conocimientos (escritos) de la CDL de Delaware?","options":["Sin cita previa en cualquier instalación del DMV, sin necesidad de agendar cita","Solo con cita previa en la sede de Dover","En línea desde casa con un supervisor remoto","Solo en un único centro de pruebas externo aprobado"],"explanation":"El Delaware DMV indica que todos los exámenes de conocimientos de la CDL son únicamente sin cita previa y pueden completarse en cualquier instalación de la división (DMV). El requisito de cita aplica al examen de habilidades, no al examen de conocimientos. Fuente: página web de CDL del Delaware DMV."},"81":{"q":"¿Cuánto tiempo debe conservarse un Permiso de Aprendiz Comercial (CLP) de Delaware antes de que el titular pueda presentar el examen de habilidades de la CDL?","options":["Un mínimo de 14 days después de la emisión inicial","Un mínimo de 30 días después de la emisión inicial","Un mínimo de 10 días después de la emisión inicial","Un mínimo de 7 días después de la emisión inicial"],"explanation":"Un titular de un CLP no es elegible para presentar el examen de inspección previa al viaje, de control básico o de habilidades en carretera de la CDL hasta que el permiso se haya conservado por un mínimo de 14 days después de la emisión inicial. Esta es la retención federal de 14 días adoptada por Delaware. Fuente: página web de CDL del Delaware DMV; 49 CFR 383.25 según lo adoptado bajo el Título 21 Cap. 26."},"82":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Delaware?","options":["Un (1) año, y puede renovarse una vez durante ese tiempo","180 días, sin renovación permitida","Dos (2) años, renovable anualmente","Seis (6) meses, renovable dos veces"],"explanation":"Un CLP de Delaware es válido por un (1) año y no puede emitirse ni extenderse por un período que exceda un año; puede renovarse una vez durante ese período. Fuente: página web de CDL del Delaware DMV; Título 21 § 2608."},"83":{"q":"¿En qué tres partes se divide el examen de habilidades de la CDL de Delaware?","options":["Inspección previa al viaje del vehículo, habilidades de control básico y conducción en carretera","Examen escrito, examen de la vista y prueba de manejo","Solo enganche, frenado y reversa","Capacitación teórica, manejo tras el volante y examen escrito final"],"explanation":"El examen de habilidades de la CDL consta de tres partes: el examen de inspección previa al viaje del vehículo, el examen de habilidades de control básico y el examen de conducción en carretera. Delaware modernizó estos protocolos con vigencia a partir del 26 de febrero de 2025. Fuente: página web de CDL del Delaware DMV; 49 CFR 383.113."},"84":{"q":"¿Qué debe completar un conductor principiante antes de presentar el examen de habilidades de la CDL de Delaware para una credencial de Clase A, Clase B, Pasajeros (P) o Autobús Escolar (S)?","options":["La Capacitación de Conductores Principiantes (ELDT) exigida a nivel federal de un proveedor registrado","Un aprendizaje de 30 días registrado con el DMV","Un curso de manejo defensivo aprobado por la Policía Estatal de Delaware","Solo el examen escrito de conocimientos generales"],"explanation":"Con vigencia a partir del 7 de febrero de 2022, ningún operador principiante puede presentar el examen de habilidades de la CDL para una Clase A, Clase B, endoso P o endoso S a menos que haya completado la ELDT teórica y tras el volante obligatoria de un proveedor que figure en el FMCSA Training Provider Registry. Fuente: página de ELDT del Delaware DMV; 49 CFR Part 380."},"85":{"q":"¿Cuáles son las cuatro categorías de autocertificación que un titular de CDL/CLP de Delaware puede declarar?","options":["Interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado, intraestatal exceptuado","Clase A, Clase B, Clase C y Clase D","HazMat, pasajeros, cisterna y dobles/triples","De alquiler, privado, exento y gubernamental"],"explanation":"Todo titular de CDL/CLP de Delaware debe autocertificarse en una de cuatro categorías: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado o intraestatal exceptuado. Fuente: Guía de Categorías de la Declaración de Autocertificación del Delaware DMV; 49 CFR 383.71."},"86":{"q":"¿Qué categoría de autocertificación exige que el conductor presente y mantenga en archivo un certificado vigente del examinador médico del DOT con el Delaware DMV?","options":["Interestatal no exceptuado","Interestatal exceptuado","Intraestatal exceptuado","Ninguna categoría necesita presentar uno"],"explanation":"Un conductor que se autocertifica como interestatal no exceptuado debe proporcionar y mantener una copia del certificado del examinador médico federal con el Delaware DMV. Las categorías exceptuadas no están obligadas a presentar un certificado médico federal. Fuente: Guía de Categorías de Autocertificación del Delaware DMV; 49 CFR 383.71."},"87":{"q":"¿Dónde debe un solicitante de CDL de Delaware obtener el examen físico del DOT que respalda el certificado del examinador médico?","options":["De un examinador médico que figure en el FMCSA National Registry of Certified Medical Examiners","De cualquier médico o quiropráctico con licencia que el conductor elija","Solo de una clínica aprobada por la Policía Estatal de Delaware","Del personal médico interno del DMV"],"explanation":"El certificado médico debe provenir de un examinador médico que figure en el FMCSA National Registry of Certified Medical Examiners. Delaware adoptó este requisito federal para todos los titulares de CDL/CLP. Fuente: página de Certificación Médica del Delaware DMV; 49 CFR 390.103 / National Registry."},"88":{"q":"¿En qué calendario vence y se vuelve renovable una CDL de Delaware?","options":["En el octavo aniversario de la fecha de nacimiento del titular siguiente a la emisión (cada 8 años)","Cada 4 años en la fecha de emisión","Cada 5 años en la fecha de emisión","Cada 2 años para coincidir con el examen físico del DOT"],"explanation":"Una CDL de Delaware vence y es renovable en la fecha del octavo aniversario del nacimiento del solicitante siguiente a la emisión, lo que da un plazo efectivo de hasta ocho años. Fuente: Título 21 § 2611(f); Delaware DMV."},"89":{"q":"¿Con cuánta anticipación, como máximo, puede renovarse una CDL de Delaware antes de que venza?","options":["Dentro de los 30 días previos a la fecha de vencimiento","Dentro de los 90 días previos a la fecha de vencimiento","Dentro de los 6 meses previos a la fecha de vencimiento","Dentro de 1 año previo a la fecha de vencimiento"],"explanation":"Delaware permite que una CDL se renueve únicamente dentro de los 30 días previos a su fecha de vencimiento. Fuente: página web de CDL del Delaware DMV."},"90":{"q":"¿Cuál es la edad mínima para obtener una CDL de Delaware solo para conducción intraestatal (dentro de Delaware)?","options":["18 años","16 años","21 años","19 años"],"explanation":"Una persona debe tener al menos 18 años para tener una CDL de Delaware para operación intraestatal. Fuente: Delaware DMV; Título 21 Cap. 26."},"91":{"q":"¿Cuál es la edad mínima para conducir un vehículo comercial en comercio interestatal, transportar materiales peligrosos o transportar pasajeros con una CDL de Delaware?","options":["21 años","18 años","19 años","23 años"],"explanation":"Un conductor debe tener al menos 21 años para operar en comercio interestatal, transportar materiales peligrosos que requieran rótulos, o transportar pasajeros. Fuente: Delaware DMV; 49 CFR 383."},"92":{"q":"¿Qué documentos debe presentar un solicitante de Delaware cuando llega para el examen de habilidades (manejo) de la CDL?","options":["Permiso de aprendiz vigente, licencia vigente del conductor acompañante de 21+ años, registro vehicular vigente y seguro vigente","Solo un permiso de aprendiz vigente y la tarjeta del Seguro Social","Solo un pasaporte y el recibo de la cuota del examen","Un acta de nacimiento y dos recibos de servicios"],"explanation":"Para la prueba de manejo, el solicitante debe presentar un permiso de aprendiz vigente, la licencia de conducir vigente del conductor acompañante (21+ años), una tarjeta de registro vehicular vigente y una tarjeta de seguro vigente. Fuente: página web de CDL del Delaware DMV."},"93":{"q":"¿Qué puntaje se requiere para aprobar el examen escrito de conocimientos generales de la CDL de Delaware?","options":["80% correcto (40 de 50 preguntas)","70% correcto (35 de 50 preguntas)","90% correcto (45 de 50 preguntas)","100% correcto (las 50 preguntas)"],"explanation":"El examen de conocimientos generales de la CDL de Delaware tiene 50 preguntas y requiere un puntaje de 80% (40 de 50) o mejor para aprobar. Fuente: Delaware DMV / sistema de pruebas de CDL basado en AAMVA utilizado en Delaware."},"94":{"q":"¿Cuál es el documento que Delaware proporciona como la principal referencia de autoestudio para prepararse para los exámenes de conocimientos y habilidades de la CDL?","options":["El Manual de CDL de Delaware (Commercial Driver License Manual) publicado por el DMV","El Código de Delaware, edición anotada del Título 21","El FMCSA Pocket Guide to Large Truck and Bus Statistics","El libro de texto estatal de Educación Vial"],"explanation":"El DMV de Delaware publica el Manual de CDL de Delaware (basado en el modelo de AAMVA), que los solicitantes deben obtener y estudiar antes del examen. Fuente: Manual de CDL del Delaware DMV."},"95":{"q":"¿Cómo se agenda la parte de conducción en carretera del examen de habilidades de la CDL de Delaware, y cómo se apoya la parte de inspección previa al viaje?","options":["El examen de habilidades es con cita, y el DMV proporciona una lista de verificación de inspección previa al viaje como ayuda para los solicitantes","Las tres partes de habilidades son sin cita, y no se proporciona ninguna lista de verificación","La prueba de manejo es en línea; la inspección previa al viaje se exime para los graduados de ELDT","El agendamiento se realiza solo a través del empleador del solicitante"],"explanation":"Los exámenes de habilidades de la CDL de Delaware son únicamente con cita, y el programa modernizado proporciona a los solicitantes una lista de verificación para el examen de inspección previa al viaje del vehículo como ayuda de estudio. Fuente: página web de CDL del Delaware DMV (examen de habilidades modernizado, vigente a partir del 26 de febrero de 2025)."},"96":{"q":"¿Qué le sucede generalmente a una CDL de Delaware si el titular que se autocertificó como interestatal no exceptuado no mantiene un certificado vigente del examinador médico en archivo con el DMV?","options":["El privilegio comercial (CDL) se degrada de modo que la persona ya no puede operar vehículos comerciales","La CDL se revoca de forma permanente y no puede reinstalarse","Nada, porque el certificado médico es solo un registro del empleador","La licencia se convierte automáticamente en una CDL interestatal exceptuada"],"explanation":"Si un conductor obligado (no exceptuado) deja vencer el certificado médico o no lo presenta, el estado debe degradar la CDL, retirando los privilegios de conducción comercial hasta que haya un certificado vigente en archivo. Fuente: Preguntas frecuentes de Autocertificación del Delaware DMV; 49 CFR 383.73."},"97":{"q":"Para un conductor de Delaware interestatal no exceptuado, ¿qué tan reciente debe ser generalmente el examen físico del DOT que respalda el certificado médico?","options":["Con fecha dentro de los 24 meses previos (hasta una certificación máxima de 2 años)","Con fecha dentro de los 6 meses previos","Con fecha dentro de los 12 meses previos únicamente","Con fecha dentro de los 5 años previos"],"explanation":"El examen físico del DOT debe cumplir con 49 CFR 391.41-391.49 y puede certificar a un conductor por hasta 24 meses (un examinador médico puede certificar por un período más corto para ciertas afecciones). Delaware exige este estándar federal. Fuente: página de Certificación Médica del Delaware DMV; 49 CFR 391.43."}},"hi":{"0":{"q":"Delaware के राजमार्गों पर किसी भी लोड सहित वाहन की अधिकतम कानूनी ऊंचाई कितनी है?","options":["13 feet 6 inches","14 feet","13 feet","12 feet 6 inches"],"explanation":"Delaware कानून किसी वाहन और उसके लोड की अधिकतम ऊंचाई 13 feet 6 inches निर्धारित करता है, सामान्य सड़कों और Interstate प्रणाली दोनों पर। स्रोत: Delaware Code Title 21, Ch. 45, sections 4502(b) और 4503(b)।"},"1":{"q":"सुरक्षा उपकरण को छोड़कर, Delaware में अधिकांश व्यावसायिक वाहनों के लिए अनुमत अधिकतम कुल बाहरी चौड़ाई कितनी है?","options":["102 inches","96 inches","108 inches","120 inches"],"explanation":"Delaware वाहन की कुल बाहरी चौड़ाई को 102 inches (8 feet 6 inches) तक सीमित करता है, सुरक्षा उपकरण को छोड़कर। स्रोत: Delaware Code Title 21, sections 4502 और 4503; DelDOT OSOW कानूनी सीमाएं।"},"2":{"q":"Delaware में संचालित होने वाले सेमीट्रेलर (ट्रक ट्रैक्टर को छोड़कर) की अधिकतम स्वीकार्य लंबाई कितनी है?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"किसी भी लोड सहित एक सेमीट्रेलर की लंबाई 53 feet से अधिक नहीं हो सकती, ट्रक ट्रैक्टर को छोड़कर। स्रोत: Delaware Code Title 21, Ch. 45, section 4503(b)।"},"3":{"q":"Delaware में पांच-या-अधिक-एक्सल वाले एक सामान्य संयोजन के लिए अधिकतम सकल वाहन वजन कितना है?","options":["80,000 pounds","73,280 pounds","88,000 pounds","90,000 pounds"],"explanation":"Delaware पांच या अधिक एक्सल वाले वाहन संयोजन के सकल वजन को 80,000 pounds तक सीमित करता है, जो संघीय सीमा के अनुरूप है। स्रोत: Delaware Code Title 21, Ch. 45, sections 4502(c) और 4503(c)।"},"4":{"q":"Delaware में Interstate प्रणाली पर, एक single axle पर अनुमत अधिकतम वजन कितना है?","options":["20,000 pounds","22,400 pounds","18,000 pounds","24,000 pounds"],"explanation":"Interstate राजमार्गों पर Delaware संघीय single-axle सीमा 20,000 pounds का पालन करता है। स्रोत: Delaware Code Title 21, Ch. 45, section 4503(c)।"},"5":{"q":"Delaware में Interstate प्रणाली पर, एक tandem axle पर अनुमत अधिकतम वजन कितना है?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"explanation":"Interstate राजमार्गों पर tandem-axle सीमा 34,000 pounds है, जो संघीय मानक से मेल खाती है। स्रोत: Delaware Code Title 21, Ch. 45, section 4503(c)।"},"6":{"q":"Delaware DOT का ओवरसाइज़/ओवरवेट हॉलिंग परमिट कब आवश्यक होता है?","options":["जब कोई वाहन या लोड Delaware Code के Title 21 के Chapter 45 में निर्धारित आकार या वजन सीमा से अधिक हो","केवल जब सकल वजन 80,000 pounds से अधिक हो, एक्सल वजन की परवाह किए बिना","केवल 12 feet से अधिक चौड़े लोड के लिए","केवल Interstate 95 पर यात्रा करते समय"],"explanation":"जब भी कोई वाहन, संयोजन, या स्व-चालित उपकरण Delaware Code के Title 21 के Chapter 45 में निर्धारित आयामी और/या वजन सीमाओं से अधिक हो, तो परमिट आवश्यक होता है, जिसमें वह स्थिति भी शामिल है जब कोई व्यक्तिगत एक्सल ओवरवेट हो भले ही सकल वजन कानूनी हो। स्रोत: DelDOT OSOW permit FAQ; Delaware Code Title 21, section 4504।"},"7":{"q":"Delaware के ओवरसाइज़/ओवरवेट हॉलिंग परमिट कैसे प्राप्त किए जाते हैं?","options":["Hauling Permit Office द्वारा प्रशासित DelDOT ऑनलाइन Oversize/Overweight (OSOW) परमिट प्रणाली के माध्यम से","Delaware DMV CDL प्रभाग को एक कागजी फॉर्म मेल करके","किसी भी DMV वाहन सेवा काउंटर पर उन्हें खरीदकर","वाहन पंजीकरण के साथ स्वतः जारी"],"explanation":"ओवरसाइज़/ओवरवेट परमिट DelDOT द्वारा अपनी ऑनलाइन OSOW परमिट प्रणाली के माध्यम से जारी किए जाते हैं, जिसका प्रबंधन Hauling Permit Office करता है, DMV द्वारा नहीं। स्रोत: DelDOT OSOW permit system (deldot.gov/osow)।"},"8":{"q":"एक मानक सिंगल-ट्रिप Delaware ओवरसाइज़/ओवरवेट परमिट के लिए न्यूनतम शुल्क क्या है?","options":["$30.00","$15.00","$50.00","$10.00"],"explanation":"एक सिंगल-ट्रिप हॉलिंग परमिट के लिए न्यूनतम शुल्क $30.00 है (Superload के लिए $60.00)। स्रोत: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405 परमिट नीति मैनुअल।"},"9":{"q":"एक ओवरवेट Delaware परमिट के लिए, अतिरिक्त वजन शुल्क की गणना कैसे की जाती है?","options":["कानूनी वजन सीमा से अधिक प्रत्येक 8,000 pounds (या उसके अंश) के लिए $10.00","कानूनी वजन सीमा से अधिक प्रत्येक 5,000 pounds के लिए $25.00","कानूनी वजन सीमा से अधिक प्रत्येक 1,000 pounds के लिए $5.00","ओवरवेट राशि की परवाह किए बिना एक सपाट $100.00"],"explanation":"Delaware कानूनी वजन सीमा से अधिक प्रत्येक 8,000 pounds, या उसके अंश, के लिए $10.00 का वजन शुल्क जोड़ता है। स्रोत: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405।"},"10":{"q":"एक मानक Delaware सिंगल-ट्रिप ओवरसाइज़/ओवरवेट हॉलिंग परमिट कितने समय तक वैध रहता है?","options":["5 days (प्रभावी तिथि से समाप्ति तिथि तक)","24 hours","30 days","10 days"],"explanation":"एक मानक हॉलिंग परमिट पांच दिनों के लिए वैध होता है, प्रभावी तिथि से समाप्ति तिथि तक। स्रोत: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405।"},"11":{"q":"जब तक परमिट में अन्यथा न कहा गया हो, एक परमिट प्राप्त ओवरसाइज़ लोड आम तौर पर Delaware के राजमार्गों पर किन घंटों के दौरान यात्रा कर सकता है?","options":["सूर्योदय से सूर्यास्त तक, सोमवार से रविवार","केवल सोमवार से शुक्रवार व्यावसायिक घंटों के दौरान","केवल रात 9 बजे से सुबह 5 बजे के बीच","किसी भी समय, 24 घंटे, बिना किसी प्रतिबंध के"],"explanation":"परमिट प्राप्त लोड को सूर्योदय से सूर्यास्त तक, सोमवार से रविवार, यात्रा करने के लिए अधिकृत किया जाता है, जब तक कि परमिट के विशेष प्रावधान अन्यथा न कहें। स्रोत: DelDOT OSOW permit FAQ।"},"12":{"q":"लगातार एक्सल के समूह पर अधिकतम सकल वजन निर्धारित करने के लिए Delaware किस सूत्र को लागू करता है?","options":["संघीय Bridge Formula, W = 500[(LN / (N-1)) + 12N + 36]","टायर की चौड़ाई के प्रति inch एक सपाट 1,000 pounds","निर्माता का GVWR 1.5 से गुणा किया गया","बिना किसी अंतराल कारक के प्रति एक्सल एक सरल 20,000 pounds"],"explanation":"Delaware संघीय Bridge Formula, W = 500[(LN / (N-1)) + 12N + 36], को अपनाता है, जहां W स्वीकार्य वजन है, L समूह के चरम एक्सल के बीच की दूरी है, और N एक्सल की संख्या है। स्रोत: Delaware Code Title 21, Ch. 45, section 4503(c)।"},"13":{"q":"Delaware के ब्रिज-वेट नियम के तहत, tandem axles के दो लगातार सेट प्रत्येक 34,000 pounds ले जा सकते हैं बशर्ते सेट के पहले और अंतिम एक्सल के बीच की दूरी कम से कम हो:","options":["36 feet","30 feet","40 feet","24 feet"],"explanation":"ब्रिज फॉर्मूले का एक अपवाद tandem axles के दो लगातार सेट को प्रत्येक 34,000 pounds ले जाने की अनुमति देता है जब उन सेट के पहले और अंतिम एक्सल के बीच की कुल दूरी 36 feet या अधिक हो। स्रोत: Delaware Code Title 21, Ch. 45, section 4503(c)।"},"14":{"q":"Delaware की उन सड़कों पर जो Interstate या संघीय-सहायता प्राथमिक प्रणाली का हिस्सा नहीं हैं, अधिकतम single-axle वजन कितना है?","options":["22,400 pounds","20,000 pounds","18,000 pounds","25,000 pounds"],"explanation":"गैर-Interstate राज्य सड़कों पर Delaware 22,400 pounds का उच्च single-axle वजन अनुमति देता है, जबकि Interstate पर यह 20,000 pounds है। स्रोत: Delaware Code Title 21, Ch. 45, section 4502(c)।"},"15":{"q":"Delaware कुछ राज्य के भीतर के कृषि उत्पाद या अनाज ढोने वाले ट्रकों को वजन में छूट देता है। ऐसे वाहन कितने सकल वजन तक संचालित हो सकते हैं?","options":["90,000 pounds","80,000 pounds","100,000 pounds","85,000 pounds"],"explanation":"Delaware राज्य के भीतर फल, सब्जियां, या कमोडिटी अनाज ढोने वाले ट्रकों को 90,000 pounds तक पहुंचने की अनुमति देता है (या निर्माता का सकल संयुक्त वजन रेटिंग, जो भी कम हो)। स्रोत: Delaware Code Title 21, Ch. 45, section 4502(c)।"},"16":{"q":"Delaware के जीवित-मुर्गी ढोने वाले वजन प्रावधान में वर्षा और पक्षी के आकार में भिन्नता को ध्यान में रखने के लिए एक छूट शामिल है। वह प्रतिशत भिन्नता कितनी है?","options":["3%","5%","10%","1%"],"explanation":"Delaware के भीतर जीवित मुर्गी ढोने वाले ट्रक 90,000 pounds तक संचालित हो सकते हैं, वर्षा और पक्षी के आकार के कारण वजन में अंतर के लिए 3% की भिन्नता के साथ। स्रोत: Delaware Code Title 21, Ch. 45, section 4502(c)।"},"17":{"q":"Delaware की उन सड़कों पर जो Interstate और संघीय-सहायता प्राथमिक प्रणाली के अलावा हैं, एक एकल वाहन (संयोजन नहीं) की अधिकतम लंबाई कितनी है?","options":["40 feet","45 feet","53 feet","35 feet"],"explanation":"गैर-Interstate सड़कों पर एक एकल वाहन की लंबाई 40 feet से अधिक नहीं हो सकती, और वाहनों के संयोजन की लंबाई 60 feet से अधिक नहीं हो सकती। स्रोत: Delaware Code Title 21, Ch. 45, section 4502(b)।"},"18":{"q":"Delaware में एक ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर (twin) संयोजन में, प्रत्येक ट्रेलर या सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["29 feet","28 feet","33 feet","31 feet"],"explanation":"एक ट्रैक्टर-सेमीट्रेलर-ट्रेलर संयोजन में प्रत्येक ट्रेलर या सेमीट्रेलर 29 feet तक सीमित है, ट्रैक्टर को छोड़कर। स्रोत: Delaware Code Title 21, Ch. 45, section 4503(b)।"},"19":{"q":"किस बिंदु पर एक Delaware ओवरसाइज़/ओवरवेट मूव 'Superload' के रूप में योग्य होता है, जिसका न्यूनतम परमिट शुल्क अधिक होता है?","options":["लंबाई 120 feet पर, चौड़ाई 15 feet पर, ऊंचाई 15 feet पर, या सकल वजन 120,000 pounds से अधिक","90,000 pounds सकल वजन से अधिक कोई भी लोड","10 feet से अधिक चौड़ा कोई भी लोड","75 feet से अधिक लंबाई या 100,000 pounds से अधिक वजन"],"explanation":"एक मूव को Superload के रूप में वर्गीकृत किया जाता है जब लंबाई 120 feet तक पहुंचती है, चौड़ाई 15 feet तक पहुंचती है, ऊंचाई 15 feet तक पहुंचती है, या सकल वजन 120,000 pounds से अधिक होता है; न्यूनतम Superload परमिट शुल्क $60.00 है। स्रोत: DelDOT OSOW permit FAQ।"},"20":{"q":"Delaware में, 26,001 pounds या उससे अधिक के Gross Vehicle Weight Rating (GVWR) वाले वाहनों के संयोजन को संचालित करने के लिए किस वर्ग के CDL की आवश्यकता होती है, बशर्ते खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"Delaware Commercial Driver's Manual (Version 4.0, \"Types of CDL\") कहता है कि 26,001 pounds या उससे अधिक के GVWR वाले वाहनों के किसी भी संयोजन के लिए Class A CDL की आवश्यकता होती है बशर्ते खींची जाने वाली इकाई(यों) का GVWR 10,000 pounds से अधिक हो।"},"21":{"q":"Delaware के नियमों के तहत, 26,001 pounds या उससे अधिक के GVWR वाला एक एकल वाहन जो 10,000 pounds से अधिक की इकाई को नहीं खींच रहा है, उसके लिए किस CDL वर्ग की आवश्यकता होती है?","options":["Class A","Class B","Class C","Class M"],"explanation":"Delaware Commercial Driver's Manual Class B को 26,001 pounds या उससे अधिक के GVWR वाले किसी भी एकल वाहन के रूप में परिभाषित करता है, या ऐसा वाहन जो 10,000 pounds GVWR से अधिक न होने वाले वाहन को खींच रहा हो।"},"22":{"q":"Delaware में, 26,001 pounds से कम GVWR वाला एक वाहन जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या placarded खतरनाक सामग्री ले जाता है, उसके लिए किस CDL वर्ग की आवश्यकता होती है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"Delaware Commercial Driver's Manual के अनुसार, 26,001 pounds से कम GVWR वाले वाहन के लिए Class C CDL की आवश्यकता होती है जो चालक सहित 16 या अधिक व्यक्तियों को ले जाने के लिए डिज़ाइन किया गया हो, या जो placarding की आवश्यकता वाली खतरनाक सामग्री ले जाने के लिए उपयोग किया जाता हो।"},"23":{"q":"एक Delaware CDL पर, कौन सा endorsement कोड टैंक वाहन के संचालन को अधिकृत करता है?","options":["Code N","Code T","Code H","Code P"],"explanation":"Delaware Commercial Driver's Manual Tanker endorsement को code N के रूप में सूचीबद्ध करता है। T endorsement Doubles/Triples के लिए है, H Hazardous Materials है, और P Passenger है।"},"24":{"q":"double या triple ट्रेलर खींचने के लिए कौन सा Delaware CDL endorsement आवश्यक है?","options":["Endorsement T","Endorsement N","Endorsement X","Endorsement P"],"explanation":"Delaware Commercial Driver's Manual Doubles/Triples endorsement को code T के रूप में सूचीबद्ध करता है और कई ट्रेलर खींचने से जुड़ी समस्याओं पर एक विशेष ज्ञान परीक्षा उत्तीर्ण करना आवश्यक है।"},"25":{"q":"Delaware Commercial Driver's Manual के अनुसार, Tank Vehicle (N) endorsement तब आवश्यक होता है जब वाहन को एक टैंक में तरल या गैस ले जाने के लिए डिज़ाइन किया गया हो जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और कुल रेटेड क्षमता कम से कम कितने gallons हो?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"Delaware Commercial Driver's Manual कहता है कि Tank Vehicle (N) endorsement उन टैंकों पर लागू होता है जिनकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और कुल रेटेड क्षमता 1,000 gallons या उससे अधिक हो।"},"26":{"q":"Delaware में, राज्य के भीतर (केवल Delaware के भीतर) गाड़ी चलाने के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years","17 years","18 years","21 years"],"explanation":"Delaware Commercial Driver's Manual की Basic CDL Requirements कहती हैं कि राज्य के भीतर गाड़ी चलाने के लिए आवेदक की आयु 18 years होनी चाहिए और 1 year का ड्राइविंग अनुभव होना चाहिए।"},"27":{"q":"Delaware की बुनियादी CDL आवश्यकताओं के तहत, अंतरराज्यीय वाणिज्य में गाड़ी चलाने या खतरनाक सामग्री ले जाने के लिए न्यूनतम कितनी आयु आवश्यक है?","options":["18 years","19 years","20 years","21 years"],"explanation":"Delaware Commercial Driver's Manual के अनुसार अंतरराज्यीय वाणिज्य में गाड़ी चलाने या खतरनाक सामग्री ले जाने के लिए आवेदक की आयु 21 years होनी चाहिए और कम से कम 1 year का ड्राइविंग अनुभव होना चाहिए।"},"28":{"q":"ज्ञान परीक्षाएं उत्तीर्ण करने के बाद, CDL skills test देने की अनुमति मिलने से पहले एक Delaware Commercial Learner's Permit (CLP) धारक को CLP को कितने समय तक रखना आवश्यक है?","options":["न्यूनतम 14 पूरे दिन","न्यूनतम 10 पूरे दिन","न्यूनतम 7 पूरे दिन","न्यूनतम 30 पूरे दिन"],"explanation":"Delaware Commercial Driver's Manual कहता है कि CDL skills test करने में सक्षम होने से पहले आपको अपना CLP न्यूनतम 14 पूरे दिनों तक रखना होगा, जो संघीय 49 CFR 383 आवश्यकता से मेल खाता है।"},"29":{"q":"Delaware Commercial Learner's Permit (CLP) पर गाड़ी चलाते समय, धारक के साथ किसका होना आवश्यक है?","options":["कोई भी लाइसेंस प्राप्त चालक जिसकी आयु 18 या उससे अधिक हो","उसी प्रकार के CMV में योग्य एक लाइसेंस प्राप्त CDL चालक","केवल एक प्रमाणित DMV परीक्षक","कोई नहीं; CLP अकेले गाड़ी चलाने की अनुमति देता है"],"explanation":"Delaware Commercial Driver's Manual कहता है कि CLP आपको एक अन्य लाइसेंस प्राप्त CDL चालक के साथ CMV चलाने की अनुमति देता है, और आप केवल उसी प्रकार का वाहन चला सकते हैं जिसके लिए आपने उसी प्रकार के CMV में योग्य CDL चालक के साथ परीक्षा दी थी।"},"30":{"q":"खतरनाक सामग्री (H) endorsement के साथ Delaware CDL जारी किए जाने से पहले, आवेदक को सबसे पहले क्या पूरा करना होगा?","options":["DMV में एक रक्षात्मक ड्राइविंग पाठ्यक्रम","skills test के बाद 30-day की प्रतीक्षा अवधि","fingerprinting सहित एक TSA सुरक्षा खतरा मूल्यांकन","एक placarded वाहन में एक अलग रोड टेस्ट"],"explanation":"Delaware Commercial Driver's Manual कहता है कि hazmat endorsement के साथ कोई CDL तब तक जारी नहीं किया जा सकता जब तक आवेदक पहले TSA सुरक्षा खतरा मूल्यांकन (जिसमें fingerprinting और नागरिकता/कानूनी उपस्थिति का सत्यापन शामिल है) से न गुज़रा हो और TSA मंजूरी प्राप्त न की हो।"},"31":{"q":"Delaware में लागू संघीय Entry-Level Driver Training (ELDT) नियम के तहत, प्रशिक्षण किस रजिस्ट्री पर सूचीबद्ध एक स्कूल द्वारा प्रदान किया जाना चाहिए?","options":["Delaware DMV Approved Schools सूची","AAMVA Instructor Directory","FMCSA Training Provider Registry (TPR)","TSA Certified Trainer Registry"],"explanation":"Delaware DMV का ELDT पृष्ठ कहता है कि आवेदक द्वारा CDL skills परीक्षा देने से पहले entry-level driver training एक FMCSA-पंजीकृत प्रदाता के माध्यम से पूरा किया जाना चाहिए जो FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध हो।"},"32":{"q":"skills/ज्ञान परीक्षा देने से पहले Delaware निम्नलिखित में से किसके लिए ELDT (Entry-Level Driver Training) की आवश्यकता रखता है?","options":["एक Tanker (N) endorsement जोड़ना","एक Doubles/Triples (T) endorsement जोड़ना","एक मौजूदा CDL का नवीनीकरण","पहली बार Class A या Class B CDL प्राप्त करना"],"explanation":"Delaware DMV के ELDT पृष्ठ के अनुसार (7 फरवरी, 2022 से प्रभावी), ELDT पहली बार Class A या B आवेदकों, उच्च वर्ग में अपग्रेड, और S, P, और H endorsements के लिए आवश्यक है। यह N या T endorsements के लिए या नवीनीकरण के लिए आवश्यक नहीं है।"},"33":{"q":"Delaware CDL धारकों से अपनी ड्राइविंग के प्रकार को स्व-प्रमाणित करने की आवश्यकता रखता है। कितनी स्व-प्रमाणन श्रेणियां हैं?","options":["दो","तीन","चार","पांच"],"explanation":"Delaware Commercial Driver's Manual कहता है कि CDL धारकों को non-excepted interstate, non-excepted intrastate, excepted interstate, या excepted intrastate की ड्राइविंग स्थिति को स्व-प्रमाणित करना होगा — चार श्रेणियां।"},"34":{"q":"एक Delaware CDL आवेदक जो अंतरराज्यीय वाणिज्य में CMV चलाता है और संघीय भौतिक योग्यता नियमों के अधीन है, किस चिकित्सा स्व-प्रमाणन श्रेणी के रूप में प्रमाणित होता है?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Delaware Commercial Driver's Manual बताता है कि जो CDL धारक अंतरराज्यीय वाणिज्य में CMV चलाते हैं और जिन्हें संघीय चिकित्सा प्रमाणपत्र आवश्यकता को पूरा करना होता है, वे non-excepted interstate commerce चालक हैं।"},"35":{"q":"जब एक Delaware CLP को Passenger (P) endorsement के साथ जारी किया जाता है, तो उसमें कौन सा प्रतिबंध भी होना चाहिए?","options":["एक 'K' Intrastate Only प्रतिबंध","एक 'L' No air brake प्रतिबंध","एक 'P' No passengers in a CMV bus प्रतिबंध","एक 'E' No manual transmission प्रतिबंध"],"explanation":"Delaware Commercial Driver's Manual नोट करता है कि यदि एक CLP को Passenger (P) या School Bus (S) endorsement के साथ जारी किया जाता है, तो उसमें एक 'P' – No passengers in a CMV bus प्रतिबंध भी होना चाहिए (केवल निर्दिष्ट कर्मियों को सवार रहने की अनुमति देते हुए)।"},"36":{"q":"यदि एक Delaware CLP को Tanker (N) endorsement के साथ जारी किया जाता है, तो उस पर कौन सा अतिरिक्त प्रतिबंध लगाया जाता है?","options":["'X' – No cargo in a CMV tank vehicle","'Z' – No full air brake equipped CMV","'V' – Medical variance","'O' – No tractor-trailer CMV"],"explanation":"Delaware Commercial Driver's Manual कहता है कि Tanker (N) endorsement के साथ जारी किए गए एक CLP में एक 'X' – No cargo in a CMV tank vehicle प्रतिबंध भी होना चाहिए, जिसका अर्थ है कि धारक केवल एक खाली, शुद्ध किए गए टैंक वाहन को संचालित कर सकता है।"},"37":{"q":"लाइसेंस के लिए आवेदन करते समय Delaware DMV आवेदक से Delaware निवास के संबंध में कौन से दस्तावेज़ प्रस्तुत करने की आवश्यकता रखता है?","options":["Delaware निवास का एक प्रमाण","Delaware निवास के तीन प्रमाण","केवल एक नोटरीकृत निवास शपथपत्र","Delaware निवास के दो प्रमाण"],"explanation":"Delaware DMV आवेदकों से पहचान का प्रमाण (एक प्राथमिक और एक द्वितीयक दस्तावेज़), यदि पात्र हो तो एक Social Security number, और Delaware निवास के दो प्रमाण प्रदान करने की आवश्यकता रखता है; गैर-U.S. नागरिकों को कानूनी उपस्थिति का प्रमाण भी दिखाना होगा (Delaware DMV Driver License/ID दस्तावेज़ आवश्यकताएं)।"},"38":{"q":"Delaware के नियमों के तहत, स्कूल बस चलाने के इच्छुक व्यक्ति से क्या आवश्यक है?","options":["केवल बिना किसी endorsements के एक Class C CDL","एक Passenger (P) और एक School Bus (S) दोनों endorsements के साथ एक CDL, साथ ही Department of Education आवश्यकताएं","एक स्कूल बस स्टिकर के साथ एक मानक Class D लाइसेंस","एक Tanker (N) endorsement और एक TSA पृष्ठभूमि जांच"],"explanation":"Delaware Commercial Driver's Manual कहता है कि सभी Delaware स्कूल बस चालकों के पास एक CDL होना चाहिए और अतिरिक्त Delaware Department of Education प्रशिक्षण और चिकित्सा आवश्यकताओं को पूरा करना चाहिए; DMV फिर P और S endorsements के साथ एक CDL जारी करता है (वाहन वर्ग के आधार पर M या N प्रतिबंध के साथ)।"},"39":{"q":"Delaware संघीय CDL छूट प्रावधानों के तहत CMV संचालित करने वाले चालकों के किस समूह के लिए एक विशेष गैर-CDL प्रमाण-पत्र प्रदान करता है?","options":["लंबी दूरी के अंतरराज्यीय ट्रक चालक","Hazmat टैंकर ऑपरेटर","चार्टर बस चालक","किसान और अग्निशामक"],"explanation":"Delaware Commercial Driver's Manual कहता है कि Delaware के पास उन किसानों और अग्निशामकों की पहचान के लिए एक विशेष Non-CDL है जो CDL छूट प्रावधानों के तहत CMV संचालित करते हैं; इस Non-CDL का उपयोग अंतरराज्यीय वाणिज्य में या किराए-पर स्थितियों में नहीं किया जा सकता।"},"40":{"q":"Delaware में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी है जिस पर कोई व्यक्ति कानूनी रूप से एक व्यावसायिक मोटर वाहन (CMV) संचालित कर सकता है?","options":["0.02 percent","0.04 percent","0.08 percent","0.10 percent"],"explanation":"Delaware 0.04 percent या उससे अधिक की BAC के साथ CMV संचालित करना अवैध बनाता है, जो निजी वाहनों के लिए 0.08 सीमा का आधा है। स्रोत: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614।"},"41":{"q":"Delaware के implied-consent कानून के तहत, जब कोई व्यक्ति राज्य में एक व्यावसायिक मोटर वाहन संचालित करता है, तो उसे किसके लिए सहमति देने वाला माना जाता है?","options":["वाहन के माल की तलाशी","अल्कोहल सांद्रता के लिए परीक्षण","एक चिकित्सा फिटनेस परीक्षा","उनके रोजगार रिकॉर्ड का प्रकाशन"],"explanation":"Delaware में CMV संचालित करके, एक चालक को अल्कोहल (रासायनिक) परीक्षण के लिए सहमति देने वाला माना जाता है। स्रोत: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614 (CMV चालकों के लिए implied consent)।"},"42":{"q":"एक Delaware CDL धारक को पहले प्रमुख अपराध के लिए कितने समय तक अयोग्य ठहराया जाता है, जैसे 0.04 या उससे अधिक की BAC के साथ CMV चलाना, जब खतरनाक सामग्री नहीं ढोई जा रही हो?","options":["60 days","120 days","1 year","3 years"],"explanation":"Delaware में पहला प्रमुख उल्लंघन 1-year की CDL अयोग्यता में परिणत होता है। स्रोत: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612 (राज्य द्वारा लागू संघीय मानक 49 CFR 383.51)।"},"43":{"q":"Delaware में, पहले प्रमुख अपराध के लिए अयोग्यता तीन वर्ष तक बढ़ जाती है जब अपराध तब होता है जब चालक एक CMV संचालित कर रहा हो जो क्या कर रहा हो?","options":["खतरनाक सामग्री के लिए placarded","किराए के लिए यात्रियों को ले जाना","एक double trailer खींचना","राज्य की सीमाएं पार करना"],"explanation":"खतरनाक सामग्री के लिए placarded एक CMV संचालित करते समय किया गया पहला प्रमुख अपराध अयोग्यता को 1 year से बढ़ाकर 3 years कर देता है। स्रोत: Delaware CDL Manual Section 1.3.2; 49 CFR 383.51।"},"44":{"q":"दूसरे प्रमुख अपराध (उदाहरण के लिए, नशे में गाड़ी चलाने के लिए दूसरी दोषसिद्धि) के लिए Delaware CDL अयोग्यता अवधि क्या है?","options":["3 years","10 years","आजीवन","5 years"],"explanation":"Delaware में किसी भी वाहन में दूसरा प्रमुख उल्लंघन आजीवन CDL अयोग्यता में परिणत होता है। स्रोत: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612; 49 CFR 383.51।"},"45":{"q":"Delaware CDL नियमों के तहत, एक CMV संचालित करते समय आवश्यक अल्कोहल/रासायनिक परीक्षण से इनकार करना किस प्रकार के उल्लंघन के रूप में माना जाता है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक out-of-service उल्लंघन","एक गैर-रिपोर्ट योग्य उल्लंघन"],"explanation":"रक्त-अल्कोहल परीक्षण कराने से इनकार को प्रमुख अपराधों में सूचीबद्ध किया गया है, जो पहले अपराध के लिए कम से कम 1-year की अयोग्यता ले जाता है। स्रोत: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614।"},"46":{"q":"CMV चालकों के लिए Delaware की implied-consent चेतावनी के तहत, अल्कोहल परीक्षण से इनकार करने पर अयोग्यता के अलावा तुरंत कितने समय के लिए out of service रखा जाता है?","options":["8 hours","12 hours","24 hours","48 hours"],"explanation":"Delaware कानून के अनुसार अधिकारी को चालक को चेतावनी देनी होगी कि इनकार करने पर तुरंत 24 hours के लिए out of service रखा जाएगा और कम से कम 1 year के लिए अयोग्य ठहराया जाएगा। स्रोत: 21 Del. C. Section 2614।"},"47":{"q":"एक Delaware CMV चालक 0.02 की BAC (0.04 से कम अल्कोहल की मापने योग्य मात्रा) के साथ पाया जाता है। आवश्यक परिणाम क्या है?","options":["एक 60-day CDL अयोग्यता","24 hours के लिए out of service रखा जाना","एक 1-year CDL अयोग्यता","आजीवन CDL अयोग्यता"],"explanation":"0.04 से कम अल्कोहल की कोई भी पता लगाने योग्य मात्रा (0.02 से 0.04 से कम की मापने योग्य मात्रा) के लिए आवश्यक है कि चालक को 24 hours के लिए out of service रखा जाए। स्रोत: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614।"},"48":{"q":"Delaware CDL नियमों के तहत निम्नलिखित में से किसे एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["0.04 की BAC के साथ CMV चलाना","सीमा से 15 mph या अधिक की अत्यधिक गति","दुर्घटना स्थल से भाग जाना","एक out-of-service आदेश का उल्लंघन"],"explanation":"अत्यधिक गति (पोस्ट की गई सीमा से 15 mph या अधिक) एक गंभीर यातायात उल्लंघन है। अन्य सूचीबद्ध मद प्रमुख अपराध या out-of-service उल्लंघन हैं। स्रोत: Delaware CDL Manual Section 1.3.3।"},"49":{"q":"Delaware में, तीन वर्ष की अवधि के भीतर एक CMV में दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने पर CDL कितने समय के लिए अयोग्य ठहराया जाता है?","options":["30 days","60 days","120 days","1 year"],"explanation":"किसी भी तीन वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघन 60-day की CDL अयोग्यता में परिणत होते हैं। स्रोत: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51।"},"50":{"q":"तीन वर्ष की अवधि के भीतर एक CMV में तीन या अधिक गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने पर Delaware CDL अयोग्यता अवधि क्या है?","options":["60 days","90 days","120 days","180 days"],"explanation":"किसी भी तीन वर्ष की अवधि के भीतर तीन या अधिक गंभीर यातायात उल्लंघन 120-day की CDL अयोग्यता में परिणत होते हैं। स्रोत: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51।"},"51":{"q":"इनमें से कौन सा Delaware CDL नियमों के तहत एक प्रमुख अपराध के बजाय एक गंभीर यातायात उल्लंघन है?","options":["किसी वाहन का बहुत करीब से पीछा करना","एक अपराध करने के लिए CMV का उपयोग करना","लापरवाह CMV संचालन के माध्यम से मृत्यु का कारण बनना","एक नियंत्रित पदार्थ के प्रभाव में CMV चलाना"],"explanation":"किसी वाहन का बहुत करीब से पीछा करना एक गंभीर यातायात उल्लंघन है। अन्य तीन प्रमुख अपराध हैं। स्रोत: Delaware CDL Manual Section 1.3.3 (गंभीर) और Section 1.3.2 (प्रमुख)।"},"52":{"q":"एक CMV संचालित करते समय टेक्स्टिंग करना या हाथ में पकड़े मोबाइल टेलीफोन का उपयोग करना Delaware CDL नियमों के तहत किस प्रकार के उल्लंघन के रूप में माना जाता है?","options":["एक प्रमुख अपराध","एक गंभीर यातायात उल्लंघन","एक out-of-service आदेश उल्लंघन","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"एक CMV संचालित करते समय टेक्स्टिंग करना या हाथ में पकड़े फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है और 60-day/120-day अयोग्यता सीमाओं की ओर गिना जाता है। स्रोत: Delaware CDL Manual Section 1.3.3 और texting/phone अनुभाग; 49 CFR 383.51।"},"53":{"q":"Delaware/संघीय CDL नियमों के तहत, एक CMV संचालित करते समय हाथ में पकड़े मोबाइल फोन का उपयोग करने के लिए कितनी दोषसिद्धियों के बाद (3 वर्ष के भीतर) CDL 60 दिनों के लिए अयोग्य ठहराया जाता है?","options":["एक दोषसिद्धि","दो या अधिक दोषसिद्धियां","चार दोषसिद्धियां","पांच दोषसिद्धियां"],"explanation":"3 वर्ष के भीतर एक CMV संचालित करते समय हाथ में पकड़े फोन कानून की दो या अधिक दोषसिद्धियां 60-day की अयोग्यता लाती हैं (तीन या अधिक के लिए 120 days)। स्रोत: Delaware CDL Manual हाथ में पकड़े मोबाइल टेलीफोन अनुभाग; 49 CFR 383.51।"},"54":{"q":"Delaware CDL Manual में बताए अनुसार, एक CMV चालक को टेक्स्टिंग-व्हाइल-ड्राइविंग उल्लंघन के लिए अधिकतम कितने संघीय नागरिक दंड का सामना करना पड़ सकता है?","options":["$750 तक","$1,500 तक","$2,750 तक","$11,000 तक"],"explanation":"Delaware CDL Manual कहता है कि चालक टेक्स्टिंग/हाथ में पकड़े फोन उल्लंघनों के लिए $2,750 तक के नागरिक दंड के अधीन हैं (नियोक्ता $11,000 तक)। स्रोत: Delaware CDL Manual texting और हाथ में पकड़े मोबाइल टेलीफोन अनुभाग।"},"55":{"q":"एक CMV में रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए एक Delaware CDL कितने समय के लिए अयोग्य ठहराया जाता है?","options":["30 days से कम नहीं","60 days से कम नहीं","120 days से कम नहीं","1 year से कम नहीं"],"explanation":"एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 60 days से कम नहीं की अयोग्यता ले जाता है। स्रोत: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51।"},"56":{"q":"Delaware में, तीन वर्षों के भीतर एक CMV में दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन CDL को कम से कम कितने समय के लिए अयोग्य ठहराता है?","options":["60 days","120 days","180 days","1 year"],"explanation":"किसी भी तीन वर्ष की अवधि के भीतर एक दूसरा रेलमार्ग-क्रॉसिंग उल्लंघन 120 days से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51।"},"57":{"q":"एक Delaware CMV चालक तीन वर्षों के भीतर तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। CDL कम से कम कितने समय के लिए अयोग्य ठहराया जाता है?","options":["120 days","180 days","1 year","3 years"],"explanation":"किसी भी तीन वर्ष की अवधि के भीतर एक तीसरा रेलमार्ग-क्रॉसिंग उल्लंघन 1 year से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51।"},"58":{"q":"Delaware CDL नियमों के तहत, एक CMV में एक out-of-service आदेश का उल्लंघन करने की पहली दोषसिद्धि (खतरनाक सामग्री नहीं ढोना) के लिए अयोग्यता सीमा क्या है?","options":["30 days से कम नहीं और न ही 90 days से अधिक","180 days से कम नहीं और न ही 1 year से अधिक","1 year से कम नहीं और न ही 2 years से अधिक","3 years से कम नहीं और न ही 5 years से अधिक"],"explanation":"एक पहला out-of-service आदेश उल्लंघन 180 days से कम नहीं और 1 year से अधिक नहीं की अयोग्यता ले जाता है। स्रोत: Delaware CDL Manual MCSIA अयोग्य ठहराने वाले उल्लंघन अनुभाग; 49 CFR 383.51।"},"59":{"q":"डेलावेयर के मूव ओवर कानून के तहत, जब आप ऐसे हाईवे पर जहाँ आपकी दिशा में चार या अधिक लेन हों, चेतावनी रोशनी प्रदर्शित कर रहे किसी रुके हुए DelDOT, पुलिस, टो, या आपातकालीन वाहन के पास पहुँचते हैं, तो आपको सबसे पहले क्या करना चाहिए?","options":["यदि ऐसा करना सुरक्षित हो, तो रुके हुए वाहन से लगी हुई लेन को छोड़कर किसी दूसरी लेन में लेन परिवर्तन करें","जब तक रुका हुआ वाहन शोल्डर नहीं छोड़ देता तब तक पूरी तरह रुके रहें","शोल्डर पर चले जाएँ और 10 mph से अधिक गति से न गुज़रें","अपनी लेन बनाए रखें और गुज़रते समय लगातार हॉर्न बजाएँ"],"explanation":"डेलावेयर टाइटल 21 § 4134(b) के अनुसार, एक ही दिशा में कम से कम चार लेन वाली सड़क पर वाहन चालकों को सुरक्षित होने पर, रुके हुए आपातकालीन/DelDOT/टो/यूटिलिटी वाहन से लगी हुई लेन को छोड़कर किसी अन्य लेन में बदलकर रास्ता देना आवश्यक है। स्रोत: 21 Del. C. § 4134।"},"60":{"q":"डेलावेयर के मूव ओवर कानून के तहत, यदि आप किसी रुके हुए आपातकालीन वाहन से सुरक्षित रूप से लेन नहीं बदल सकते, तो जहाँ निर्धारित सीमा 50 mph या उससे अधिक हो, वहाँ गति में कितनी कमी आवश्यक है?","options":["निर्धारित गति सीमा से कम से कम 20 mph कम किसी सुरक्षित गति तक घटाएँ","निर्धारित गति सीमा से कम से कम 10 mph कम किसी सुरक्षित गति तक घटाएँ","निर्धारित गति सीमा के ठीक आधे तक घटाएँ","निर्धारित सीमा चाहे जो भी हो, 25 mph से अधिक न रखें"],"explanation":"21 Del. C. § 4134(b) के अनुसार, जब लेन बदलना संभव न हो, तो जहाँ सीमा 50 mph या उससे अधिक हो, वहाँ चालक को निर्धारित सीमा से कम से कम 20 mph कम किसी सुरक्षित गति तक घटाना आवश्यक है। स्रोत: 21 Del. C. § 4134।"},"61":{"q":"जब कोई डेलावेयर स्कूल बस किसी अविभाजित दो-लेन सड़क पर अपनी लाल रोशनी चमकाते हुए रुकी हो, तो किन चालकों को रुकना चाहिए?","options":["आगे और पीछे दोनों दिशाओं से आने वाले चालक","केवल पीछे से आने वाले चालक (बस की उसी दिशा में)","केवल आगे से आने वाले चालक (सामने से आने वाले)","केवल बस के 20 फीट के भीतर वाले चालक"],"explanation":"डेलावेयर टाइटल 21 § 4166 के अनुसार, जब किसी स्कूल बस की लाल स्टॉप लाइटें सक्रिय हों, तो आगे या पीछे से बस के पास पहुँच रहे किसी भी वाहन के चालक को बस से गुज़रने से पहले रुकना आवश्यक है। स्रोत: 21 Del. C. § 4166।"},"62":{"q":"चार या अधिक लेन वाली डेलावेयर सड़क (या सड़कों) पर, चमकती लाल रोशनी प्रदर्शित कर रही स्कूल बस के लिए किस पास आ रहे चालक को रुकना आवश्यक नहीं है?","options":["आगे से आने वाला चालक (सामने वाली दिशा से)","पीछे से आने वाला चालक (बस की उसी दिशा में)","आगे और पीछे दोनों के चालकों को छूट है","किसी भी चालक को छूट नहीं है; दोनों को हमेशा रुकना चाहिए"],"explanation":"21 Del. C. § 4166 के अनुसार, 4 या अधिक लेन वाली सड़क या सड़कों पर, आगे से (विपरीत दिशा से) आने वाले चालक को रुकने की आवश्यकता नहीं है; पीछे से आने वाले चालक को फिर भी रुकना चाहिए। स्रोत: 21 Del. C. § 4166।"},"63":{"q":"लाल रोशनी चमकाती हुई डेलावेयर स्कूल बस के लिए रुकने के बाद, चालक को कब तक रुके रहना चाहिए?","options":["जब तक बस चलना शुरू न कर दे या उसकी लाल स्टॉप लाइटें सक्रिय न रह जाएँ","कम से कम निश्चित 30 सेकंड तक","जब तक बस चालक यातायात को आगे बढ़ने का इशारा न करे","जब तक सभी बच्चे बस से कम से कम 100 फीट दूर न हो जाएँ"],"explanation":"21 Del. C. § 4166 के अनुसार, चालक को तब तक रुके रहना आवश्यक है जब तक बस चलना शुरू न कर दे या अपनी सक्रिय लाल स्टॉप लाइटें प्रदर्शित करना बंद न कर दे। स्रोत: 21 Del. C. § 4166।"},"64":{"q":"डेलावेयर CDL मैनुअल के अनुसार, जब प्लेकार्ड लगे खतरनाक-सामग्री वाहन को ऐसे रेलरोड क्रॉसिंग पर रुकना हो जहाँ कोई पेंट की हुई स्टॉप लाइन न हो, तो उसे निकटतम रेल के सापेक्ष कहाँ रुकना चाहिए?","options":["निकटतम रेल से 15 फीट से अधिक पास नहीं और 50 फीट से अधिक दूर नहीं","निकटतम रेल से 10 फीट से अधिक पास नहीं और 25 फीट से अधिक दूर नहीं","निकटतम रेल से 25 फीट से अधिक पास नहीं और 75 फीट से अधिक दूर नहीं","निकटतम रेल से 5 फीट से अधिक पास नहीं और 35 फीट से अधिक दूर नहीं"],"explanation":"डेलावेयर CDL मैनुअल (खंड 2.15) के अनुसार, जिन वाहनों को रुकना आवश्यक है, उन्हें निकटतम ट्रैक की निकटतम रेल से 15 फीट से अधिक पास नहीं और 50 फीट से अधिक दूर नहीं रुकना चाहिए। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.15।"},"65":{"q":"डेलावेयर CDL मैनुअल के अनुसार, जब आपके वाणिज्यिक वाहन का कोई भी हिस्सा रेलरोड ट्रैक पार कर रहा हो, तो आपको निम्न में से क्या नहीं करना चाहिए?","options":["ट्रैक पार करते समय गियर बदलना","स्टीयरिंग व्हील पर दोनों हाथ रखना","केवल यह पुष्टि करने के बाद पार करना कि सभी ट्रैक साफ़ हैं","जब उपलब्ध हो तब रुकने के लिए पुलआउट लेन का उपयोग करना"],"explanation":"डेलावेयर CDL मैनुअल (खंड 2.15) चालकों को निर्देश देता है कि वे क्रॉसिंग पर रुक जाने से बचने के लिए रेलरोड ट्रैक पार करते समय गियर न बदलें। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.15।"},"66":{"q":"डेलावेयर CDL मैनुअल के तहत, यदि आपके वाणिज्यिक वाहन को किसी एक-तरफ़ा या विभाजित हाईवे पर रुकना पड़े, तो आपको अपने तीन चेतावनी उपकरण किन दूरियों पर रखने चाहिए?","options":["आने वाले यातायात की ओर 10 फीट, 100 फीट, और 200 फीट","आने वाले यातायात की ओर 10 फीट, 50 फीट, और 150 फीट","आने वाले यातायात की ओर 25 फीट, 100 फीट, और 250 फीट","10 फीट, 100 फीट, और 100 फीट (एक आगे और एक पीछे)"],"explanation":"डेलावेयर CDL मैनुअल (खंड 2.5) निर्देश देता है कि एक-तरफ़ा या विभाजित हाईवे पर चेतावनी उपकरण आने वाले यातायात की ओर 10, 100, और 200 फीट पर रखे जाएँ। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.5।"},"67":{"q":"डेलावेयर CDL मैनुअल के अनुसार, दोनों दिशाओं में यातायात ले जा रही दो-लेन वाली अविभाजित सड़क पर, रुकने के बाद आप चेतावनी उपकरण कहाँ रखते हैं?","options":["वाहन के 10 फीट के भीतर, और उसके 100 फीट पीछे और 100 फीट आगे","200 फीट पीछे और 200 फीट आगे, वाहन के पास कोई नहीं","केवल एक उपकरण वाहन के 100 फीट पीछे","10 फीट, 100 फीट, और 200 फीट, सभी वाहन के पीछे"],"explanation":"डेलावेयर CDL मैनुअल (खंड 2.5) निर्देश देता है कि दो-लेन/अविभाजित सड़क पर एक उपकरण वाहन के आगे या पीछे के कोने के 10 फीट के भीतर तथा उपकरण वाहन के 100 फीट पीछे और 100 फीट आगे रखे जाएँ। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.5।"},"68":{"q":"डेलावेयर CDL मैनुअल के तहत, सड़क या शोल्डर पर रुकने के कितने मिनट के भीतर आपको अपने आपातकालीन चेतावनी उपकरण बाहर रखने चाहिए?","options":["10 मिनट","5 मिनट","15 मिनट","30 मिनट"],"explanation":"डेलावेयर CDL मैनुअल (खंड 2.5) के अनुसार, सड़क या शोल्डर पर रुकने के 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण रखे जाने आवश्यक हैं। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.5।"},"69":{"q":"डेलावेयर CDL मैनुअल के अनुसार, पार्क किए जाने या खराब होने पर उपयोग के लिए वाणिज्यिक वाहन को कौन-से चेतावनी उपकरण साथ रखने चाहिए?","options":["तीन परावर्तक त्रिकोण, या कम से कम 6 फ्यूज़ी, या 3 तरल-जलने वाले फ्लेयर","दो परावर्तक त्रिकोण और एक लाल झंडा","केवल चार परावर्तक त्रिकोण","एक परावर्तक त्रिकोण और एक बैटरी-संचालित बीकन"],"explanation":"डेलावेयर CDL मैनुअल आवश्यक आपातकालीन उपकरण के रूप में तीन परावर्तक त्रिकोण, या कम से कम 6 फ्यूज़ी, या 3 तरल-जलने वाले फ्लेयर सूचीबद्ध करता है। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.1 (निरीक्षण)।"},"70":{"q":"डेलावेयर CDL मैनुअल के अनुसार, यदि कोई पहाड़ी या मोड़ पीछे आ रहे चालकों को आपके रुके हुए वाहन को 500 फीट के भीतर देखने से रोकता है, तो आपको अपने सबसे पीछे वाले चेतावनी त्रिकोण के साथ क्या करना चाहिए?","options":["इसे सड़क पर और पीछे, रुकावट के परे ले जाएँ, ताकि चेतावनी मिल सके","इसे मानक 100 फीट पर ही रहने दें और एक चौथा त्रिकोण जोड़ें","इसकी दृश्यता बढ़ाने के लिए इसे वाहन के हुड पर रखें","इसे हटा दें और केवल फोर-वे फ्लैशर्स पर निर्भर रहें"],"explanation":"डेलावेयर CDL मैनुअल (खंड 2.5) के अनुसार, जब कोई पहाड़ी या मोड़ 500 फीट के भीतर दृश्य को अवरुद्ध करता है, तो सबसे पीछे वाले त्रिकोण को रुकावट के परे और पीछे ले जाएँ ताकि पीछे आ रहे चालकों को चेतावनी मिले। स्रोत: डेलावेयर CDL मैनुअल, खंड 2.5।"},"71":{"q":"डेलावेयर टाइटल 21 के तहत, ऐसी दो-लेन सड़क पर जहाँ कोई अन्य सीमा निर्धारित नहीं है, वैधानिक गति सीमा क्या है?","options":["50 mph","55 mph","45 mph","60 mph"],"explanation":"डेलावेयर टाइटल 21 § 4169 अन्यथा निर्धारित न होने पर 2-लेन सड़कों पर 50 mph (और 4-लेन तथा विभाजित सड़कों पर 55 mph) निर्धारित करता है। स्रोत: 21 Del. C. § 4169।"},"72":{"q":"डेलावेयर टाइटल 21 के तहत, ऐसी चार-लेन या विभाजित सड़क पर जहाँ कोई अन्य सीमा निर्धारित नहीं है, वैधानिक गति सीमा क्या है?","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"डेलावेयर टाइटल 21 § 4169 अन्यथा निर्धारित न होने पर 4-लेन तथा विभाजित सड़कों पर 55 mph निर्धारित करता है। स्रोत: 21 Del. C. § 4169।"},"73":{"q":"डेलावेयर टाइटल 21 के तहत, अन्यथा निर्धारित न होने पर व्यावसायिक या आवासीय क्षेत्र में गति सीमा क्या है?","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"डेलावेयर टाइटल 21 § 4169 अन्यथा निर्धारित न होने पर व्यावसायिक क्षेत्रों में 25 mph और आवासीय क्षेत्रों में 25 mph निर्धारित करता है। स्रोत: 21 Del. C. § 4169।"},"74":{"q":"किस डेलावेयर सड़क पर परिवहन विभाग ने रेड लायन क्रीक और एपोक्विनिमिंक नदी के बीच 65 mph अधिकतम गति सीमा निर्दिष्ट की है?","options":["डेलावेयर स्टेट रूट 1","इंटरस्टेट 495","U.S. रूट 13","इंटरस्टेट 295"],"explanation":"डेलावेयर टाइटल 21 § 4169 DelDOT को निर्देश देता है कि वह स्टेट रूट 1 के रेड लायन क्रीक और एपोक्विनिमिंक नदी के बीच वाले हिस्से (टोल प्लाज़ा क्षेत्र को छोड़कर) पर 65 mph अधिकतम निर्दिष्ट करे। स्रोत: 21 Del. C. § 4169।"},"75":{"q":"डेलावेयर के लेन-यात्रा प्रतिबंध कानून (§ 4114A) के तहत, कौन-से वाहन आम तौर पर स्टेट रूट 1 और इंटरस्टेट 495 पर केवल दाहिनी ओर वाली लेन में ही चल सकते हैं?","options":["26,000 पाउंड से अधिक के सकल वाहन भार रेटिंग वाला वाहन","10,000 पाउंड से अधिक के सकल वाहन भार रेटिंग वाला वाहन","किसी भी आकार का ट्रेलर खींच रहा कोई भी वाहन","भार चाहे जो भी हो, तीन या अधिक एक्सल वाला वाहन"],"explanation":"डेलावेयर टाइटल 21 § 4114A 26,000 पाउंड से अधिक GVWR वाले वाहनों को सीमित अपवादों के साथ SR 1 और I-495 के एक्सप्रेस/नियंत्रित-पहुँच हिस्सों पर दाहिनी ओर वाली लेन तक सीमित करता है। स्रोत: 21 Del. C. § 4114A।"},"76":{"q":"डेलावेयर § 4114A के तहत, दाहिनी-लेन प्रतिबंध के अधीन कोई वाहन SR 1 या I-495 पर बाईं लेन का वैध रूप से कब उपयोग कर सकता है?","options":["जब किसी अन्य वाहन को पीछे छोड़कर पार करते समय, सड़क में प्रवेश करते या उससे निकलते समय, या जैसा यातायात की स्थिति आवश्यक करे","केवल आधी रात से सुबह 6:00 बजे के बीच","केवल जब निर्धारित गति सीमा 35 mph या उससे कम हो","कभी नहीं, किसी भी परिस्थिति में"],"explanation":"डेलावेयर टाइटल 21 § 4114A भारी वाहन को पार करने, सड़क में प्रवेश करने/निकलने, आपातकाल, रुकावटों, यातायात की स्थितियों, या अन्य कानून का अनुपालन करने के लिए बाईं लेन का उपयोग करने की अनुमति देता है। स्रोत: 21 Del. C. § 4114A।"},"77":{"q":"डेलावेयर कानून के तहत, यातायात की सामान्य गति से धीमे चल रहे वाहन को, पार करते समय या बाएँ मोड़ की तैयारी करते समय को छोड़कर, कहाँ चलाया जाना चाहिए?","options":["यातायात के लिए उपलब्ध दाहिनी ओर वाली लेन में, या जितना संभव हो दाहिने कर्ब या किनारे के निकट","किसी भी बहु-लेन सड़क की बीच वाली लेन में","जिस लेन में सबसे कम वाहन हों, उसमें","बाईं लेन में, मर्ज होने वाले यातायात के लिए दाहिनी लेन खुली छोड़ते हुए"],"explanation":"डेलावेयर टाइटल 21 § 4114 के अनुसार, सामान्य यातायात से धीमे चल रहे वाहन को, किसी को पीछे छोड़कर पार करते समय या बाएँ मोड़ की तैयारी करते समय को छोड़कर, दाहिनी ओर वाली लेन में या जितना संभव हो दाहिने कर्ब/किनारे के निकट रहना आवश्यक है। स्रोत: 21 Del. C. § 4114।"},"78":{"q":"डेलावेयर CDL मैनुअल के अनुसार, CMV चलाते समय रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप पहले अपराध के लिए कम से कम कितने समय की CDL अयोग्यता होती है?","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"डेलावेयर CDL मैनुअल (खंड 1.3.5) के अनुसार, रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन CDL को कम से कम 60 दिन (पहला), 120 दिन (3 वर्षों के भीतर दूसरा), और 1 वर्ष (3 वर्षों के भीतर तीसरा) के लिए अयोग्य घोषित करता है। स्रोत: डेलावेयर CDL मैनुअल, खंड 1.3.5।"},"79":{"q":"कौन-सी डेलावेयर एजेंसी वाणिज्यिक चालक लाइसेंस (CDL) जारी करती है?","options":["डेलावेयर डिवीज़न ऑफ़ मोटर व्हीकल्स (DMV), जो DelDOT का हिस्सा है","डेलावेयर स्टेट पुलिस कमर्शियल कैरियर ब्यूरो","फ़ेडरल मोटर कैरियर सेफ़्टी एडमिनिस्ट्रेशन फ़ील्ड ऑफ़िस","डेलावेयर सेक्रेटरी ऑफ़ स्टेट का कार्यालय"],"explanation":"डेलावेयर में, CDL डेलावेयर डिवीज़न ऑफ़ मोटर व्हीकल्स (DMV) द्वारा जारी किए जाते हैं, जो डेलावेयर परिवहन विभाग के अंतर्गत संचालित होता है। FMCSA संघीय मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: Delaware DMV CDL पेज; टाइटल 21, अध्याय 26 (Uniform Commercial Driver License Act)।"},"80":{"q":"डेलावेयर CDL ज्ञान (लिखित) परीक्षाएँ कैसे आयोजित की जाती हैं?","options":["किसी भी DMV सुविधा पर वॉक-इन द्वारा, बिना किसी अपॉइंटमेंट की आवश्यकता के","केवल अपॉइंटमेंट द्वारा डोवर मुख्यालय पर","घर से ऑनलाइन एक रिमोट प्रॉक्टर के साथ","केवल एक अनुमोदित तृतीय-पक्ष परीक्षण केंद्र पर"],"explanation":"Delaware DMV के अनुसार, सभी CDL ज्ञान परीक्षाएँ केवल वॉक-इन द्वारा होती हैं और किसी भी डिवीज़न (DMV) सुविधा पर पूरी की जा सकती हैं। अपॉइंटमेंट की आवश्यकता कौशल परीक्षा पर लागू होती है, ज्ञान परीक्षा पर नहीं। स्रोत: Delaware DMV CDL वेबपेज।"},"81":{"q":"CDL कौशल परीक्षा देने से पहले धारक को डेलावेयर वाणिज्यिक शिक्षार्थी परमिट (CLP) कितने समय तक रखना आवश्यक है?","options":["प्रारंभिक जारी होने के बाद कम से कम 14 दिन","प्रारंभिक जारी होने के बाद कम से कम 30 दिन","प्रारंभिक जारी होने के बाद कम से कम 10 दिन","प्रारंभिक जारी होने के बाद कम से कम 7 दिन"],"explanation":"CLP धारक तब तक CDL प्री-ट्रिप, बेसिक कंट्रोल, या रोड कौशल परीक्षा देने के पात्र नहीं है जब तक परमिट प्रारंभिक जारी होने के बाद कम से कम 14 दिन तक न रखा गया हो। यह डेलावेयर द्वारा अपनाई गई संघीय 14-दिन की रोक है। स्रोत: Delaware DMV CDL वेबपेज; 49 CFR 383.25, जैसा टाइटल 21 अध्याय 26 के तहत अपनाया गया।"},"82":{"q":"डेलावेयर वाणिज्यिक शिक्षार्थी परमिट (CLP) कितने समय तक वैध रहता है?","options":["एक (1) वर्ष, और इसे उस अवधि के दौरान एक बार नवीनीकृत किया जा सकता है","180 दिन, बिना किसी नवीनीकरण की अनुमति के","दो (2) वर्ष, वार्षिक रूप से नवीनीकरण योग्य","छह (6) महीने, दो बार नवीनीकरण योग्य"],"explanation":"डेलावेयर CLP एक (1) वर्ष के लिए वैध है और इसे एक वर्ष से अधिक की अवधि के लिए जारी या विस्तारित नहीं किया जा सकता; इसे उस अवधि के दौरान एक बार नवीनीकृत किया जा सकता है। स्रोत: Delaware DMV CDL वेबपेज; टाइटल 21 § 2608।"},"83":{"q":"डेलावेयर CDL कौशल परीक्षा किन तीन भागों में विभाजित है?","options":["प्री-ट्रिप वाहन निरीक्षण, बेसिक कंट्रोल कौशल, और ऑन-रोड ड्राइविंग","लिखित परीक्षा, नेत्र परीक्षा, और रोड टेस्ट","केवल कपलिंग, ब्रेकिंग, और बैकिंग","थ्योरी प्रशिक्षण, बिहाइंड-द-व्हील, और अंतिम लिखित परीक्षा"],"explanation":"CDL कौशल परीक्षा तीन भागों से मिलकर बनी है: प्री-ट्रिप वाहन निरीक्षण परीक्षा, बेसिक कंट्रोल कौशल परीक्षा, और ऑन-रोड ड्राइविंग परीक्षा। डेलावेयर ने इन प्रोटोकॉलों को 26 फ़रवरी, 2025 से प्रभावी रूप से आधुनिक बनाया। स्रोत: Delaware DMV CDL वेबपेज; 49 CFR 383.113।"},"84":{"q":"क्लास A, क्लास B, पैसेंजर (P), या स्कूल बस (S) क्रेडेंशियल के लिए डेलावेयर CDL कौशल परीक्षा देने से पहले एंट्री-लेवल चालक को क्या पूरा करना आवश्यक है?","options":["किसी पंजीकृत प्रदाता से संघीय रूप से आवश्यक एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT)","DMV के साथ दर्ज की गई 30-दिन की अप्रेंटिसशिप","डेलावेयर स्टेट पुलिस द्वारा अनुमोदित एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","केवल सामान्य ज्ञान लिखित परीक्षा"],"explanation":"7 फ़रवरी, 2022 से प्रभावी, कोई भी एंट्री-लेवल ऑपरेटर क्लास A, क्लास B, P एंडोर्समेंट, या S एंडोर्समेंट के लिए CDL कौशल परीक्षा तब तक नहीं दे सकता जब तक उसने FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री पर सूचीबद्ध किसी प्रदाता से अनिवार्य थ्योरी और बिहाइंड-द-व्हील ELDT पूरी न की हो। स्रोत: Delaware DMV ELDT पेज; 49 CFR Part 380।"},"85":{"q":"डेलावेयर CDL/CLP धारक जिन चार स्व-प्रमाणन श्रेणियों की घोषणा कर सकता है, वे कौन-सी हैं?","options":["इंटरस्टेट नॉन-एक्सेप्टेड, इंटरस्टेट एक्सेप्टेड, इंट्रास्टेट नॉन-एक्सेप्टेड, इंट्रास्टेट एक्सेप्टेड","क्लास A, क्लास B, क्लास C, और क्लास D","हैज़मैट, पैसेंजर, टैंकर, और डबल्स/ट्रिपल्स","फ़ॉर-हायर, प्राइवेट, एक्सेम्प्ट, और गवर्नमेंट"],"explanation":"प्रत्येक डेलावेयर CDL/CLP धारक को चार श्रेणियों में से एक में स्व-प्रमाणन करना आवश्यक है: इंटरस्टेट नॉन-एक्सेप्टेड, इंटरस्टेट एक्सेप्टेड, इंट्रास्टेट नॉन-एक्सेप्टेड, या इंट्रास्टेट एक्सेप्टेड। स्रोत: Delaware DMV Self-Certification Affidavit Category Guide; 49 CFR 383.71।"},"86":{"q":"किस स्व-प्रमाणन श्रेणी के लिए चालक को डेलावेयर DMV के पास एक वर्तमान DOT मेडिकल परीक्षक प्रमाणपत्र जमा करना और फ़ाइल में रखना आवश्यक है?","options":["इंटरस्टेट नॉन-एक्सेप्टेड","इंटरस्टेट एक्सेप्टेड","इंट्रास्टेट एक्सेप्टेड","किसी भी श्रेणी को जमा करने की आवश्यकता नहीं है"],"explanation":"जो चालक इंटरस्टेट नॉन-एक्सेप्टेड के रूप में स्व-प्रमाणन करता है, उसे डेलावेयर DMV के पास संघीय मेडिकल परीक्षक प्रमाणपत्र की एक प्रति प्रदान करनी और बनाए रखनी होती है। एक्सेप्टेड श्रेणियों के लिए संघीय मेडिकल प्रमाणपत्र जमा करना आवश्यक नहीं है। स्रोत: Delaware DMV Self-Certification Category Guide; 49 CFR 383.71।"},"87":{"q":"डेलावेयर CDL आवेदक को मेडिकल परीक्षक प्रमाणपत्र का समर्थन करने वाली DOT शारीरिक जाँच कहाँ से प्राप्त करनी चाहिए?","options":["FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध किसी मेडिकल परीक्षक से","चालक की पसंद के किसी भी लाइसेंस प्राप्त चिकित्सक या कायरोप्रैक्टर से","केवल डेलावेयर स्टेट पुलिस-अनुमोदित क्लिनिक से","DMV के आंतरिक चिकित्सा कर्मचारियों से"],"explanation":"मेडिकल प्रमाणपत्र FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध किसी मेडिकल परीक्षक से आना चाहिए। डेलावेयर ने सभी CDL/CLP धारकों के लिए यह संघीय आवश्यकता अपनाई है। स्रोत: Delaware DMV Medical Certification पेज; 49 CFR 390.103 / National Registry।"},"88":{"q":"डेलावेयर CDL किस समय-सारणी पर समाप्त होता है और नवीनीकरण योग्य बनता है?","options":["जारी होने के बाद आने वाली धारक की जन्म तिथि की आठवीं वर्षगाँठ पर (हर 8 वर्ष)","जारी होने की तिथि पर हर 4 वर्ष","जारी होने की तिथि पर हर 5 वर्ष","DOT शारीरिक जाँच से मेल खाने के लिए हर 2 वर्ष"],"explanation":"डेलावेयर CDL जारी होने के बाद आने वाली आवेदक की जन्म तिथि की आठवीं वर्षगाँठ पर समाप्त होता है और नवीनीकरण योग्य होता है, जिससे आठ वर्ष तक की प्रभावी अवधि मिलती है। स्रोत: टाइटल 21 § 2611(f); Delaware DMV।"},"89":{"q":"डेलावेयर CDL को उसकी समाप्ति से पहले सबसे जल्दी कब नवीनीकृत किया जा सकता है?","options":["समाप्ति तिथि से 30 दिन पहले के भीतर","समाप्ति तिथि से 90 दिन पहले के भीतर","समाप्ति तिथि से 6 महीने पहले के भीतर","समाप्ति तिथि से 1 वर्ष पहले के भीतर"],"explanation":"डेलावेयर CDL को केवल उसकी समाप्ति तिथि से 30 दिन पहले के भीतर ही नवीनीकृत करने की अनुमति देता है। स्रोत: Delaware DMV CDL वेबपेज।"},"90":{"q":"केवल इंट्रास्टेट (डेलावेयर के भीतर) ड्राइविंग के लिए डेलावेयर CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","19 वर्ष"],"explanation":"इंट्रास्टेट संचालन के लिए डेलावेयर CDL रखने हेतु व्यक्ति का कम से कम 18 वर्ष का होना आवश्यक है। स्रोत: Delaware DMV; टाइटल 21 अध्याय 26।"},"91":{"q":"डेलावेयर CDL के तहत इंटरस्टेट वाणिज्य में वाणिज्यिक वाहन चलाने, खतरनाक सामग्री ले जाने, या यात्रियों को ले जाने हेतु न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","23 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में संचालन करने, प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाने, या यात्रियों को ले जाने हेतु चालक का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: Delaware DMV; 49 CFR 383।"},"92":{"q":"CDL कौशल (रोड) परीक्षा के लिए पहुँचने पर डेलावेयर आवेदक को कौन-से दस्तावेज़ प्रस्तुत करने होंगे?","options":["वैध शिक्षार्थी परमिट, साथ आ रहे 21+ चालक का वैध लाइसेंस, वैध वाहन पंजीकरण, और वैध बीमा","केवल एक वैध शिक्षार्थी परमिट और सोशल सिक्योरिटी कार्ड","केवल एक पासपोर्ट और परीक्षा शुल्क की रसीद","एक जन्म प्रमाणपत्र और दो यूटिलिटी बिल"],"explanation":"रोड टेस्ट के लिए आवेदक को एक वैध शिक्षार्थी परमिट, साथ आ रहे चालक (21+) का वैध ड्राइवर लाइसेंस, एक वैध वाहन पंजीकरण कार्ड, और एक वैध बीमा कार्ड प्रस्तुत करना होगा। स्रोत: Delaware DMV CDL वेबपेज।"},"93":{"q":"डेलावेयर CDL सामान्य ज्ञान लिखित परीक्षा पास करने के लिए कौन-सा स्कोर आवश्यक है?","options":["80% सही (50 में से 40 प्रश्न)","70% सही (50 में से 35 प्रश्न)","90% सही (50 में से 45 प्रश्न)","100% सही (सभी 50 प्रश्न)"],"explanation":"डेलावेयर CDL सामान्य ज्ञान परीक्षा में 50 प्रश्न होते हैं और पास होने के लिए 80% (50 में से 40) या उससे बेहतर स्कोर आवश्यक है। स्रोत: Delaware DMV / डेलावेयर में उपयोग की जाने वाली AAMVA-आधारित CDL परीक्षण प्रणाली।"},"94":{"q":"CDL ज्ञान और कौशल परीक्षाओं की तैयारी के लिए डेलावेयर द्वारा प्रदान किया जाने वाला प्राथमिक स्व-अध्ययन संदर्भ कौन-सा दस्तावेज़ है?","options":["DMV द्वारा प्रकाशित डेलावेयर CDL मैनुअल (Commercial Driver License Manual)","डेलावेयर कोड, टाइटल 21 एनोटेटेड संस्करण","FMCSA Pocket Guide to Large Truck and Bus Statistics","राज्य का ड्राइवर एजुकेशन पाठ्यपुस्तक"],"explanation":"डेलावेयर का DMV डेलावेयर CDL मैनुअल (AAMVA मॉडल पर आधारित) प्रकाशित करता है, जिसे आवेदकों को परीक्षा से पहले प्राप्त करना और अध्ययन करना चाहिए। स्रोत: Delaware DMV CDL Manual।"},"95":{"q":"डेलावेयर CDL कौशल परीक्षा का ऑन-रोड भाग कैसे निर्धारित किया जाता है, और प्री-ट्रिप भाग को कैसे समर्थन दिया जाता है?","options":["कौशल परीक्षा अपॉइंटमेंट द्वारा होती है, और DMV आवेदकों की सहायता के रूप में एक प्री-ट्रिप निरीक्षण चेकलिस्ट प्रदान करता है","तीनों कौशल भाग वॉक-इन हैं, और कोई चेकलिस्ट प्रदान नहीं की जाती","रोड टेस्ट ऑनलाइन है; ELDT स्नातकों के लिए प्री-ट्रिप माफ़ कर दिया जाता है","निर्धारण केवल आवेदक के नियोक्ता के माध्यम से किया जाता है"],"explanation":"डेलावेयर CDL कौशल परीक्षाएँ केवल अपॉइंटमेंट द्वारा होती हैं, और आधुनिकीकृत कार्यक्रम आवेदकों को प्री-ट्रिप वाहन निरीक्षण परीक्षा के लिए एक अध्ययन सहायता के रूप में चेकलिस्ट प्रदान करता है। स्रोत: Delaware DMV CDL वेबपेज (आधुनिकीकृत कौशल परीक्षा, 26 फ़रवरी, 2025 से प्रभावी)।"},"96":{"q":"यदि इंटरस्टेट नॉन-एक्सेप्टेड के रूप में स्व-प्रमाणित धारक DMV के पास एक वर्तमान मेडिकल परीक्षक प्रमाणपत्र फ़ाइल में रखने में विफल रहता है, तो डेलावेयर CDL के साथ आम तौर पर क्या होता है?","options":["वाणिज्यिक (CDL) विशेषाधिकार डाउनग्रेड कर दिया जाता है ताकि व्यक्ति अब वाणिज्यिक वाहन न चला सके","CDL स्थायी रूप से रद्द कर दिया जाता है और पुनर्बहाल नहीं किया जा सकता","कुछ नहीं, क्योंकि मेडिकल प्रमाणपत्र केवल एक नियोक्ता रिकॉर्ड है","लाइसेंस स्वतः ही इंटरस्टेट एक्सेप्टेड CDL में बदल जाता है"],"explanation":"यदि कोई आवश्यक (नॉन-एक्सेप्टेड) चालक मेडिकल प्रमाणपत्र को समाप्त होने देता है या उसे जमा करने में विफल रहता है, तो राज्य को CDL को डाउनग्रेड करना होगा, जिससे वैध प्रमाणपत्र फ़ाइल में आने तक वाणिज्यिक ड्राइविंग विशेषाधिकार हट जाते हैं। स्रोत: Delaware DMV Self-Certification FAQ; 49 CFR 383.73।"},"97":{"q":"इंटरस्टेट नॉन-एक्सेप्टेड डेलावेयर चालक के लिए, मेडिकल प्रमाणपत्र का समर्थन करने वाली DOT शारीरिक जाँच आम तौर पर कितनी हालिया होनी चाहिए?","options":["पिछले 24 महीनों के भीतर की तिथि (अधिकतम 2-वर्ष का प्रमाणन)","पिछले 6 महीनों के भीतर की तिथि","केवल पिछले 12 महीनों के भीतर की तिथि","पिछले 5 वर्षों के भीतर की तिथि"],"explanation":"DOT शारीरिक जाँच को 49 CFR 391.41-391.49 का पालन करना चाहिए और यह किसी चालक को 24 महीने तक के लिए प्रमाणित कर सकती है (कुछ स्थितियों के लिए मेडिकल परीक्षक कम अवधि के लिए प्रमाणित कर सकता है)। डेलावेयर को यह संघीय मानक आवश्यक है। स्रोत: Delaware DMV Medical Certification पेज; 49 CFR 391.43।"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك أي حمولة، على طرق ولاية ديلاوير السريعة؟","options":["13 قدمًا و6 بوصات","14 قدمًا","13 قدمًا","12 قدمًا و6 بوصات"],"explanation":"يحدد قانون ولاية ديلاوير الحد الأقصى لارتفاع المركبة وحمولتها بـ 13 قدمًا و6 بوصات، سواء على الطرق العامة أو على شبكة الطرق السريعة بين الولايات. المصدر: Delaware Code Title 21, Ch. 45, sections 4502(b) and 4503(b)."},"1":{"q":"باستثناء معدات السلامة، ما هو الحد الأقصى للعرض الخارجي الإجمالي المسموح به لمعظم المركبات التجارية في ولاية ديلاوير؟","options":["102 بوصة","96 بوصة","108 بوصات","120 بوصة"],"explanation":"تحدد ولاية ديلاوير العرض الخارجي الإجمالي للمركبة بـ 102 بوصة (8 أقدام و6 بوصات)، باستثناء معدات السلامة. المصدر: Delaware Code Title 21, sections 4502 and 4503; DelDOT OSOW legal limits."},"2":{"q":"ما هو الحد الأقصى المسموح به لطول نصف المقطورة (باستثناء جرار الشاحنة) التي تعمل في ولاية ديلاوير؟","options":["53 قدمًا","48 قدمًا","57 قدمًا","45 قدمًا"],"explanation":"لا يجوز أن يتجاوز طول نصف المقطورة، بما في ذلك أي حمولة، 53 قدمًا، باستثناء جرار الشاحنة. المصدر: Delaware Code Title 21, Ch. 45, section 4503(b)."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة لتركيبة نموذجية من خمسة محاور أو أكثر في ولاية ديلاوير؟","options":["80,000 رطل","73,280 رطلًا","88,000 رطل","90,000 رطل"],"explanation":"تحدد ولاية ديلاوير الوزن الإجمالي لتركيبة مركبات من خمسة محاور أو أكثر بـ 80,000 رطل، بما يتوافق مع الحد الفيدرالي. المصدر: Delaware Code Title 21, Ch. 45, sections 4502(c) and 4503(c)."},"4":{"q":"على شبكة الطرق السريعة بين الولايات في ولاية ديلاوير، ما هو الحد الأقصى للوزن المسموح به على محور واحد؟","options":["20,000 رطل","22,400 رطلًا","18,000 رطل","24,000 رطل"],"explanation":"على الطرق السريعة بين الولايات، تتبع ولاية ديلاوير الحد الفيدرالي للمحور الواحد البالغ 20,000 رطل. المصدر: Delaware Code Title 21, Ch. 45, section 4503(c)."},"5":{"q":"على شبكة الطرق السريعة بين الولايات في ولاية ديلاوير، ما هو الحد الأقصى للوزن المسموح به على محور مزدوج (تاندم)؟","options":["34,000 رطل","36,000 رطل","40,000 رطل","32,000 رطل"],"explanation":"على الطرق السريعة بين الولايات، يبلغ حد المحور المزدوج (التاندم) 34,000 رطل، بما يطابق المعيار الفيدرالي. المصدر: Delaware Code Title 21, Ch. 45, section 4503(c)."},"6":{"q":"متى يكون تصريح النقل الزائد الحجم/الزائد الوزن الصادر عن Delaware DOT مطلوبًا؟","options":["عندما تتجاوز المركبة أو الحمولة حدود الحجم أو الوزن المنصوص عليها في الفصل 45، الباب 21 من قانون ولاية ديلاوير","فقط عندما يتجاوز الوزن الإجمالي 80,000 رطل، بصرف النظر عن أوزان المحاور","فقط للحمولات التي يزيد عرضها عن 12 قدمًا","فقط عند السير على الطريق السريع Interstate 95"],"explanation":"يُطلب التصريح كلما تجاوزت مركبة أو تركيبة أو معدة ذاتية الدفع الحدود البُعدية و/أو الوزنية المنصوص عليها في الفصل 45، الباب 21 من قانون ولاية ديلاوير، بما في ذلك عندما يكون محور فردي زائد الوزن حتى لو كان الوزن الإجمالي قانونيًا. المصدر: DelDOT OSOW permit FAQ; Delaware Code Title 21, section 4504."},"7":{"q":"كيف يتم الحصول على تصاريح النقل الزائدة الحجم/الزائدة الوزن في ولاية ديلاوير؟","options":["من خلال نظام تصاريح الحجم الزائد/الوزن الزائد (OSOW) الإلكتروني التابع لـ DelDOT والذي يديره مكتب تصاريح النقل","عن طريق إرسال نموذج ورقي بالبريد إلى قسم CDL في Delaware DMV","عن طريق شرائها من أي منضدة لخدمات المركبات في DMV","تصدر تلقائيًا مع تسجيل المركبة"],"explanation":"تصدر تصاريح الحجم الزائد/الوزن الزائد عن DelDOT من خلال نظام تصاريح OSOW الإلكتروني الذي يديره مكتب تصاريح النقل، وليس عن DMV. المصدر: DelDOT OSOW permit system (deldot.gov/osow)."},"8":{"q":"ما هو الحد الأدنى للرسوم لتصريح قياسي لرحلة واحدة زائد الحجم/زائد الوزن في ولاية ديلاوير؟","options":["$30.00","$15.00","$50.00","$10.00"],"explanation":"الحد الأدنى للرسوم لتصريح نقل لرحلة واحدة هو $30.00 ($60.00 للحمولة فائقة الثقل Superload). المصدر: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405 permit policy manual."},"9":{"q":"بالنسبة لتصريح الوزن الزائد في ولاية ديلاوير، كيف يتم احتساب رسوم الوزن الإضافي؟","options":["$10.00 عن كل 8,000 رطل (أو جزء منها) تتجاوز حد الوزن القانوني","$25.00 عن كل 5,000 رطل تتجاوز حد الوزن القانوني","$5.00 عن كل 1,000 رطل تتجاوز حد الوزن القانوني","مبلغ ثابت قدره $100.00 بصرف النظر عن مقدار الوزن الزائد"],"explanation":"تضيف ولاية ديلاوير رسوم وزن قدرها $10.00 عن كل 8,000 رطل، أو جزء منها، تتجاوز حد الوزن القانوني. المصدر: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405."},"10":{"q":"ما هي مدة صلاحية تصريح النقل القياسي لرحلة واحدة زائد الحجم/زائد الوزن في ولاية ديلاوير؟","options":["5 أيام (من تاريخ السريان إلى تاريخ الانتهاء)","24 ساعة","30 يومًا","10 أيام"],"explanation":"تصريح النقل القياسي صالح لمدة خمسة أيام، من تاريخ السريان إلى تاريخ الانتهاء. المصدر: DelDOT OSOW permit FAQ; Delaware Administrative Code 2405."},"11":{"q":"خلال أي ساعات يجوز عمومًا لحمولة زائدة الحجم مصرح بها أن تسير على طرق ولاية ديلاوير السريعة، ما لم ينص التصريح على خلاف ذلك؟","options":["من شروق الشمس إلى غروبها، من الاثنين إلى الأحد","فقط من الاثنين إلى الجمعة خلال ساعات العمل","فقط بين الساعة 9 مساءً و5 صباحًا","في أي وقت، على مدار 24 ساعة يوميًا، دون قيود"],"explanation":"يُصرح للحمولات المرخصة بالتحرك من شروق الشمس إلى غروبها، من الاثنين إلى الأحد، ما لم تنص الأحكام الخاصة بالتصريح على خلاف ذلك. المصدر: DelDOT OSOW permit FAQ."},"12":{"q":"أي معادلة تطبقها ولاية ديلاوير لتحديد الحد الأقصى للوزن الإجمالي على مجموعة من المحاور المتتالية؟","options":["المعادلة الفيدرالية للجسور (Bridge Formula)، W = 500[(LN / (N-1)) + 12N + 36]","مقدار ثابت 1,000 رطل لكل بوصة من عرض الإطار","تصنيف الوزن الإجمالي للمركبة GVWR من الشركة المصنعة مضروبًا في 1.5","ببساطة 20,000 رطل لكل محور دون عامل تباعد"],"explanation":"تعتمد ولاية ديلاوير المعادلة الفيدرالية للجسور (Bridge Formula)، W = 500[(LN / (N-1)) + 12N + 36]، حيث W هو الوزن المسموح به، وL هي المسافة بين المحاور الطرفية للمجموعة، وN هو عدد المحاور. المصدر: Delaware Code Title 21, Ch. 45, section 4503(c)."},"13":{"q":"بموجب قاعدة وزن الجسر في ولاية ديلاوير، يجوز لمجموعتين متتاليتين من المحاور المزدوجة (التاندم) أن تحمل كل منهما 34,000 رطل بشرط أن تكون المسافة بين المحور الأول والأخير للمجموعتين على الأقل:","options":["36 قدمًا","30 قدمًا","40 قدمًا","24 قدمًا"],"explanation":"يسمح استثناء من معادلة الجسر لمجموعتين متتاليتين من المحاور المزدوجة (التاندم) بحمل 34,000 رطل لكل منهما عندما تكون المسافة الإجمالية بين المحور الأول والأخير لتلك المجموعات 36 قدمًا أو أكثر. المصدر: Delaware Code Title 21, Ch. 45, section 4503(c)."},"14":{"q":"على طرق ولاية ديلاوير التي ليست جزءًا من شبكة الطرق السريعة بين الولايات أو شبكة المساعدة الفيدرالية الأساسية، ما هو الحد الأقصى لوزن المحور الواحد؟","options":["22,400 رطلًا","20,000 رطل","18,000 رطل","25,000 رطل"],"explanation":"على الطرق الحكومية غير الطرق السريعة بين الولايات، تسمح ولاية ديلاوير بوزن محور واحد أعلى يبلغ 22,400 رطلًا، مقارنة بـ 20,000 رطل على الطرق السريعة بين الولايات. المصدر: Delaware Code Title 21, Ch. 45, section 4502(c)."},"15":{"q":"تمنح ولاية ديلاوير استثناءً وزنيًا للشاحنات التي تنقل بعض المنتجات الزراعية أو الحبوب داخل الولاية. حتى أي وزن إجمالي يجوز لهذه المركبات أن تعمل؟","options":["90,000 رطل","80,000 رطل","100,000 رطل","85,000 رطل"],"explanation":"تسمح ولاية ديلاوير للشاحنات التي تنقل الفواكه أو الخضروات أو حبوب السلع داخل الولاية بالوصول إلى ما يصل إلى 90,000 رطل (أو تصنيف الوزن الإجمالي المركّب من الشركة المصنعة، أيهما أقل). المصدر: Delaware Code Title 21, Ch. 45, section 4502(c)."},"16":{"q":"يتضمن حكم وزن نقل الدواجن الحية في ولاية ديلاوير هامش تسامح لمراعاة هطول الأمطار والاختلافات في حجم الطيور. ما هي نسبة هذا التفاوت؟","options":["3%","5%","10%","1%"],"explanation":"يجوز للشاحنات التي تنقل الدواجن الحية داخل ولاية ديلاوير أن تعمل بما يصل إلى 90,000 رطل مع تفاوت قدره 3% لاختلافات الوزن الناتجة عن هطول الأمطار وحجم الطيور. المصدر: Delaware Code Title 21, Ch. 45, section 4502(c)."},"17":{"q":"على طرق ولاية ديلاوير غير الطرق السريعة بين الولايات وشبكة المساعدة الفيدرالية الأساسية، ما هو الحد الأقصى لطول مركبة واحدة (وليست تركيبة)؟","options":["40 قدمًا","45 قدمًا","53 قدمًا","35 قدمًا"],"explanation":"على الطرق غير الطرق السريعة بين الولايات، لا يجوز أن يتجاوز طول مركبة واحدة 40 قدمًا، ولا يجوز أن يتجاوز طول تركيبة من المركبات 60 قدمًا. المصدر: Delaware Code Title 21, Ch. 45, section 4502(b)."},"18":{"q":"في تركيبة جرار شاحنة-نصف مقطورة-مقطورة (مزدوجة) في ولاية ديلاوير، ما هو الحد الأقصى لطول كل مقطورة أو نصف مقطورة؟","options":["29 قدمًا","28 قدمًا","33 قدمًا","31 قدمًا"],"explanation":"تقتصر كل مقطورة أو نصف مقطورة في تركيبة جرار-نصف مقطورة-مقطورة على 29 قدمًا، باستثناء الجرار. المصدر: Delaware Code Title 21, Ch. 45, section 4503(b)."},"19":{"q":"عند أي نقطة تُعتبر عملية نقل زائدة الحجم/زائدة الوزن في ولاية ديلاوير حمولة فائقة الثقل (Superload)، والتي تحمل حدًا أدنى أعلى لرسوم التصريح؟","options":["الطول عند 120 قدمًا، والعرض عند 15 قدمًا، والارتفاع عند 15 قدمًا، أو الوزن الإجمالي يتجاوز 120,000 رطل","أي حمولة يزيد وزنها الإجمالي عن 90,000 رطل","أي حمولة يزيد عرضها عن 10 أقدام","الطول يتجاوز 75 قدمًا أو الوزن يتجاوز 100,000 رطل"],"explanation":"تُصنف عملية النقل على أنها حمولة فائقة الثقل (Superload) عندما يصل الطول إلى 120 قدمًا، أو يصل العرض إلى 15 قدمًا، أو يصل الارتفاع إلى 15 قدمًا، أو يتجاوز الوزن الإجمالي 120,000 رطل؛ والحد الأدنى لرسوم تصريح الحمولة فائقة الثقل هو $60.00. المصدر: DelDOT OSOW permit FAQ."},"20":{"q":"في ولاية ديلاوير، أي فئة من CDL مطلوبة لتشغيل تركيبة مركبات بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطل أو أكثر، بشرط أن يكون تصنيف GVWR للوحدة المقطورة يزيد عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير (Version 4.0, \"Types of CDL\") على أن رخصة CDL من الفئة A مطلوبة لأي تركيبة مركبات بتصنيف GVWR يبلغ 26,001 رطل أو أكثر بشرط أن يكون تصنيف GVWR للوحدة (الوحدات) المقطورة يزيد عن 10,000 رطل."},"21":{"q":"بموجب قواعد ولاية ديلاوير، مركبة واحدة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر ولا تقطر وحدة تزيد عن 10,000 رطل تتطلب أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"يعرّف دليل سائق المركبات التجارية في ولاية ديلاوير الفئة B بأنها أي مركبة واحدة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، أو مركبة من هذا القبيل تقطر مركبة لا يتجاوز تصنيف GVWR لها 10,000 رطل."},"22":{"q":"في ولاية ديلاوير، مركبة بتصنيف GVWR أقل من 26,001 رطل ومصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو تحمل مواد خطرة تتطلب لوحات تحذيرية تتطلب أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","لا يلزم CDL"],"explanation":"وفقًا لدليل سائق المركبات التجارية في ولاية ديلاوير، تُطلب رخصة CDL من الفئة C لمركبة بتصنيف GVWR أقل من 26,001 رطل ومصممة لنقل 16 شخصًا أو أكثر بما في ذلك السائق، أو تُستخدم لنقل مواد خطرة تتطلب لوحات تحذيرية."},"23":{"q":"في رخصة CDL لولاية ديلاوير، أي رمز تصديق يُجيز تشغيل مركبة صهريج؟","options":["الرمز N","الرمز T","الرمز H","الرمز P"],"explanation":"يدرج دليل سائق المركبات التجارية في ولاية ديلاوير تصديق الصهريج (Tanker) بالرمز N. التصديق T مخصص للمقطورات المزدوجة/الثلاثية، وH للمواد الخطرة (HazMat)، وP للركاب."},"24":{"q":"أي تصديق CDL في ولاية ديلاوير مطلوب لقطر المقطورات المزدوجة أو الثلاثية؟","options":["التصديق T","التصديق N","التصديق X","التصديق P"],"explanation":"يدرج دليل سائق المركبات التجارية في ولاية ديلاوير تصديق المقطورات المزدوجة/الثلاثية بالرمز T ويتطلب اجتياز اختبار معرفي خاص حول المشكلات المرتبطة بقطر مقطورات متعددة."},"25":{"q":"وفقًا لدليل سائق المركبات التجارية في ولاية ديلاوير، يُطلب تصديق مركبة الصهريج (N) عندما تكون المركبة مصممة لنقل سائل أو غاز في صهريج بسعة فردية مقدّرة تزيد عن 119 غالونًا وسعة إجمالية مقدّرة لا تقل عن كم غالونًا؟","options":["500 غالون","750 غالونًا","1,000 غالون","1,500 غالون"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أن تصديق مركبة الصهريج (N) ينطبق على الصهاريج ذات السعة الفردية المقدّرة التي تزيد عن 119 غالونًا والسعة الإجمالية المقدّرة البالغة 1,000 غالون أو أكثر."},"26":{"q":"في ولاية ديلاوير، ما هو الحد الأدنى للسن للحصول على رخصة CDL للقيادة داخل الولاية (داخل ولاية ديلاوير فقط)؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"تنص متطلبات CDL الأساسية في دليل سائق المركبات التجارية في ولاية ديلاوير على أنه يجب أن يكون عمر مقدم الطلب 18 عامًا ولديه خبرة قيادة لمدة عام واحد للقيادة داخل الولاية."},"27":{"q":"بموجب متطلبات CDL الأساسية في ولاية ديلاوير، ما هو الحد الأدنى للسن المطلوب للقيادة في التجارة بين الولايات أو لنقل المواد الخطرة؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"يتطلب دليل سائق المركبات التجارية في ولاية ديلاوير أن يكون عمر مقدم الطلب 21 عامًا ولديه ما لا يقل عن عام واحد من خبرة القيادة للقيادة في التجارة بين الولايات أو لنقل المواد الخطرة."},"28":{"q":"بعد اجتياز الاختبارات المعرفية، كم من الوقت يجب أن يحتفظ حامل تصريح المتعلم التجاري (CLP) في ولاية ديلاوير بتصريح CLP قبل أن يُسمح له بإجراء اختبار مهارات CDL؟","options":["ما لا يقل عن 14 يومًا كاملًا","ما لا يقل عن 10 أيام كاملة","ما لا يقل عن 7 أيام كاملة","ما لا يقل عن 30 يومًا كاملًا"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أنه يجب عليك الاحتفاظ بتصريح CLP الخاص بك لمدة لا تقل عن 14 يومًا كاملًا قبل أن تتمكن من إجراء اختبار مهارات CDL، بما يطابق المتطلب الفيدرالي 49 CFR 383."},"29":{"q":"عند القيادة بتصريح المتعلم التجاري (CLP) في ولاية ديلاوير، يجب أن يكون الحامل مصحوبًا بمن؟","options":["أي سائق مرخص يبلغ من العمر 18 عامًا أو أكثر","سائق CDL مرخص ومؤهل في نفس نوع المركبة التجارية CMV","فاحص معتمد من DMV فقط","لا أحد؛ يسمح تصريح CLP بالقيادة المنفردة"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أن تصريح CLP يسمح لك بقيادة مركبة تجارية CMV مصحوبًا بسائق CDL مرخص آخر، ولا يجوز لك إلا قيادة نوع المركبة الذي اختُبرت عليه مع سائق CDL مؤهل في نفس نوع المركبة التجارية CMV."},"30":{"q":"قبل إصدار رخصة CDL في ولاية ديلاوير مع تصديق المواد الخطرة (H)، ما الذي يجب على مقدم الطلب إكماله أولًا؟","options":["دورة قيادة دفاعية في DMV","فترة انتظار مدتها 30 يومًا بعد اختبار المهارات","تقييم تهديد أمني من TSA يشمل أخذ البصمات","اختبار طريق منفصل في مركبة تحمل لوحات تحذيرية"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أنه لا يجوز إصدار رخصة CDL مع تصديق المواد الخطرة (HazMat) ما لم يخضع مقدم الطلب أولًا لتقييم التهديد الأمني من TSA (بما في ذلك أخذ البصمات والتحقق من الجنسية/الوجود القانوني) ويحصل على موافقة TSA."},"31":{"q":"بموجب قاعدة التدريب الفيدرالية لسائقي المستوى المبتدئ (ELDT) المطبقة في ولاية ديلاوير، يجب أن يُقدَّم التدريب من قبل مدرسة مدرجة في أي سجل؟","options":["قائمة المدارس المعتمدة من Delaware DMV","دليل المدربين التابع لـ AAMVA","سجل مقدمي التدريب التابع لـ FMCSA (TPR)","سجل المدربين المعتمدين من TSA"],"explanation":"تنص صفحة ELDT الخاصة بـ Delaware DMV على أنه يجب إكمال تدريب سائق المستوى المبتدئ من خلال مقدم مسجل لدى FMCSA ومدرج في سجل مقدمي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov) قبل أن يتمكن مقدم الطلب من إجراء اختبار مهارات CDL."},"32":{"q":"أي مما يلي تتطلب ولاية ديلاوير له تدريب ELDT (تدريب سائق المستوى المبتدئ) قبل أن يتسنى إجراء اختبار المهارات/المعرفة؟","options":["إضافة تصديق الصهريج (N)","إضافة تصديق المقطورات المزدوجة/الثلاثية (T)","تجديد رخصة CDL قائمة","الحصول على رخصة CDL من الفئة A أو الفئة B لأول مرة"],"explanation":"وفقًا لصفحة ELDT الخاصة بـ Delaware DMV (السارية اعتبارًا من 7 فبراير 2022)، يُطلب تدريب ELDT لمقدمي طلبات الفئة A أو B لأول مرة، والترقيات إلى فئة أعلى، وتصديقات S وP وH. وهو غير مطلوب لتصديقي N أو T أو للتجديدات."},"33":{"q":"تتطلب ولاية ديلاوير من حاملي رخصة CDL التصديق الذاتي على نوع قيادتهم. كم عدد فئات التصديق الذاتي؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أنه يجب على حاملي رخصة CDL التصديق ذاتيًا على حالة قيادة هي: بين الولايات غير معفاة، أو داخل الولاية غير معفاة، أو بين الولايات معفاة، أو داخل الولاية معفاة — أربع فئات."},"34":{"q":"مقدم طلب CDL في ولاية ديلاوير يقود مركبة تجارية CMV في التجارة بين الولايات ويخضع لقواعد التأهيل البدني الفيدرالية يصدّق على أي فئة من فئات التصديق الذاتي الطبي؟","options":["بين الولايات غير معفاة","بين الولايات معفاة","داخل الولاية غير معفاة","داخل الولاية معفاة"],"explanation":"يوضح دليل سائق المركبات التجارية في ولاية ديلاوير أن حاملي رخصة CDL الذين يقودون مركبات تجارية CMV في التجارة بين الولايات ويجب عليهم استيفاء متطلب الشهادة الطبية الفيدرالية هم سائقو تجارة بين الولايات غير معفاة."},"35":{"q":"عندما يُصدر تصريح CLP في ولاية ديلاوير مع تصديق الركاب (P)، أي قيد يجب أن يحمله أيضًا؟","options":["قيد 'K' داخل الولاية فقط","قيد 'L' لا فرامل هوائية","قيد 'P' لا ركاب في حافلة CMV","قيد 'E' لا ناقل حركة يدوي"],"explanation":"يشير دليل سائق المركبات التجارية في ولاية ديلاوير إلى أنه إذا صدر تصريح CLP مع تصديق الركاب (P) أو الحافلة المدرسية (S)، فيجب أن يحتوي أيضًا على قيد 'P' – لا ركاب في حافلة CMV (يسمح فقط بوجود الأفراد المحددين على متنها)."},"36":{"q":"إذا صدر تصريح CLP في ولاية ديلاوير مع تصديق الصهريج (N)، أي قيد إضافي يوضع عليه؟","options":["'X' – لا حمولة في مركبة صهريج CMV","'Z' – لا مركبة CMV مجهزة بفرامل هوائية كاملة","'V' – استثناء طبي","'O' – لا مركبة CMV من نوع الجرار-المقطورة"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أن تصريح CLP الصادر مع تصديق الصهريج (N) يجب أن يحتوي أيضًا على قيد 'X' – لا حمولة في مركبة صهريج CMV، بمعنى أنه لا يجوز للحامل تشغيل سوى مركبة صهريج فارغة ومطهّرة."},"37":{"q":"ما هي الوثائق التي تطلب Delaware DMV من مقدم الطلب تقديمها بشأن الإقامة في ولاية ديلاوير عند التقدم بطلب للحصول على رخصة؟","options":["إثبات واحد للإقامة في ولاية ديلاوير","ثلاثة إثباتات للإقامة في ولاية ديلاوير","إقرار إقامة موثّق فقط","إثباتان للإقامة في ولاية ديلاوير"],"explanation":"تتطلب Delaware DMV من مقدمي الطلبات تقديم إثبات الهوية (وثيقة أساسية واحدة وأخرى ثانوية)، ورقم ضمان اجتماعي إن كان مؤهلًا، وإثباتين للإقامة في ولاية ديلاوير؛ كما يجب على غير المواطنين الأمريكيين إظهار إثبات الوجود القانوني (متطلبات وثائق رخصة القيادة/الهوية في Delaware DMV)."},"38":{"q":"بموجب قواعد ولاية ديلاوير، ما المطلوب من الشخص الذي يرغب في قيادة حافلة مدرسية؟","options":["فقط رخصة CDL من الفئة C دون أي تصديقات","رخصة CDL مع كل من تصديق الركاب (P) وتصديق الحافلة المدرسية (S)، بالإضافة إلى متطلبات وزارة التعليم","رخصة قياسية من الفئة D مع ملصق حافلة مدرسية","تصديق الصهريج (N) وفحص خلفية من TSA"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أنه يجب أن يكون لدى جميع سائقي الحافلات المدرسية في ولاية ديلاوير رخصة CDL واستيفاء متطلبات التدريب والمتطلبات الطبية الإضافية لوزارة التعليم في ولاية ديلاوير؛ ثم تصدر DMV رخصة CDL مع تصديقي P وS (مع قيد M أو N حسب فئة المركبة)."},"39":{"q":"تقدم ولاية ديلاوير اعتمادًا خاصًا من غير نوع CDL بموجب أحكام الإعفاء الفيدرالية من CDL لأي مجموعة من السائقين الذين يشغّلون مركبة تجارية CMV؟","options":["سائقو الشاحنات لمسافات طويلة بين الولايات","مشغلو صهاريج المواد الخطرة","سائقو حافلات النقل المستأجرة","المزارعون ورجال الإطفاء"],"explanation":"ينص دليل سائق المركبات التجارية في ولاية ديلاوير على أن ولاية ديلاوير لديها رخصة خاصة من غير نوع CDL لتحديد المزارعين ورجال الإطفاء الذين يشغّلون مركبات تجارية CMV بموجب أحكام الإعفاء من CDL؛ ولا يجوز استخدام هذه الرخصة من غير نوع CDL في التجارة بين الولايات أو في حالات النقل مقابل أجر."},"40":{"q":"في ولاية ديلاوير، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونًا تشغيل مركبة تجارية (CMV)؟","options":["0.02 بالمئة","0.04 بالمئة","0.08 بالمئة","0.10 بالمئة"],"explanation":"تجعل ولاية ديلاوير من غير القانوني تشغيل مركبة تجارية CMV بتركيز BAC يبلغ 0.04 بالمئة أو أكثر، أي نصف الحد البالغ 0.08 للمركبات الخاصة. المصدر: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"41":{"q":"بموجب قانون الموافقة الضمنية في ولاية ديلاوير، عندما يشغّل شخص مركبة تجارية في الولاية، يُعتبر أنه أعطى موافقته على ماذا؟","options":["تفتيش حمولة المركبة","الاختبار لتركيز الكحول","فحص اللياقة الطبية","الإفراج عن سجلات توظيفه"],"explanation":"بتشغيل مركبة تجارية CMV في ولاية ديلاوير، يُعتبر السائق قد وافق على اختبار الكحول (الاختبار الكيميائي). المصدر: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614 (implied consent for CMV drivers)."},"42":{"q":"كم تبلغ مدة إيقاف رخصة CDL لحامل CDL في ولاية ديلاوير لأول مخالفة جسيمة، مثل قيادة مركبة تجارية CMV بتركيز BAC يبلغ 0.04 أو أعلى، عندما لا يكون ناقلًا لمواد خطرة؟","options":["60 يومًا","120 يومًا","سنة واحدة","3 سنوات"],"explanation":"تؤدي أول مخالفة جسيمة إلى إيقاف رخصة CDL لمدة سنة واحدة في ولاية ديلاوير. المصدر: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612 (المعيار الفيدرالي 49 CFR 383.51 المطبق من قبل الولاية)."},"43":{"q":"في ولاية ديلاوير، تزداد مدة إيقاف الرخصة لأول مخالفة جسيمة إلى ثلاث سنوات عندما تقع المخالفة أثناء قيادة السائق لمركبة تجارية CMV تقوم بماذا؟","options":["تحمل لوحات تحذيرية للمواد الخطرة","تنقل ركابًا مقابل أجر","تقطر مقطورة مزدوجة","تعبر حدود الولايات"],"explanation":"ترفع أول مخالفة جسيمة تُرتكب أثناء تشغيل مركبة تجارية CMV تحمل لوحات تحذيرية للمواد الخطرة مدة الإيقاف من سنة واحدة إلى 3 سنوات. المصدر: Delaware CDL Manual Section 1.3.2; 49 CFR 383.51."},"44":{"q":"ما هي مدة إيقاف رخصة CDL في ولاية ديلاوير لمخالفة جسيمة ثانية (على سبيل المثال، إدانة ثانية بالقيادة تحت تأثير الكحول)؟","options":["3 سنوات","10 سنوات","مدى الحياة","5 سنوات"],"explanation":"تؤدي المخالفة الجسيمة الثانية في أي مركبة إلى إيقاف رخصة CDL مدى الحياة في ولاية ديلاوير. المصدر: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2612; 49 CFR 383.51."},"45":{"q":"بموجب قواعد CDL في ولاية ديلاوير، يُعامل رفض الخضوع لاختبار كحول/كيميائي مطلوب أثناء تشغيل مركبة تجارية CMV على أنه أي نوع من المخالفات؟","options":["مخالفة مرورية خطيرة","مخالفة جسيمة","مخالفة إيقاف عن الخدمة","مخالفة غير قابلة للإبلاغ"],"explanation":"يُدرج رفض الخضوع لاختبار الكحول في الدم ضمن المخالفات الجسيمة، ويحمل إيقافًا لا يقل عن سنة واحدة لأول مخالفة. المصدر: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"46":{"q":"بموجب تحذير الموافقة الضمنية لسائقي المركبات التجارية CMV في ولاية ديلاوير، يؤدي رفض اختبار الكحول إلى الإيقاف الفوري عن الخدمة لمدة كم، بالإضافة إلى إيقاف الرخصة؟","options":["8 ساعات","12 ساعة","24 ساعة","48 ساعة"],"explanation":"يتطلب قانون ولاية ديلاوير من الضابط تحذير السائق من أن الرفض يؤدي إلى الإيقاف الفوري عن الخدمة لمدة 24 ساعة وإيقاف الرخصة لمدة لا تقل عن سنة واحدة. المصدر: 21 Del. C. Section 2614."},"47":{"q":"وُجد سائق مركبة تجارية CMV في ولاية ديلاوير بتركيز BAC يبلغ 0.02 (كمية قابلة للقياس من الكحول أقل من 0.04). ما هو الإجراء المطلوب؟","options":["إيقاف رخصة CDL لمدة 60 يومًا","الإيقاف عن الخدمة لمدة 24 ساعة","إيقاف رخصة CDL لمدة سنة واحدة","إيقاف رخصة CDL مدى الحياة"],"explanation":"أي كمية قابلة للكشف من الكحول أقل من 0.04 (كمية قابلة للقياس من 0.02 إلى أقل من 0.04) تتطلب إيقاف السائق عن الخدمة لمدة 24 ساعة. المصدر: Delaware CDL Manual Section 1.3.2; 21 Del. C. Section 2614."},"48":{"q":"أي مما يلي يُصنف على أنه مخالفة مرورية خطيرة بموجب قواعد CDL في ولاية ديلاوير؟","options":["قيادة مركبة تجارية CMV بتركيز BAC يبلغ 0.04","السرعة المفرطة بمقدار 15 mph أو أكثر فوق الحد المسموح","مغادرة مكان الحادث","انتهاك أمر الإيقاف عن الخدمة"],"explanation":"السرعة المفرطة (15 mph أو أكثر فوق الحد المعلن) هي مخالفة مرورية خطيرة. أما العناصر الأخرى المدرجة فهي مخالفات جسيمة أو مخالفات إيقاف عن الخدمة. المصدر: Delaware CDL Manual Section 1.3.3."},"49":{"q":"في ولاية ديلاوير، كم تبلغ مدة إيقاف رخصة CDL بسبب الإدانة بمخالفتين مروريتين خطيرتين في مركبة تجارية CMV خلال فترة ثلاث سنوات؟","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال أي فترة ثلاث سنوات إلى إيقاف رخصة CDL لمدة 60 يومًا. المصدر: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51."},"50":{"q":"ما هي مدة إيقاف رخصة CDL في ولاية ديلاوير بسبب الإدانة بثلاث مخالفات مرورية خطيرة أو أكثر في مركبة تجارية CMV خلال فترة ثلاث سنوات؟","options":["60 يومًا","90 يومًا","120 يومًا","180 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة أو أكثر خلال أي فترة ثلاث سنوات إلى إيقاف رخصة CDL لمدة 120 يومًا. المصدر: Delaware CDL Manual Section 1.3.3; 49 CFR 383.51."},"51":{"q":"أي من هذه يُعد مخالفة مرورية خطيرة بموجب قواعد CDL في ولاية ديلاوير وليس مخالفة جسيمة؟","options":["اتباع مركبة عن قرب شديد","استخدام مركبة تجارية CMV لارتكاب جناية","التسبب في وفاة بسبب تشغيل مركبة تجارية CMV بإهمال","قيادة مركبة تجارية CMV تحت تأثير مادة خاضعة للرقابة"],"explanation":"اتباع مركبة عن قرب شديد هو مخالفة مرورية خطيرة. أما الثلاثة الأخرى فهي مخالفات جسيمة. المصدر: Delaware CDL Manual Section 1.3.3 (خطيرة) and Section 1.3.2 (جسيمة)."},"52":{"q":"تُعامل المراسلة النصية أو استخدام هاتف محمول يدوي أثناء تشغيل مركبة تجارية CMV بموجب قواعد CDL في ولاية ديلاوير على أنها أي نوع من المخالفات؟","options":["مخالفة جسيمة","مخالفة مرورية خطيرة","انتهاك أمر الإيقاف عن الخدمة","مخالفة معبر سكة حديد"],"explanation":"المراسلة النصية أو استخدام هاتف يدوي أثناء تشغيل مركبة تجارية CMV هي مخالفة مرورية خطيرة وتُحتسب ضمن عتبات الإيقاف البالغة 60 يومًا/120 يومًا. المصدر: Delaware CDL Manual Section 1.3.3 وقسم المراسلة النصية/الهاتف; 49 CFR 383.51."},"53":{"q":"بموجب قواعد CDL في ولاية ديلاوير/الفيدرالية، تُوقف رخصة CDL لمدة 60 يومًا بعد كم عدد من الإدانات باستخدام هاتف محمول يدوي أثناء تشغيل مركبة تجارية CMV (خلال 3 سنوات)؟","options":["إدانة واحدة","إدانتان أو أكثر","أربع إدانات","خمس إدانات"],"explanation":"تؤدي إدانتان أو أكثر بقانون الهاتف اليدوي أثناء تشغيل مركبة تجارية CMV خلال 3 سنوات إلى إيقاف لمدة 60 يومًا (120 يومًا لثلاث إدانات أو أكثر). المصدر: قسم الهاتف المحمول اليدوي في Delaware CDL Manual; 49 CFR 383.51."},"54":{"q":"ما هو الحد الأقصى للعقوبة المدنية الفيدرالية التي قد يواجهها سائق مركبة تجارية CMV لمخالفة المراسلة النصية أثناء القيادة، كما هو مذكور في Delaware CDL Manual؟","options":["حتى $750","حتى $1,500","حتى $2,750","حتى $11,000"],"explanation":"ينص Delaware CDL Manual على أن السائقين يخضعون لعقوبات مدنية تصل إلى $2,750 لمخالفات المراسلة النصية/الهاتف اليدوي (وأصحاب العمل حتى $11,000). المصدر: قسم المراسلة النصية والهاتف المحمول اليدوي في Delaware CDL Manual."},"55":{"q":"كم تبلغ مدة إيقاف رخصة CDL في ولاية ديلاوير لأول إدانة بمخالفة معبر السكة الحديد مع الطريق السريع في مركبة تجارية CMV؟","options":["لا تقل عن 30 يومًا","لا تقل عن 60 يومًا","لا تقل عن 120 يومًا","لا تقل عن سنة واحدة"],"explanation":"تحمل أول مخالفة لمعبر السكة الحديد مع الطريق السريع إيقافًا لا يقل عن 60 يومًا. المصدر: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"56":{"q":"في ولاية ديلاوير، تؤدي مخالفة معبر السكة الحديد مع الطريق السريع الثانية في مركبة تجارية CMV خلال ثلاث سنوات إلى إيقاف رخصة CDL لمدة لا تقل عن كم؟","options":["60 يومًا","120 يومًا","180 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفة معبر السكة الحديد الثانية خلال أي فترة ثلاث سنوات إلى إيقاف لا يقل عن 120 يومًا. المصدر: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"57":{"q":"يرتكب سائق مركبة تجارية CMV في ولاية ديلاوير مخالفة معبر السكة الحديد مع الطريق السريع الثالثة خلال ثلاث سنوات. تُوقف رخصة CDL لمدة لا تقل عن كم؟","options":["120 يومًا","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"تؤدي مخالفة معبر السكة الحديد الثالثة خلال أي فترة ثلاث سنوات إلى إيقاف لا يقل عن سنة واحدة. المصدر: Delaware CDL Manual Section 1.3.5; 49 CFR 383.51."},"58":{"q":"بموجب قواعد CDL في ولاية ديلاوير، ما هو نطاق الإيقاف لأول إدانة بانتهاك أمر الإيقاف عن الخدمة في مركبة تجارية CMV (لا تنقل مواد خطرة)؟","options":["لا يقل عن 30 يومًا ولا يزيد عن 90 يومًا","لا يقل عن 180 يومًا ولا يزيد عن سنة واحدة","لا يقل عن سنة واحدة ولا يزيد عن سنتين","لا يقل عن 3 سنوات ولا يزيد عن 5 سنوات"],"explanation":"يحمل أول انتهاك لأمر الإيقاف عن الخدمة إيقافًا لا يقل عن 180 يومًا ولا يزيد عن سنة واحدة. المصدر: قسم مخالفات MCSIA الموجبة للإيقاف في Delaware CDL Manual; 49 CFR 383.51."},"59":{"q":"بموجب قانون \"ابتعد\" (Move Over) في ولاية ديلاوير، عندما تقترب من مركبة متوقفة تابعة لـ DelDOT أو الشرطة أو القطر أو مركبة طوارئ تعرض أضواء تحذير على طريق سريع به أربعة مسارات أو أكثر في اتجاهك، فما الذي يجب عليك فعله أولاً؟","options":["تغيير المسار إلى مسار غير مجاور للمركبة المتوقفة، إذا كان من الآمن القيام بذلك","التوقف توقفاً تاماً حتى تغادر المركبة المتوقفة الكتف","الانتقال إلى الكتف والمرور بسرعة لا تزيد عن 10 mph","البقاء في مسارك وإطلاق منبه السيارة باستمرار أثناء المرور"],"explanation":"يتطلب الباب 21 § 4134(b) من قانون ديلاوير أن يفسح السائقون على طريق به أربعة مسارات على الأقل في الاتجاه نفسه المجال عن طريق الانتقال إلى مسار غير مجاور للمركبة المتوقفة من مركبات الطوارئ/DelDOT/القطر/المرافق عندما يكون ذلك آمناً. المصدر: 21 Del. C. § 4134."},"60":{"q":"بموجب قانون \"ابتعد\" (Move Over) في ولاية ديلاوير، إذا لم تتمكن من تغيير المسار بأمان بعيداً عن مركبة طوارئ متوقفة، فما تخفيض السرعة المطلوب حيث يكون الحد الأقصى المعلن 50 mph أو أعلى؟","options":["التخفيف إلى سرعة آمنة تقل بمقدار 20 mph على الأقل عن حد السرعة المعلن","التخفيف إلى سرعة آمنة تقل بمقدار 10 mph على الأقل عن حد السرعة المعلن","التخفيف إلى نصف حد السرعة المعلن بالضبط","التخفيف إلى ما لا يزيد عن 25 mph بغض النظر عن الحد المعلن"],"explanation":"يتطلب 21 Del. C. § 4134(b) أنه، عندما يتعذر تغيير المسار، يخفّض السائق سرعته إلى سرعة آمنة تقل بمقدار 20 mph على الأقل عن الحد المعلن حيث يكون الحد 50 mph أو أعلى. المصدر: 21 Del. C. § 4134."},"61":{"q":"عندما تتوقف حافلة مدرسية في ديلاوير على طريق غير مقسوم بمسارين مع وميض أضوائها الحمراء، فأي السائقين يجب عليهم التوقف؟","options":["السائقون المقتربون من الأمام ومن الخلف على حد سواء","فقط السائقون المقتربون من الخلف (الاتجاه نفسه للحافلة)","فقط السائقون المقتربون من الأمام (القادمون عكس الاتجاه)","فقط السائقون الموجودون على بعد 20 قدماً من الحافلة"],"explanation":"يتطلب الباب 21 § 4166 من قانون ديلاوير من سائق أي مركبة تقترب من حافلة مدرسية متوقفة من الأمام أو من الخلف أن يتوقف قبل تجاوز الحافلة عند تشغيل أضواء التوقف الحمراء. المصدر: 21 Del. C. § 4166."},"62":{"q":"على طريق (أو طرق) في ديلاوير به أربعة مسارات أو أكثر، أي سائق مقترب غير مُلزَم بالتوقف لحافلة مدرسية تعرض أضواء حمراء وامضة؟","options":["السائق المقترب من الأمام (الاتجاه القادم عكسياً)","السائق المقترب من الخلف (الاتجاه نفسه للحافلة)","كل من السائق الأمامي والخلفي مُعفى","لا أحد من السائقين مُعفى؛ يجب على كليهما التوقف دائماً"],"explanation":"ينص 21 Del. C. § 4166 على أنه على طريق أو طرق بها 4 مسارات أو أكثر، لا يلزم السائق المقترب من الأمام (الاتجاه المعاكس) التوقف؛ أما السائق المقترب من الخلف فيظل ملزماً بالتوقف. المصدر: 21 Del. C. § 4166."},"63":{"q":"بعد التوقف لحافلة مدرسية في ديلاوير مع وميض أضوائها الحمراء، كم من الوقت يجب على السائق أن يبقى متوقفاً؟","options":["حتى تبدأ الحافلة بالتحرك أو يتوقف عرض أضواء التوقف الحمراء لديها","لمدة لا تقل عن 30 ثانية كحد أدنى ثابت","حتى يلوّح سائق الحافلة لحركة المرور بالتقدم","حتى يبتعد جميع الأطفال مسافة 100 قدم على الأقل عن الحافلة"],"explanation":"يتطلب 21 Del. C. § 4166 من السائق أن يبقى متوقفاً حتى تبدأ الحافلة بالتحرك أو لم تعد تعرض أضواء التوقف الحمراء المُشغَّلة لديها. المصدر: 21 Del. C. § 4166."},"64":{"q":"وفقاً لدليل CDL في ديلاوير، عندما يجب على مركبة تحمل لافتات مواد خطرة (HazMat) أن تتوقف عند معبر سكة حديد لا يوجد به خط توقف مرسوم، فأين يجب أن تتوقف بالنسبة لأقرب قضيب سكة؟","options":["على مسافة لا تقل عن 15 قدماً ولا تزيد عن 50 قدماً من أقرب قضيب سكة","على مسافة لا تقل عن 10 أقدام ولا تزيد عن 25 قدماً من أقرب قضيب سكة","على مسافة لا تقل عن 25 قدماً ولا تزيد عن 75 قدماً من أقرب قضيب سكة","على مسافة لا تقل عن 5 أقدام ولا تزيد عن 35 قدماً من أقرب قضيب سكة"],"explanation":"ينص دليل CDL في ديلاوير (القسم 2.15) على أن المركبات المطلوب منها التوقف يجب أن تتوقف على مسافة لا تقل عن 15 قدماً ولا تزيد عن 50 قدماً من أقرب قضيب من أقرب مسار سكة. المصدر: Delaware CDL Manual, Sec. 2.15."},"65":{"q":"وفقاً لدليل CDL في ديلاوير، أثناء عبور أي جزء من مركبتك التجارية لخطوط سكة الحديد، أي مما يلي يجب ألا تفعله؟","options":["تغيير التروس أثناء عبور الخطوط","إبقاء كلتا يديك على عجلة القيادة","العبور فقط بعد التأكد من خلو جميع الخطوط","استخدام مسار جانبي للتوقف عند توافره"],"explanation":"يوجّه دليل CDL في ديلاوير (القسم 2.15) السائقين بعدم تغيير التروس أثناء عبور خطوط سكة الحديد، لتجنب توقف المحرك على المعبر. المصدر: Delaware CDL Manual, Sec. 2.15."},"66":{"q":"بموجب دليل CDL في ديلاوير، إذا تعيّن على مركبتك التجارية التوقف على طريق سريع باتجاه واحد أو مقسوم، فعلى أي مسافات يجب أن تضع أجهزة التحذير الثلاثة الخاصة بك؟","options":["10 أقدام، و100 قدم، و200 قدم باتجاه حركة المرور المقتربة","10 أقدام، و50 قدماً، و150 قدماً باتجاه حركة المرور المقتربة","25 قدماً، و100 قدم، و250 قدماً باتجاه حركة المرور المقتربة","10 أقدام، و100 قدم، و100 قدم (واحد أماماً وواحد خلفاً)"],"explanation":"يوجّه دليل CDL في ديلاوير (القسم 2.5) بأنه على طريق سريع باتجاه واحد أو مقسوم توضع أجهزة التحذير على مسافات 10 و100 و200 قدم باتجاه حركة المرور المقتربة. المصدر: Delaware CDL Manual, Sec. 2.5."},"67":{"q":"بموجب دليل CDL في ديلاوير، على طريق غير مقسوم بمسارين يحمل حركة المرور في كلا الاتجاهين، أين تضع أجهزة التحذير بعد التوقف؟","options":["في حدود 10 أقدام من المركبة، و100 قدم خلفها و100 قدم أمامها","200 قدم خلفها و200 قدم أمامها، دون أي جهاز قرب المركبة","جهاز واحد فقط على بعد 100 قدم خلف المركبة","10 أقدام، و100 قدم، و200 قدم، جميعها خلف المركبة"],"explanation":"يوجّه دليل CDL في ديلاوير (القسم 2.5) بوضع جهاز في حدود 10 أقدام من الزاوية الأمامية أو الخلفية وأجهزة على بعد 100 قدم خلف و100 قدم أمام المركبة على طريق بمسارين/غير مقسوم. المصدر: Delaware CDL Manual, Sec. 2.5."},"68":{"q":"بموجب دليل CDL في ديلاوير، في غضون كم دقيقة بعد التوقف على الطريق أو الكتف يجب أن تضع أجهزة التحذير من الطوارئ الخاصة بك؟","options":["10 دقائق","5 دقائق","15 دقيقة","30 دقيقة"],"explanation":"يتطلب دليل CDL في ديلاوير (القسم 2.5) أن توضع أجهزة التحذير من الطوارئ في غضون 10 دقائق من التوقف على طريق أو كتف. المصدر: Delaware CDL Manual, Sec. 2.5."},"69":{"q":"وفقاً لدليل CDL في ديلاوير، ما معدات التحذير التي يجب أن تحملها المركبة التجارية للاستخدام عند الوقوف أو التعطل؟","options":["ثلاثة مثلثات عاكسة، أو ما لا يقل عن 6 شُعَل (fusees)، أو 3 شُعَل سائلة الاحتراق","مثلثان عاكسان وعَلَم أحمر واحد","أربعة مثلثات عاكسة فقط","مثلث عاكس واحد ومنارة تعمل بالبطارية"],"explanation":"يُدرج دليل CDL في ديلاوير معدات الطوارئ المطلوبة على أنها ثلاثة مثلثات عاكسة، أو ما لا يقل عن 6 شُعَل، أو 3 شُعَل سائلة الاحتراق. المصدر: Delaware CDL Manual, Sec. 2.1 (الفحص)."},"70":{"q":"بموجب دليل CDL في ديلاوير، إذا حال تل أو منعطف دون رؤية السائقين القادمين خلفك لمركبتك المتوقفة في حدود 500 قدم، فماذا يجب أن تفعل بمثلث التحذير الخلفي الأبعد لديك؟","options":["نقله إلى الخلف أبعد على الطريق، خلف العائق، بحيث يتوفر التحذير","تركه عند مسافة 100 قدم القياسية وإضافة مثلث رابع","وضعه على غطاء محرك المركبة لزيادة وضوحه","إزالته والاعتماد فقط على أضواء التحذير الرباعية"],"explanation":"يقول دليل CDL في ديلاوير (القسم 2.5) إنه عندما يحجب تل أو منعطف الرؤية في حدود 500 قدم، انقل المثلث الخلفي الأبعد إلى الخلف خلف العائق بحيث يحصل السائقون القادمون خلفك على التحذير. المصدر: Delaware CDL Manual, Sec. 2.5."},"71":{"q":"بموجب الباب 21 من قانون ديلاوير، ما حد السرعة القانوني على طريق بمسارين حيث لا يوجد حد آخر معلن؟","options":["50 mph","55 mph","45 mph","60 mph"],"explanation":"يحدد الباب 21 § 4169 من قانون ديلاوير سرعة 50 mph على الطرق بمسارين (و55 mph على الطرق بأربعة مسارات والمقسومة) ما لم يُعلَن خلاف ذلك. المصدر: 21 Del. C. § 4169."},"72":{"q":"بموجب الباب 21 من قانون ديلاوير، ما حد السرعة القانوني على طريق بأربعة مسارات أو مقسوم حيث لا يوجد حد آخر معلن؟","options":["55 mph","50 mph","60 mph","65 mph"],"explanation":"يحدد الباب 21 § 4169 من قانون ديلاوير سرعة 55 mph على الطرق بأربعة مسارات والمقسومة ما لم يُعلَن خلاف ذلك. المصدر: 21 Del. C. § 4169."},"73":{"q":"بموجب الباب 21 من قانون ديلاوير، ما حد السرعة في منطقة تجارية أو سكنية ما لم يُعلَن خلاف ذلك؟","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"يحدد الباب 21 § 4169 من قانون ديلاوير سرعة 25 mph في المناطق التجارية و25 mph في المناطق السكنية ما لم يُعلَن خلاف ذلك. المصدر: 21 Del. C. § 4169."},"74":{"q":"على أي طريق في ديلاوير حددت وزارة النقل حداً أقصى للسرعة قدره 65 mph بين Red Lion Creek ونهر Appoquinimink؟","options":["طريق ولاية ديلاوير رقم 1 (Delaware State Route 1)","Interstate 495","U.S. Route 13","Interstate 295"],"explanation":"يوجّه الباب 21 § 4169 من قانون ديلاوير DelDOT بتحديد حد أقصى قدره 65 mph على الجزء من Route 1 بين Red Lion Creek ونهر Appoquinimink (باستثناء منطقة محطة الرسوم). المصدر: 21 Del. C. § 4169."},"75":{"q":"بموجب قانون تقييد السير في المسارات في ديلاوير (§ 4114A)، أي المركبات يجوز لها عموماً السير فقط في المسار الأيمن على Route 1 وInterstate 495؟","options":["مركبة يزيد تصنيف وزنها الإجمالي للمركبة عن 26,000 pounds","مركبة يزيد تصنيف وزنها الإجمالي للمركبة عن 10,000 pounds","أي مركبة تقطر مقطورة من أي حجم","مركبة بثلاثة محاور أو أكثر بغض النظر عن الوزن"],"explanation":"يقيّد الباب 21 § 4114A من قانون ديلاوير المركبات التي يزيد تصنيف وزنها الإجمالي (GVWR) عن 26,000 pounds بالمسار الأيمن على الأجزاء السريعة/المحدودة الوصول من SR 1 وI-495، مع استثناءات محدودة. المصدر: 21 Del. C. § 4114A."},"76":{"q":"بموجب § 4114A في ديلاوير، متى يجوز لمركبة خاضعة لقيد المسار الأيمن أن تستخدم قانونياً مساراً أيسر على SR 1 أو I-495؟","options":["عند تخطي مركبة أخرى وتجاوزها، أو الدخول إلى الطريق أو مغادرته، أو حسبما تقتضي ظروف حركة المرور","فقط بين منتصف الليل و6:00 صباحاً","فقط عندما يكون حد السرعة المعلن 35 mph أو أقل","أبداً، تحت أي ظرف"],"explanation":"يسمح الباب 21 § 4114A من قانون ديلاوير للمركبة الثقيلة باستخدام مسار أيسر للتجاوز، أو الدخول إلى الطريق/مغادرته، أو في حالات الطوارئ، أو العوائق، أو ظروف حركة المرور، أو للامتثال لقانون آخر. المصدر: 21 Del. C. § 4114A."},"77":{"q":"بموجب قانون ديلاوير، أين يجب أن تُقاد مركبة تتحرك أبطأ من السرعة الطبيعية لحركة المرور، باستثناء عند التجاوز أو الاستعداد للانعطاف يساراً؟","options":["في المسار الأيمن المتاح لحركة المرور، أو على أقرب مسافة ممكنة عملياً من الرصيف أو الحافة اليمنى","في المسار الأوسط لأي طريق متعدد المسارات","في أي مسار به أقل عدد من المركبات","في المسار الأيسر، مع ترك المسار الأيمن مفتوحاً لحركة المرور المندمجة"],"explanation":"يتطلب الباب 21 § 4114 من قانون ديلاوير من المركبة التي تسير أبطأ من حركة المرور الطبيعية أن تلتزم بالمسار الأيمن أو على أقرب مسافة ممكنة عملياً من الرصيف/الحافة اليمنى، باستثناء عند التخطي أو الاستعداد للانعطاف يساراً. المصدر: 21 Del. C. § 4114."},"78":{"q":"بموجب دليل CDL في ديلاوير، تؤدي مخالفة معبر سكة الحديد المستوي مع الطريق أثناء تشغيل مركبة تجارية (CMV) إلى عدم أهلية CDL لمدة لا تقل عن كم لمخالفة أولى؟","options":["60 days","30 days","120 days","1 year"],"explanation":"ينص دليل CDL في ديلاوير (القسم 1.3.5) على أن مخالفة معبر سكة الحديد المستوي مع الطريق تُسقِط أهلية CDL لمدة لا تقل عن 60 days (الأولى)، و120 days (الثانية خلال 3 سنوات)، و1 year (الثالثة خلال 3 سنوات). المصدر: Delaware CDL Manual, Sec. 1.3.5."},"79":{"q":"أي جهة في ديلاوير تصدر رخص القيادة التجارية (CDLs)؟","options":["قسم المركبات الآلية في ديلاوير (DMV)، وهو جزء من DelDOT","مكتب الناقلات التجارية بشرطة ولاية ديلاوير","المكتب الميداني للإدارة الفيدرالية لسلامة الناقلات بالمحركات (FMCSA)","مكتب وزير خارجية ولاية ديلاوير"],"explanation":"في ديلاوير، تُصدر رخص CDL من قبل قسم المركبات الآلية في ديلاوير (DMV)، الذي يعمل تحت وزارة النقل في ديلاوير. تضع FMCSA المعايير الفيدرالية لكنها لا تصدر الرخصة. المصدر: صفحات CDL لدى Delaware DMV؛ الباب 21، الفصل 26 (قانون رخصة القيادة التجارية الموحد)."},"80":{"q":"كيف تُدار اختبارات المعرفة (التحريرية) لرخصة CDL في ديلاوير؟","options":["بالحضور المباشر دون موعد في أي منشأة من منشآت DMV، دون الحاجة إلى موعد","بموعد مسبق فقط في المقر الرئيسي في Dover","عبر الإنترنت من المنزل مع مراقب عن بُعد","فقط في مركز اختبار واحد معتمد تابع لطرف ثالث"],"explanation":"تذكر Delaware DMV أن جميع اختبارات المعرفة لرخصة CDL تتم بالحضور المباشر فقط ويمكن إكمالها في أي منشأة من منشآت القسم (DMV). يسري شرط الموعد على اختبار المهارات، وليس على اختبار المعرفة. المصدر: صفحة CDL لدى Delaware DMV."},"81":{"q":"كم من الوقت يجب الاحتفاظ برخصة المتعلم التجارية (CLP) في ديلاوير قبل أن يتمكن حاملها من أداء اختبار مهارات CDL؟","options":["ما لا يقل عن 14 days بعد الإصدار الأولي","ما لا يقل عن 30 days بعد الإصدار الأولي","ما لا يقل عن 10 days بعد الإصدار الأولي","ما لا يقل عن 7 days بعد الإصدار الأولي"],"explanation":"لا يكون حامل CLP مؤهلاً لأداء اختبار CDL لفحص ما قبل الرحلة، أو التحكم الأساسي، أو مهارات الطريق حتى يتم الاحتفاظ بالرخصة لمدة لا تقل عن 14 days بعد الإصدار الأولي. هذه هي فترة الاحتفاظ الفيدرالية البالغة 14 days التي اعتمدتها ديلاوير. المصدر: صفحة CDL لدى Delaware DMV؛ 49 CFR 383.25 كما اعتُمد بموجب الباب 21 الفصل 26."},"82":{"q":"كم تبلغ مدة صلاحية رخصة المتعلم التجارية (CLP) في ديلاوير؟","options":["سنة واحدة (1)، ويجوز تجديدها مرة واحدة خلال تلك المدة","180 days، دون السماح بالتجديد","سنتان (2)، قابلة للتجديد سنوياً","ستة (6) أشهر، قابلة للتجديد مرتين"],"explanation":"تكون رخصة CLP في ديلاوير صالحة لمدة سنة واحدة (1) ولا يجوز إصدارها أو تمديدها لمدة تتجاوز سنة واحدة؛ ويجوز تجديدها مرة واحدة خلال تلك المدة. المصدر: صفحة CDL لدى Delaware DMV؛ الباب 21 § 2608."},"83":{"q":"ينقسم اختبار مهارات CDL في ديلاوير إلى أي ثلاثة أجزاء؟","options":["فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية، والقيادة على الطريق","الاختبار التحريري، وفحص النظر، واختبار الطريق","التوصيل، والكبح، والرجوع للخلف فقط","التدريب النظري، والقيادة الفعلية، والاختبار التحريري النهائي"],"explanation":"يتكون اختبار مهارات CDL من ثلاثة أجزاء: اختبار فحص المركبة قبل الرحلة، واختبار مهارات التحكم الأساسية، واختبار القيادة على الطريق. حدّثت ديلاوير هذه البروتوكولات اعتباراً من 26 فبراير 2025. المصدر: صفحة CDL لدى Delaware DMV؛ 49 CFR 383.113."},"84":{"q":"ما الذي يجب على السائق المبتدئ إكماله قبل أداء اختبار مهارات CDL في ديلاوير للحصول على اعتماد الفئة A، أو الفئة B، أو الركاب (P)، أو الحافلة المدرسية (S)؟","options":["تدريب السائق المبتدئ المطلوب فيدرالياً (ELDT) من مزوّد مسجّل","تدرّب لمدة 30 days مُسجَّل لدى DMV","دورة قيادة دفاعية معتمدة من شرطة ولاية ديلاوير","فقط اختبار المعرفة العامة التحريري"],"explanation":"اعتباراً من 7 فبراير 2022، لا يجوز لأي مشغّل مبتدئ أداء اختبار مهارات CDL للفئة A، أو الفئة B، أو اعتماد P، أو اعتماد S ما لم يكن قد أكمل التدريب النظري والقيادة الفعلية الإلزامي (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب لدى FMCSA. المصدر: صفحة ELDT لدى Delaware DMV؛ 49 CFR Part 380."},"85":{"q":"ما فئات التصديق الذاتي الأربع التي يجوز لحامل CDL/CLP في ديلاوير أن يُقرّ بها؟","options":["بين الولايات غير مستثنى، بين الولايات مستثنى، داخل الولاية غير مستثنى، داخل الولاية مستثنى","الفئة A، والفئة B، والفئة C، والفئة D","المواد الخطرة، والركاب، والصهاريج، والمزدوجة/الثلاثية","للأجرة، وخاص، ومستثنى، وحكومي"],"explanation":"يجب على كل حامل CDL/CLP في ديلاوير أن يُصدّق ذاتياً ضمن واحدة من أربع فئات: بين الولايات غير مستثنى، أو بين الولايات مستثنى، أو داخل الولاية غير مستثنى، أو داخل الولاية مستثنى. المصدر: دليل فئات إقرار التصديق الذاتي لدى Delaware DMV؛ 49 CFR 383.71."},"86":{"q":"أي فئة من فئات التصديق الذاتي تتطلب من السائق تقديم شهادة فاحص طبي ساري المفعول تابعة لـ DOT والاحتفاظ بها في ملفه لدى Delaware DMV؟","options":["بين الولايات غير مستثنى","بين الولايات مستثنى","داخل الولاية مستثنى","لا تحتاج أي فئة إلى تقديمها"],"explanation":"يجب على السائق الذي يُصدّق ذاتياً على أنه بين الولايات غير مستثنى أن يقدّم نسخة من شهادة الفاحص الطبي الفيدرالية ويحتفظ بها لدى Delaware DMV. الفئات المستثناة غير مطالبة بتقديم شهادة طبية فيدرالية. المصدر: دليل فئات التصديق الذاتي لدى Delaware DMV؛ 49 CFR 383.71."},"87":{"q":"من أين يجب أن يحصل مقدّم طلب CDL في ديلاوير على الفحص البدني التابع لـ DOT الذي يدعم شهادة الفاحص الطبي؟","options":["من فاحص طبي مدرج في السجل الوطني لـ FMCSA للفاحصين الطبيين المعتمدين","من أي طبيب مرخّص أو مقوّم عظام من اختيار السائق","من عيادة معتمدة من شرطة ولاية ديلاوير فقط","من الطاقم الطبي الداخلي لدى DMV"],"explanation":"يجب أن تأتي الشهادة الطبية من فاحص طبي مدرج في السجل الوطني لـ FMCSA للفاحصين الطبيين المعتمدين. اعتمدت ديلاوير هذا الشرط الفيدرالي لجميع حاملي CDL/CLP. المصدر: صفحة التصديق الطبي لدى Delaware DMV؛ 49 CFR 390.103 / السجل الوطني."},"88":{"q":"وفق أي جدول زمني تنتهي صلاحية رخصة CDL في ديلاوير وتصبح قابلة للتجديد؟","options":["في الذكرى السنوية الثامنة لتاريخ ميلاد حاملها التالي للإصدار (كل 8 سنوات)","كل 4 سنوات في تاريخ الإصدار","كل 5 سنوات في تاريخ الإصدار","كل سنتين لتتوافق مع الفحص البدني لـ DOT"],"explanation":"تنتهي صلاحية رخصة CDL في ديلاوير وتكون قابلة للتجديد في تاريخ الذكرى السنوية الثامنة لميلاد مقدّم الطلب التالي للإصدار، مما يمنح مدة فعلية تصل إلى ثماني سنوات. المصدر: الباب 21 § 2611(f)؛ Delaware DMV."},"89":{"q":"ما أبكر موعد يجوز فيه تجديد رخصة CDL في ديلاوير قبل انتهاء صلاحيتها؟","options":["في غضون 30 days قبل تاريخ انتهاء الصلاحية","في غضون 90 days قبل تاريخ انتهاء الصلاحية","في غضون 6 أشهر قبل تاريخ انتهاء الصلاحية","في غضون سنة واحدة قبل تاريخ انتهاء الصلاحية"],"explanation":"تسمح ديلاوير بتجديد رخصة CDL فقط في غضون 30 days قبل تاريخ انتهاء صلاحيتها. المصدر: صفحة CDL لدى Delaware DMV."},"90":{"q":"ما الحد الأدنى للسن للحصول على رخصة CDL في ديلاوير للقيادة داخل الولاية (داخل ديلاوير) فقط؟","options":["18 عاماً","16 عاماً","21 عاماً","19 عاماً"],"explanation":"يجب أن يكون عمر الشخص 18 عاماً على الأقل لحمل رخصة CDL في ديلاوير للتشغيل داخل الولاية. المصدر: Delaware DMV؛ الباب 21 الفصل 26."},"91":{"q":"ما الحد الأدنى للسن لقيادة مركبة تجارية في التجارة بين الولايات، أو نقل المواد الخطرة، أو نقل الركاب بموجب رخصة CDL في ديلاوير؟","options":["21 عاماً","18 عاماً","19 عاماً","23 عاماً"],"explanation":"يجب أن يكون عمر السائق 21 عاماً على الأقل للتشغيل في التجارة بين الولايات، أو نقل المواد الخطرة التي تتطلب لافتات، أو نقل الركاب. المصدر: Delaware DMV؛ 49 CFR 383."},"92":{"q":"ما المستندات التي يجب على مقدّم الطلب في ديلاوير إبرازها عند الوصول لاختبار مهارات CDL (اختبار الطريق)؟","options":["رخصة متعلم سارية، ورخصة سارية للسائق المرافق الذي يبلغ 21 عاماً فأكثر، وتسجيل مركبة ساري، وتأمين ساري","فقط رخصة متعلم سارية وبطاقة الضمان الاجتماعي","فقط جواز سفر وإيصال رسوم الاختبار","شهادة ميلاد وفاتورتي مرافق"],"explanation":"لاختبار الطريق يجب على مقدّم الطلب إبراز رخصة متعلم سارية، ورخصة القيادة السارية للسائق المرافق (21 عاماً فأكثر)، وبطاقة تسجيل مركبة سارية، وبطاقة تأمين سارية. المصدر: صفحة CDL لدى Delaware DMV."},"93":{"q":"ما الدرجة المطلوبة للنجاح في اختبار المعرفة العامة التحريري لرخصة CDL في ديلاوير؟","options":["80% صحيحة (40 من 50 سؤالاً)","70% صحيحة (35 من 50 سؤالاً)","90% صحيحة (45 من 50 سؤالاً)","100% صحيحة (جميع الأسئلة الـ 50)"],"explanation":"يحتوي اختبار المعرفة العامة لرخصة CDL في ديلاوير على 50 سؤالاً ويتطلب درجة 80% (40 من 50) أو أفضل للنجاح. المصدر: Delaware DMV / نظام اختبار CDL المستند إلى AAMVA المستخدم في ديلاوير."},"94":{"q":"أي مستند هو المرجع الأساسي للدراسة الذاتية الذي توفّره ديلاوير للتحضير لاختباري المعرفة والمهارات لرخصة CDL؟","options":["دليل CDL في ديلاوير (دليل رخصة القيادة التجارية) الصادر عن DMV","قانون ديلاوير، الباب 21 الطبعة المشروحة","دليل FMCSA الجيبي لإحصاءات الشاحنات والحافلات الكبيرة","الكتاب المدرسي لتعليم القيادة في الولاية"],"explanation":"تنشر DMV في ديلاوير دليل CDL في ديلاوير (المستند إلى نموذج AAMVA)، الذي ينبغي على مقدّمي الطلبات الحصول عليه ودراسته قبل الاختبار. المصدر: Delaware CDL Manual."},"95":{"q":"كيف يُجدوَل الجزء على الطريق من اختبار مهارات CDL في ديلاوير، وكيف يُدعَم جزء ما قبل الرحلة؟","options":["يكون اختبار المهارات بموعد مسبق، وتوفّر DMV قائمة تدقيق لفحص ما قبل الرحلة كمساعدة لمقدّمي الطلبات","جميع أجزاء المهارات الثلاثة بالحضور المباشر، ولا تُوفَّر أي قائمة تدقيق","اختبار الطريق عبر الإنترنت؛ ويُعفى فحص ما قبل الرحلة لخريجي ELDT","تتم الجدولة فقط من خلال صاحب عمل مقدّم الطلب"],"explanation":"تكون اختبارات مهارات CDL في ديلاوير بموعد مسبق فقط، ويوفّر البرنامج المحدّث لمقدّمي الطلبات قائمة تدقيق لاختبار فحص المركبة قبل الرحلة كمساعدة للدراسة. المصدر: صفحة CDL لدى Delaware DMV (اختبار المهارات المحدّث، اعتباراً من 26 فبراير 2025)."},"96":{"q":"ماذا يحدث عموماً لرخصة CDL في ديلاوير إذا فشل حاملها الذي صدّق ذاتياً على أنه بين الولايات غير مستثنى في الاحتفاظ بشهادة فاحص طبي سارية في ملفه لدى DMV؟","options":["يُخفَّض امتياز القيادة التجارية (CDL) بحيث لا يعود بإمكان الشخص تشغيل المركبات التجارية","تُلغى رخصة CDL نهائياً ولا يمكن إعادتها","لا شيء، لأن الشهادة الطبية مجرد سجل لدى صاحب العمل","تتحول الرخصة تلقائياً إلى رخصة CDL مستثناة بين الولايات"],"explanation":"إذا ترك سائق مطلوب منه ذلك (غير مستثنى) الشهادة الطبية تنتهي أو فشل في تقديمها، يجب على الولاية تخفيض رخصة CDL، مع إزالة امتيازات القيادة التجارية حتى تتوفر شهادة سارية في الملف. المصدر: الأسئلة الشائعة حول التصديق الذاتي لدى Delaware DMV؛ 49 CFR 383.73."},"97":{"q":"بالنسبة للسائق في ديلاوير المصنّف بين الولايات غير مستثنى، ما مدى حداثة الفحص البدني التابع لـ DOT الذي يدعم الشهادة الطبية بوجه عام؟","options":["مؤرّخ خلال الـ 24 months السابقة (بحد أقصى تصديق لمدة سنتين)","مؤرّخ خلال الـ 6 أشهر السابقة","مؤرّخ خلال الـ 12 month السابقة فقط","مؤرّخ خلال الـ 5 سنوات السابقة"],"explanation":"يجب أن يستوفي الفحص البدني التابع لـ DOT المتطلبات 49 CFR 391.41-391.49 ويجوز أن يصدّق على السائق لمدة تصل إلى 24 months (يمكن للفاحص الطبي التصديق لمدة أقصر لبعض الحالات). تتطلب ديلاوير هذا المعيار الفيدرالي. المصدر: صفحة التصديق الطبي لدى Delaware DMV؛ 49 CFR 391.43."}}};
